-- Online Web Presence (High-Impact) - Assess (variant 1)
UPDATE product_content SET
  description = 'Get a clear picture of where your website is losing visitors, missing conversions, and underperforming on search, then walk away with a prioritised action list your marketing and IT teams can execute.',
  positioning = 'Evidence-led audit of your web estate: gaps scored, priorities set, roadmap ready.',
  hero_summary = 'Get a clear picture of where your website is losing visitors, missing conversions, and underperforming on search, then walk away with a prioritised action list your marketing and IT teams can execute.',
  overview_paragraphs = '["The Online Web Presence Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment gives you evidence-led priorities your leadership team can act on.","See how online web presence performs today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews how your web presence supports discovery, engagement, and conversion across priority customer journeys.","You receive practical findings and a prioritised roadmap your teams can use for design, investment, and delivery decisions."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment with no obligation to proceed","Covers performance, SEO, accessibility, and conversion in one engagement","Stakeholder-ready findings delivered within the week"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations run web estates with inconsistent journeys, weak conversion paths, and no clear view of AI readiness. This assessment gives you evidence-led priorities your leadership team can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented journeys","description":"Customers hit dead ends between discovery, content, and conversion."},{"title":"Weak conversion signals","description":"Teams optimise pages without shared metrics or testable hypotheses."},{"title":"No AI readiness view","description":"Personalisation and assistant use cases are discussed without a practical baseline."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Journey-led priorities","description":"You know which paths to fix first across content, UX, and conversion."},{"title":"Clear improvement backlog","description":"Gaps are ranked for design, investment, and delivery decisions."},{"title":"Leadership-ready roadmap","description":"Recommendations are structured for governance review and next-stage funding."}]}}'::jsonb,
  faq_intro = 'Common questions about the Online Web Presence assessment.'
WHERE variant_id = 1;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'Web estate audit report', 'Page-level findings covering performance, accessibility, SEO, and conversion barriers, with each issue rated by severity and effort to fix.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'SEO gap analysis', 'Keyword coverage, crawlability issues, and content gaps mapped against organic visibility targets.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'Competitor benchmark', 'Side-by-side comparison of your top three competitors on journey quality, content depth, and search presence.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (1, 'Prioritised action roadmap', 'Sequenced recommendations with effort scores, expected business impact, and suggested owners so your team can begin immediately.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'What access do you need to run the audit?', 'Read-only access to Google Analytics or equivalent, Google Search Console, and your CMS is ideal. The DigitalQatalyst team agrees the exact access list during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'Do you audit every page on our site?', 'We crawl the full site but focus detailed analysis on the highest-traffic and highest-value pages. Scope is confirmed with your team at the start.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'Will we get specific fixes or just a list of issues?', 'Both. Each finding comes with a recommended fix, effort estimate, and expected impact so your teams have actionable instructions, not just a list of problems.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (1, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm scope, access requirements, and stakeholders before the engagement begins.', 3);

-- Online Web Presence (High-Impact) - Design (variant 2)
UPDATE product_content SET
  description = 'Transform your web presence goals into a complete, build-ready blueprint: user journeys mapped, information architecture defined, and technical specifications your development team can code against.',
  positioning = 'From brief to blueprint: user-centred web design with every decision documented for build.',
  hero_summary = 'Transform your web presence goals into a complete, build-ready blueprint: user journeys mapped, information architecture defined, and technical specifications your development team can code against.',
  overview_paragraphs = '["The Online Web Presence Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns web goals into user-centred designs and build-ready specifications.","Turn online web presence goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate online web presence requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["User research-validated designs, not assumption-led templates","Build-ready specifications that reduce development rework","Stakeholder sign-off checkpoint built into the engagement"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations plan web changes without aligned journeys, experience standards, or specifications implementation teams can build against. This design engagement turns web goals into user-centred designs and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined journey direction","description":"Priority web journeys are unclear, making it hard to align teams and stakeholders."},{"title":"Inconsistent experience standards","description":"Brand, UX, and technical patterns are applied unevenly across pages and flows."},{"title":"Build ambiguity","description":"Delivery teams lack the specifications needed to implement with confidence."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"User-centred web designs","description":"Experiences are designed around real user needs with clear journey definitions."},{"title":"Brand-aligned patterns","description":"Visual systems and interaction standards reflect your brand with consistency."},{"title":"Implementation-ready specs","description":"Build teams receive clear specifications that reduce rework and accelerate delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Web Presence Design service.'
WHERE variant_id = 2;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'User journey maps', 'Documented journeys for each visitor type, showing entry points, decision moments, and the actions needed to reach conversion.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'Information architecture and navigation design', 'Site structure, menu hierarchy, and content taxonomy validated against user expectations and business goals.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'Wireframe library', 'Annotated wireframes for every key template and interaction, with component-level specifications your developers can implement directly.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (2, 'Technical and integration specification', 'CMS requirements, third-party integration points, and API contracts documented to eliminate ambiguity during build.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'Do we need to have completed an assessment first?', 'Not mandatory, but recommended. The DigitalQatalyst team can work from your existing analytics and research if an assessment has not been done.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'Will the designs be handed off to our internal developers or to your team?', 'Either. The specification pack is tool-agnostic and includes everything an internal team or an external agency needs to build accurately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'How much user research is included?', 'The engagement includes synthesis of existing data and targeted interviews or usability sessions. Larger primary research programmes can be scoped separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (2, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your existing assets, agree the design scope, and confirm the research approach before work begins.', 3);

-- Online Web Presence (High-Impact) - AI Design (variant 3)
UPDATE product_content SET
  description = 'Identify which AI capabilities will genuinely improve your website''s visitor experience, validate the use cases with real data, and receive deployment-ready specifications before a single line of build code is written.',
  positioning = 'AI use cases for your web presence validated before build investment, with guardrails built in.',
  hero_summary = 'Identify which AI capabilities will genuinely improve your website''s visitor experience, validate the use cases with real data, and receive deployment-ready specifications before a single line of build code is written.',
  overview_paragraphs = '["The Online Web Presence AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for online web presence, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for online web presence.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation before any build commitment","Responsible AI guardrails designed in from the start","Specification pack handed to your build team or the DigitalQatalyst team"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations apply AI to your web presence without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for online web presence lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for online web presence are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Web Presence AI Design service.'
WHERE variant_id = 3;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'AI opportunity register', 'Ranked list of AI use cases for your web presence, each scored on visitor impact, data readiness, and build complexity.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'Responsible AI workflow designs', 'Process flows for each prioritised use case, including human-in-the-loop checkpoints, bias mitigation, and fallback logic.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'Data and model specification', 'Training data requirements, model selection criteria, and pipeline architecture for each approved use case.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (3, 'Deployment-ready build specification', 'Integration contracts, API requirements, and acceptance criteria your engineering team can build and test against.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'Which AI use cases are most common for web presence?', 'Personalised content recommendations, AI-powered site search, conversational chat assistants, and automated content tagging are the most frequently prioritised. The DigitalQatalyst team will validate which of these fits your data and visitor profile.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'What data do we need to have in place?', 'We assess your current data landscape as part of the engagement and identify gaps. You do not need a complete data platform before starting.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'How do you handle AI risks like hallucination or bias?', 'Every workflow design includes a responsible AI review covering bias testing, output validation, fallback logic, and human escalation paths.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (3, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm your AI readiness level and agree the discovery scope before work begins.', 3);

-- Online Web Presence (High-Impact) - Deploy (variant 4)
UPDATE product_content SET
  description = 'Bring your website designs to life with a phased build, integration, and launch programme that keeps quality and go-live dates on track, and hands over a fully documented site to your operations team.',
  positioning = 'Managed web delivery: configured, tested, and launched with a documented handover to your team.',
  hero_summary = 'Bring your website designs to life with a phased build, integration, and launch programme that keeps quality and go-live dates on track, and hands over a fully documented site to your operations team.',
  overview_paragraphs = '["The Online Web Presence Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed online web presence changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated online web presence assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Build managed against a fixed specification to contain scope creep","QA, accessibility, and performance testing included before go-live","Documented handover so your team can manage the site independently"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations stall between approved designs and production for your web presence, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for online web presence sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Web Presence Deploy service.'
WHERE variant_id = 4;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'Configured and tested website', 'Fully built site meeting the design specification, with all integrations live and accessibility checks passed.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'QA test report', 'Documented test results covering cross-browser compatibility, performance benchmarks, accessibility compliance, and resolved defects.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'Launch runbook', 'Step-by-step go-live procedure including DNS changes, cache warm-up, monitoring checks, and rollback instructions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (4, 'Operations handover pack', 'CMS user guides, integration documentation, and maintenance procedures your internal team needs to manage the site post-launch.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'Does the Deploy service include content creation?', 'Content migration is included. Content creation and copywriting are separate and can be quoted alongside this service.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'Which CMS platforms do you build on?', 'The DigitalQatalyst team works across the major platforms including WordPress, Contentful, Sanity, and custom headless stacks. The target platform is confirmed during design.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'How is change managed during the build?', 'Scope changes go through a formal change request process to protect the timeline and budget. Minor clarifications are absorbed; additions are quoted separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'What happens if a critical issue is found after launch?', 'The launch runbook includes a rollback procedure. The DigitalQatalyst team provides a defined hypercare window post-go-live to resolve priority defects.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (4, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the design specification, confirm the technical environment, and agree a delivery schedule.', 4);

-- Online Web Presence (High-Impact) - AI Deploy (variant 5)
UPDATE product_content SET
  description = 'Put your validated AI web features into production with monitoring, safety controls, and a clear operational handover, so personalisation and automation deliver measurable results from launch day.',
  positioning = 'Governed AI for your website: in production, monitored, and handed over with safety controls intact.',
  hero_summary = 'Put your validated AI web features into production with monitoring, safety controls, and a clear operational handover, so personalisation and automation deliver measurable results from launch day.',
  overview_paragraphs = '["The Online Web Presence AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled online web presence workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for online web presence with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["AI safety controls and monitoring configured before public launch","A/B testing framework included to prove ROI from day one","Full operational runbook and team training at handover"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many AI initiatives for your web presence fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for online web presence fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Web Presence AI Deploy service.'
WHERE variant_id = 5;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'Deployed AI features', 'AI capabilities live on your website, integrated with your CMS and analytics stack, and confirmed against the agreed acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'Monitoring and alerting dashboard', 'Real-time view of model accuracy, response latency, and safety flags with configured alerts for your operations team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'Safety and moderation controls', 'Output filters, fallback logic, and escalation paths configured and tested to protect visitors and your brand.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (5, 'AI operations runbook', 'Step-by-step procedures for monitoring, retraining triggers, incident response, and routine maintenance of each deployed AI feature.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'Do we need in-house ML engineers to manage the AI features after launch?', 'Not necessarily. The DigitalQatalyst team designs the operational model around your team''s capability and can include an ongoing managed tier if needed.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'How do you handle model drift over time?', 'Monitoring dashboards flag accuracy degradation. The runbook includes retraining triggers and a process for re-deploying updated models without site downtime.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'What if an AI feature produces harmful or incorrect outputs?', 'Safety controls and fallback logic are configured and tested before launch. The moderation layer catches out-of-policy outputs before they reach visitors.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (5, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI Design specification and confirm the deployment environment before work begins.', 3);

-- Online Web Presence (High-Impact) - Managed (variant 6)
UPDATE product_content SET
  description = 'Keep your website performing at its best with ongoing monitoring, optimisation, and content governance managed by the DigitalQatalyst team under a clear SLA, so your team stays focused on business priorities.',
  positioning = 'Your website, running and improving every month: SLA-backed operations with no surprises.',
  hero_summary = 'Keep your website performing at its best with ongoing monitoring, optimisation, and content governance managed by the DigitalQatalyst team under a clear SLA, so your team stays focused on business priorities.',
  overview_paragraphs = '["The Online Web Presence Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve online web presence with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cx, digital, marketing & it leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for online web presence - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed response times with monthly performance accountability","Proactive monitoring, not reactive ticket management","Quarterly improvement sprints included in the managed plan"]'::jsonb,
  why_it_matters = '{"hook":"Your website is often the first place customers judge whether to trust, engage, or leave.","problemParagraph":"Many organisations struggle to sustain performance across your web presence after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"online web presence issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Web Presence Managed service.'
WHERE variant_id = 6;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Monthly performance report', 'Traffic, SEO, speed, and conversion data with month-on-month trends and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Issue log and resolution record', 'Tracked log of every detected issue, time to resolution, and root cause, demonstrating SLA compliance.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Quarterly optimisation plan', 'Prioritised improvements for the next quarter, each with expected impact and effort, agreed with your team in advance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (6, 'Annual web health review', 'Full assessment of your web estate''s performance against goals, with strategic recommendations for the year ahead.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'What is included in the SLA?', 'Response and resolution times for critical, high, and standard issues, plus monthly reporting delivery dates. Exact SLA terms are agreed during onboarding.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'Can we make content updates ourselves or does everything go through your team?', 'You retain full CMS access. The DigitalQatalyst team handles governance, quality checks, and complex updates while your team handles day-to-day content.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'How are quarterly optimisation priorities set?', 'The DigitalQatalyst team analyses performance data and presents a prioritised list at the start of each quarter. You approve the plan before work begins.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'What happens if performance drops after go-live?', 'The DigitalQatalyst team monitors your website continuously and responds to critical performance incidents within four business hours. Non-critical issues are triaged and resolved in line with the SLA response targets agreed during onboarding.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'What happens if our website needs a major redesign during the managed contract?', 'Major redesigns are scoped as separate Design or Deploy engagements. The managed service continues uninterrupted during the project.', 4);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (6, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current web setup, agree the SLA terms, and confirm the onboarding timeline.', 5);

-- Online Social Presence (High-Impact) - Assess (variant 7)
UPDATE product_content SET
  description = 'Assess the health of your social media presence across every active channel, identify where engagement is low or brand consistency is missing, and receive a prioritised plan your marketing team can act on immediately.',
  positioning = 'A clear audit of your social channels: where audience engagement is lost and how to win it back.',
  hero_summary = 'Assess the health of your social media presence across every active channel, identify where engagement is low or brand consistency is missing, and receive a prioritised plan your marketing team can act on immediately.',
  overview_paragraphs = '["The Online Social Presence Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment gives you evidence-led priorities for social strategy and investment.","See how social presence and audience engagement perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for marketing, communications & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews online social presence across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope audit covering all active social channels","Competitor benchmarking included at no extra cost","Stakeholder-ready findings delivered within the week"]'::jsonb,
  why_it_matters = '{"hook":"Your social channels are where audiences form first impressions and build ongoing relationships.","problemParagraph":"Many organisations run social programmes with inconsistent publishing, weak audience insight, and no clear view of AI-enabled engagement. This assessment gives you evidence-led priorities for social strategy and investment.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented publishing","description":"Content and campaigns run across channels without a coordinated audience model."},{"title":"Limited audience insight","description":"Teams post without shared metrics on reach, engagement, or conversion impact."},{"title":"Unclear AI opportunities","description":"Automation and content intelligence are discussed without a practical readiness baseline."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Channel-led priorities","description":"You know which audiences, formats, and journeys to improve first."},{"title":"Ranked improvement plan","description":"Gaps are ordered for design, tooling, and campaign investment."},{"title":"Leadership-ready roadmap","description":"Recommendations are structured for governance review and next-stage funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Social Presence assessment.'
WHERE variant_id = 7;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Social channel audit report', 'Platform-by-platform findings on content quality, posting frequency, engagement rates, and follower demographics.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Brand consistency assessment', 'Review of voice, visual identity, and messaging coherence across your active social accounts.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Competitor social benchmark', 'Comparison of your top three competitors on content strategy, audience growth rate, and engagement quality.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (7, 'Prioritised social action plan', 'Ranked recommendations with expected engagement impact and implementation effort for your marketing team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'Which social platforms do you cover in the audit?', 'All platforms where your organisation has an active presence. The DigitalQatalyst team confirms the channel list during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'Do you need admin access to our social accounts?', 'Read-only analytics access is sufficient. The DigitalQatalyst team agrees the exact access requirements before the engagement starts.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'Will you assess our paid social campaigns as well as organic content?', 'The standard assessment focuses on organic presence. Paid social campaign analysis can be added to scope during the initial consultation.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (7, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the channel scope and access requirements before work begins.', 3);

-- Online Social Presence (High-Impact) - Design (variant 8)
UPDATE product_content SET
  description = 'Build a social media presence your audience will actually engage with: content frameworks designed for each platform, channel-specific workflows, and a publication system your team can run without agency dependency.',
  positioning = 'A social strategy designed for your audience, your channels, and your team''s capacity.',
  hero_summary = 'Build a social media presence your audience will actually engage with: content frameworks designed for each platform, channel-specific workflows, and a publication system your team can run without agency dependency.',
  overview_paragraphs = '["The Online Social Presence Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns social goals into actionable strategies and build-ready specifications.","Turn social presence and audience engagement goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for marketing, communications & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate online social presence requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Audience research built into the design, not assumed","Team-operable workflows that reduce dependency on external agencies","90-day content calendar template included at handover"]'::jsonb,
  why_it_matters = '{"hook":"Your social channels are where audiences form first impressions and build ongoing relationships.","problemParagraph":"Many organisations launch social initiatives without defined audience journeys, campaign structures, or specifications teams can operationalise. This design engagement turns social goals into actionable strategies and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined audience journeys","description":"Engagement paths from awareness to action are unclear across channels."},{"title":"Inconsistent campaign design","description":"Publishing workflows and governance vary by team and platform."},{"title":"Operational ambiguity","description":"Teams lack playbooks and specs to run programmes at scale."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Audience-centred strategies","description":"Journeys and content models reflect how your audiences actually engage."},{"title":"Aligned campaign structures","description":"Publishing, moderation, and governance requirements are defined upfront."},{"title":"Implementation-ready artefacts","description":"Teams receive specifications and workflows they can execute against."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Social Presence Design service.'
WHERE variant_id = 8;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Platform-specific content strategy', 'Audience-validated content approach for each active social channel, covering formats, tone, themes, and posting cadence.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Content pillar and topic framework', 'Structured content pillars with topic clusters, format guidance, and a 90-day content calendar template.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Editorial and approval workflow', 'End-to-end process for content creation, review, scheduling, and performance tracking, mapped to your team structure.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (8, 'Community management playbook', 'Response frameworks for comments, direct messages, and crisis scenarios, with example copy your team can adapt.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'Does the design include creating actual social content?', 'The engagement produces frameworks, templates, and examples rather than finished posts. Content production can be scoped as a separate service.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'What if our team is small? Will the workflows be too complex to run?', 'Workflow design is matched to your team''s size and capability. The DigitalQatalyst team designs for what your team can realistically sustain.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'Can you design for a new platform we have not used before?', 'Yes. The DigitalQatalyst team can include strategy for platforms you are launching on, with audience research to validate the channel choice.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (8, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current channels and team structure before agreeing the design scope.', 3);

-- Online Social Presence (High-Impact) - AI Design (variant 9)
UPDATE product_content SET
  description = 'Identify which AI tools will make your social content more relevant and your community management more responsive, validate those use cases, and receive specifications ready for your technology team to build.',
  positioning = 'AI for social: content intelligence, scheduling optimisation, and sentiment monitoring designed before build.',
  hero_summary = 'Identify which AI tools will make your social content more relevant and your community management more responsive, validate those use cases, and receive specifications ready for your technology team to build.',
  overview_paragraphs = '["The Online Social Presence AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for social presence and audience engagement, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for marketing, communications & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for online social presence.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["AI use cases validated for your platforms and audience before any build","Responsible moderation design included from the start","Vendor-neutral specification compatible with your existing stack"]'::jsonb,
  why_it_matters = '{"hook":"Your social channels are where audiences form first impressions and build ongoing relationships.","problemParagraph":"Many organisations apply AI to your social channels without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for online social presence lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for online social presence are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Social Presence AI Design service.'
WHERE variant_id = 9;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'AI opportunity assessment', 'Ranked list of AI use cases for social presence, each scored on audience impact, platform feasibility, and implementation effort.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'Social listening and sentiment workflow', 'Designed workflow for AI-powered monitoring, alerting, and escalation, including response thresholds for your community team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'Content AI specification', 'Requirements for caption assistance, hashtag optimisation, and scheduling tools, with vendor shortlist and integration contracts.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (9, 'Responsible moderation design', 'AI moderation rules, escalation paths, and human-review criteria that protect your brand without silencing legitimate audience voices.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'Can AI really help with social content creation without sounding robotic?', 'Yes, when implemented with your brand voice guidelines and human editorial review. The design includes tone guardrails and a human-approval step for all published content.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'Which social platforms support AI integrations?', 'Most major platforms expose APIs for scheduling, analytics, and moderation. The DigitalQatalyst team validates feasibility per platform during the design engagement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'How do you handle AI-generated content and transparency obligations?', 'The workflow design includes disclosure guidance aligned with current platform policies and relevant regulatory guidance in your region.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (9, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current social stack and agree the AI design scope.', 3);

-- Online Social Presence (High-Impact) - Deploy (variant 10)
UPDATE product_content SET
  description = 'Activate your social media strategy with a fully configured technology stack, content workflows, and community management tools deployed and tested so your team can publish and engage from day one.',
  positioning = 'Social channels live: tools configured, workflows active, and your team ready to publish.',
  hero_summary = 'Activate your social media strategy with a fully configured technology stack, content workflows, and community management tools deployed and tested so your team can publish and engage from day one.',
  overview_paragraphs = '["The Online Social Presence Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed social presence and audience engagement changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for marketing, communications & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated online social presence assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Full technology stack configured and tested before handover","Team training included so your people can operate independently","First publication cycle supported by the DigitalQatalyst team"]'::jsonb,
  why_it_matters = '{"hook":"Your social channels are where audiences form first impressions and build ongoing relationships.","problemParagraph":"Many organisations stall between approved designs and production for your social channels, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for online social presence sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Social Presence Deploy service.'
WHERE variant_id = 10;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Configured social management platform', 'All active channels connected, permission levels set, approval workflows active, and accounts verified across your social management tool.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Analytics and reporting dashboard', 'Live reporting across all channels showing reach, engagement, follower growth, and content performance with automated monthly report templates.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Training materials and guides', 'Role-specific guides for content creators, approvers, and community managers so your team runs every tool without ongoing support.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (10, 'Operations handover pack', 'All platform credentials, workflow documentation, and escalation contacts compiled and handed to your team at close.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'Which social management tools do you deploy?', 'Hootsuite, Sprout Social, Buffer, and similar platforms. If you have an existing tool, the DigitalQatalyst team configures it. If not, a recommendation is made during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'Is content creation included in the deploy?', 'Content deployment tools and workflows are included. Content creation and copywriting are separate and can be scoped alongside this service.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'How long does team training take?', 'Typically two to three sessions across the final weeks of deployment, tailored to each role. Self-service reference guides are provided for ongoing use.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (10, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm your current technology, account access, and deployment timeline.', 3);

-- Online Social Presence (High-Impact) - AI Deploy (variant 11)
