  description = 'Deploy AI-powered social listening, content assistance, and automated moderation into your live channels with safety controls configured and your team trained to manage every feature in production.',
  positioning = 'AI social tools in production: listening live, moderation active, and your team in control.',
  hero_summary = 'Deploy AI-powered social listening, content assistance, and automated moderation into your live channels with safety controls configured and your team trained to manage every feature in production.',
  overview_paragraphs = '["The Online Social Presence AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled social presence and audience engagement workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for marketing, communications & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for online social presence with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["AI features deployed with brand guardrails active before public exposure","Community manager training included for every AI tool","Performance measurement built in to prove ROI from launch"]'::jsonb,
  why_it_matters = '{"hook":"Your social channels are where audiences form first impressions and build ongoing relationships.","problemParagraph":"Many AI initiatives for your social channels fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for online social presence fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Social Presence AI Deploy service.'
WHERE variant_id = 11;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'Deployed AI social tools', 'Listening, content assistance, and moderation AI live across your active channels, integrated with your social management platform.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'Monitoring and alerting configuration', 'Real-time dashboards for brand sentiment, keyword alerts, and moderation activity with configured escalation thresholds.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'Content AI guardrail configuration', 'Brand voice rules, topic restrictions, and human approval workflows configured and tested before any AI content reaches your audience.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (11, 'AI operations guide', 'Procedures for managing alerts, reviewing moderation decisions, updating content AI rules, and handling AI tool incidents.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'Will AI moderation remove comments our community should see?', 'Moderation rules are calibrated to your community standards and reviewed before activation. The system flags for human review rather than automatically deleting borderline content.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'How does the social listening AI handle multiple languages?', 'Multi-language support is configured based on your audience profile. The DigitalQatalyst team confirms language coverage during the deployment setup.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'What happens if an AI tool produces inappropriate content?', 'Editorial approval gates prevent AI-suggested content from publishing without human sign-off. The guardrail configuration is tested before any tool goes live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (11, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the deployment infrastructure.', 3);

-- Online Social Presence (High-Impact) - Managed (variant 12)
UPDATE product_content SET
  description = 'Keep your social channels active, on-brand, and growing with monthly content management, community monitoring, and performance reporting handled by the DigitalQatalyst team under a defined SLA.',
  positioning = 'Social presence managed end-to-end: publishing, monitoring, and reporting every month.',
  hero_summary = 'Keep your social channels active, on-brand, and growing with monthly content management, community monitoring, and performance reporting handled by the DigitalQatalyst team under a defined SLA.',
  overview_paragraphs = '["The Online Social Presence Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve social presence and audience engagement with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for marketing, communications & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for online social presence - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Daily monitoring with SLA-backed response times","Content published monthly within agreed brand guidelines","Quarterly strategy review keeps the approach current with audience data"]'::jsonb,
  why_it_matters = '{"hook":"Your social channels are where audiences form first impressions and build ongoing relationships.","problemParagraph":"Many organisations struggle to sustain performance across your social channels after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"online social presence issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Online Social Presence Managed service.'
WHERE variant_id = 12;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Monthly content publishing report', 'Record of all published content with per-post engagement data, reach, and impressions by channel.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Community management log', 'Tracked log of all monitored interactions, response times against SLA, and escalated items for your team''s attention.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Monthly social performance report', 'Audience growth, engagement rate trends, and content effectiveness scores with recommended adjustments.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (12, 'Quarterly strategy review', 'Assessment of the quarter''s social performance against goals, with a revised content approach and priorities for the next period.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'Does your team create the social content or do we?', 'The DigitalQatalyst team creates and publishes content within agreed brand guidelines. You review and approve the monthly content calendar before publication.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'What response time is guaranteed for community management?', 'Response timeframes are defined in the SLA during onboarding. Typical configurations target four-hour response for standard comments and one-hour for urgent or crisis mentions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'Can we adjust the content direction mid-contract?', 'Yes. The quarterly strategy review is the formal checkpoint, but the DigitalQatalyst team can accommodate urgent messaging changes outside of the review cycle.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'What happens during a social media crisis?', 'A crisis escalation protocol is agreed during onboarding. The DigitalQatalyst team alerts your communications lead immediately and follows the agreed response procedure.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (12, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm channel access, review your brand guidelines, and agree the SLA terms before onboarding begins.', 4);

-- Mobile Apps (High-Impact) - Assess (variant 13)
UPDATE product_content SET
  description = 'Assess the performance, usability, and technical health of your mobile app portfolio, identify the gaps driving low adoption or poor retention, and receive a prioritised improvement roadmap your product and engineering teams can act on.',
  positioning = 'A rigorous mobile app health check: adoption barriers identified, retention risks surfaced, roadmap ready.',
  hero_summary = 'Assess the performance, usability, and technical health of your mobile app portfolio, identify the gaps driving low adoption or poor retention, and receive a prioritised improvement roadmap your product and engineering teams can act on.',
  overview_paragraphs = '["The Mobile Apps & Services Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps maturity and returns prioritised improvements your product and technology leaders can act on.","See how mobile apps and mobile services perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for digital product, cx & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews mobile apps across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Covers UX, technical performance, and app store presence in one audit","Findings prioritised by user impact, not just technical severity","Roadmap your product team can take straight into sprint planning"]'::jsonb,
  why_it_matters = '{"hook":"Your mobile apps are where users engage most deeply, and where experience gaps have the greatest impact.","problemParagraph":"Many organisations operate mobile apps with inconsistent journeys, weak retention signals, and no clear view of AI-enabled features. This assessment maps maturity and returns prioritised improvements your product and technology leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented user journeys","description":"Users encounter friction across onboarding, core tasks, and support paths."},{"title":"Weak performance signals","description":"Teams lack shared metrics on retention, conversion, and accessibility."},{"title":"No AI feature baseline","description":"Assistant and personalisation ideas are discussed without a practical readiness view."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Journey-led priorities","description":"You know which flows to fix first across UX, performance, and engagement."},{"title":"Clear product backlog","description":"Gaps are ranked for design, engineering, and investment decisions."},{"title":"Leadership-ready roadmap","description":"Recommendations are structured for governance review and delivery funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Mobile Apps assessment.'
WHERE variant_id = 13;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Mobile app audit report', 'Findings across UX quality, technical performance, app store ratings, and retention funnel, with each issue rated by severity.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Journey friction analysis', 'Identified drop-off points in your key user journeys with specific causes and recommended fixes.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Technical performance benchmark', 'App load times, crash rates, and API performance compared against category benchmarks for your app store category.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (13, 'Prioritised mobile roadmap', 'Sequenced improvement recommendations with user impact scores, engineering effort estimates, and suggested sprint sequencing.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'Do you audit both iOS and Android versions?', 'Yes. The audit covers both platforms unless the assessment scope is limited to one by mutual agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'What data access do you need?', 'Firebase or equivalent analytics, App Store Connect, and Google Play Console read-only access. The DigitalQatalyst team confirms the exact list during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'Can you assess an app still in development, not yet in production?', 'Yes. The assessment can be run on a staging build. Findings will focus on UX and technical architecture rather than live retention data.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (13, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the platform scope and access requirements before the engagement begins.', 3);

-- Mobile Apps (High-Impact) - Design (variant 14)
UPDATE product_content SET
  description = 'Turn your mobile app strategy into screen-by-screen designs and build-ready specifications that your development team can code against, with user research validating every key interaction before build begins.',
  positioning = 'From product brief to build-ready mobile app specification: user-validated, technically complete.',
  hero_summary = 'Turn your mobile app strategy into screen-by-screen designs and build-ready specifications that your development team can code against, with user research validating every key interaction before build begins.',
  overview_paragraphs = '["The Mobile Apps & Services Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns mobile goals into user-centred designs and build-ready specifications.","Turn mobile apps and mobile services goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for digital product, cx & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate mobile apps requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Usability testing included before specification is finalised","iOS and Android covered in a single design engagement","Accessibility standards built into the design system from day one"]'::jsonb,
  why_it_matters = '{"hook":"Your mobile apps are where users engage most deeply, and where experience gaps have the greatest impact.","problemParagraph":"Many organisations build mobile features without validated journeys, design standards, or specifications engineering teams can implement confidently. This design engagement turns mobile goals into user-centred designs and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined experience direction","description":"Target mobile journeys and interaction patterns are unclear across squads."},{"title":"Design inconsistency","description":"UI patterns, accessibility, and platform standards are applied unevenly."},{"title":"Build ambiguity","description":"Engineering teams lack specs, acceptance criteria, and integration detail."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"User-centred mobile designs","description":"Experiences reflect real user needs with clear flow definitions."},{"title":"Consistent design standards","description":"Patterns and accessibility requirements are defined for iOS, Android, or cross-platform builds."},{"title":"Implementation-ready specs","description":"Engineering receives artefacts that reduce rework and accelerate release cycles."}]}}'::jsonb,
  faq_intro = 'Key questions about the Mobile Apps Design service.'
WHERE variant_id = 14;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Mobile user journey maps', 'Research-validated journeys for each user type across the key app flows, including edge cases and error states.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Interaction design and prototype', 'Screen-by-screen designs with annotated interactions for iOS and Android, tested with real users before specification sign-off.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Mobile design system', 'Component library, colour system, typography, and accessibility guidelines aligned to platform standards.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (14, 'Technical build specification', 'API contracts, data models, push notification flows, and offline behaviour documented for your engineering team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'Do you design for both iOS and Android in the same engagement?', 'Yes. The design system and specification cover both platforms, with platform-specific component guidance where the experiences diverge.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'How many rounds of usability testing are included?', 'One round of moderated usability testing is included. Additional rounds can be added to the scope during the initial consultation.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'Is the prototype interactive?', 'Yes. A clickable prototype is produced for usability testing and stakeholder sign-off. It covers the core journeys rather than every screen.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (14, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your product brief and existing research before agreeing the design scope.', 3);

-- Mobile Apps (High-Impact) - AI Design (variant 15)
UPDATE product_content SET
  description = 'Validate which AI features will genuinely improve your mobile app experience, from in-app personalisation to intelligent search, and produce deployment-ready specifications with responsible AI controls built in.',
  positioning = 'AI for mobile apps: validated use cases, on-device and cloud options assessed, guardrails specified.',
  hero_summary = 'Validate which AI features will genuinely improve your mobile app experience, from in-app personalisation to intelligent search, and produce deployment-ready specifications with responsible AI controls built in.',
  overview_paragraphs = '["The Mobile Apps & Services AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for mobile apps and mobile services, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for digital product, cx & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for mobile apps.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["On-device AI feasibility assessed alongside cloud options","Privacy and consent design included from the start","Build specification matched to iOS and Android platform constraints"]'::jsonb,
  why_it_matters = '{"hook":"Your mobile apps are where users engage most deeply, and where experience gaps have the greatest impact.","problemParagraph":"Many organisations apply AI to your mobile apps without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for mobile apps lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for mobile apps are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the Mobile Apps AI Design service.'
WHERE variant_id = 15;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'Mobile AI opportunity register', 'Ranked AI use cases for your app, each scored on user impact, technical feasibility, and privacy considerations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'On-device versus cloud analysis', 'Documented trade-offs for each use case covering latency, connectivity requirements, battery impact, and data privacy.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'Responsible AI specification', 'Bias testing requirements, consent flow designs, data minimisation rules, and human oversight checkpoints for each approved use case.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (15, 'Mobile AI build specification', 'SDK and API requirements, model delivery approach, and integration contracts your engineering team can build to.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'Can AI features work offline on mobile?', 'On-device AI models can operate without connectivity. The design engagement assesses which features are suitable for on-device deployment and which require cloud inference.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'How do you handle app store AI disclosure requirements?', 'The specification includes platform-specific disclosure requirements for iOS and Android, aligned to current App Store and Google Play policies.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'What if our app user base is privacy-sensitive?', 'Privacy-first AI design is the default. Data minimisation, on-device processing options, and explicit consent flows are designed into every use case.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (15, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your existing app architecture and agree the AI design scope.', 3);

-- Mobile Apps (High-Impact) - Deploy (variant 16)
UPDATE product_content SET
  description = 'Build and launch your mobile app with sprint-based engineering, rigorous QA across iOS and Android, and a documented handover that leaves your team able to manage and evolve the product independently.',
  positioning = 'Mobile app delivered: built to specification, tested on real devices, and handed over with full documentation.',
  hero_summary = 'Build and launch your mobile app with sprint-based engineering, rigorous QA across iOS and Android, and a documented handover that leaves your team able to manage and evolve the product independently.',
  overview_paragraphs = '["The Mobile Apps & Services Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed mobile apps and mobile services changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for digital product, cx & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated mobile apps assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Real-device QA included across iOS and Android before launch","App store submission managed as part of the service","Hypercare period for priority defect resolution post-launch"]'::jsonb,
  why_it_matters = '{"hook":"Your mobile apps are where users engage most deeply, and where experience gaps have the greatest impact.","problemParagraph":"Many organisations stall between approved designs and production for your mobile apps, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for mobile apps sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Mobile Apps Deploy service.'
WHERE variant_id = 16;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'Production-ready mobile app', 'Fully built application on iOS and Android meeting the specification, passing QA, and live in both app stores.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'QA test report', 'Documented test results covering real-device performance, accessibility, offline behaviour, and resolved defects.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'App store submission package', 'App store listings, screenshots, metadata, and privacy disclosures prepared and submitted with review process managed.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (16, 'Technical handover documentation', 'Architecture overview, API documentation, build and deployment procedures, and maintenance guides for your engineering team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'Do you build native or cross-platform apps?', 'Both options are available. The DigitalQatalyst team recommends the approach best suited to your performance requirements, team capability, and budget during the design phase.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'How do you handle app store rejection during the review process?', 'App store review requirements are built into the QA checklist before submission. If a rejection occurs, the DigitalQatalyst team resolves the flagged issue and resubmits.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'What is included in the hypercare period?', 'Priority defect resolution, performance monitoring, and crash report triage for a defined window after launch. Duration is confirmed during scoping.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (16, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the design specification and agree the build schedule and technology stack.', 3);

-- Mobile Apps (High-Impact) - AI Deploy (variant 17)
UPDATE product_content SET
  description = 'Deploy your validated AI mobile features into production with on-device and cloud infrastructure configured, safety controls active, and your product team trained to manage every feature after handover.',
  positioning = 'AI mobile features live: on-device models deployed, monitoring active, and your team in control.',
  hero_summary = 'Deploy your validated AI mobile features into production with on-device and cloud infrastructure configured, safety controls active, and your product team trained to manage every feature after handover.',
  overview_paragraphs = '["The Mobile Apps & Services AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled mobile apps and mobile services workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for digital product, cx & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for mobile apps with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["On-device and cloud AI deployment options both supported","Privacy controls and consent flows verified before public release","Model update and retraining procedures documented at handover"]'::jsonb,
  why_it_matters = '{"hook":"Your mobile apps are where users engage most deeply, and where experience gaps have the greatest impact.","problemParagraph":"Many AI initiatives for your mobile apps fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for mobile apps fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about the Mobile Apps AI Deploy service.'
WHERE variant_id = 17;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'Deployed AI mobile features', 'AI capabilities live in your production app on iOS and Android, integrated with your backend services and confirmed against acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'Mobile AI monitoring dashboard', 'Real-time view of model accuracy, inference latency, battery impact, and error rates with configured alerts.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'Privacy and consent implementation', 'User consent flows, data handling disclosures, and privacy controls implemented, tested, and confirmed against platform policies.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (17, 'AI model management guide', 'Procedures for monitoring performance, triggering retraining, deploying model updates, and handling AI-related incidents.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'How do on-device model updates reach users?', 'Model updates can be delivered via app store releases or over-the-air model delivery frameworks. The deployment approach is documented in the model management guide.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'Will AI features increase our app''s data consumption or battery usage?', 'Battery and data impact are monitored as part of the production deployment. On-device model size and inference frequency are optimised during the build phase.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'How do we manage AI features if we do not have ML engineers in-house?', 'The handover documentation and training are designed for product and mobile engineering teams without dedicated ML expertise. The DigitalQatalyst team can also provide an ongoing managed tier.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (17, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the deployment environment and tooling.', 3);

-- Mobile Apps (High-Impact) - Managed (variant 18)
UPDATE product_content SET
  description = 'Keep your mobile app performing, updated, and growing with ongoing release management, performance monitoring, and user feedback analysis handled by the DigitalQatalyst team under a defined SLA.',
  positioning = 'Mobile app operations on autopilot: releases managed, performance monitored, issues resolved.',
  hero_summary = 'Keep your mobile app performing, updated, and growing with ongoing release management, performance monitoring, and user feedback analysis handled by the DigitalQatalyst team under a defined SLA.',
  overview_paragraphs = '["The Mobile Apps & Services Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve mobile apps and mobile services with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for digital product, cx & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for mobile apps - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Monthly release management with SLA-backed defect resolution","App store optimisation included in the managed plan","Quarterly product reviews grounded in retention and user feedback data"]'::jsonb,
  why_it_matters = '{"hook":"Your mobile apps are where users engage most deeply, and where experience gaps have the greatest impact.","problemParagraph":"Many organisations struggle to sustain performance across your mobile apps after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"mobile apps issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Mobile Apps Managed service.'
WHERE variant_id = 18;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'Monthly release report', 'Record of all releases including changes shipped, QA outcomes, and app store review status.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'Performance and stability report', 'Monthly crash rates, ANR rates, and performance benchmarks with trends and resolved issue log.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'App store optimisation report', 'Keyword rankings, rating trends, review response log, and listing update history by month.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (18, 'Quarterly product review', 'Retention analysis, user feedback synthesis, and prioritised feature and improvement recommendations for the next quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'What is included in monthly release management?', 'Bug fixes, OS and device compatibility updates, and minor enhancements within agreed scope. Feature additions are quoted separately.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'How quickly are critical crashes resolved?', 'Critical crash SLA timeframes are agreed during onboarding. The DigitalQatalyst team monitors crash reporting continuously and escalates immediately for severity-one issues.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'Do you manage both the iOS and Android app store presences?', 'Yes. App Store Connect and Google Play management are both included in the managed service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'What happens if a new OS version breaks our app?', 'The DigitalQatalyst team monitors OS beta releases and tests compatibility ahead of public releases, issuing a compatibility update before it affects users.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (18, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your app, agree the release cadence, and confirm the monitoring and SLA terms.', 4);

-- Physical Channels (High-Impact) - Assess (variant 19)
UPDATE product_content SET
  description = 'Assess how your branches, service centres, and in-person touchpoints are performing today, identify where frontline experience is inconsistent or inefficient, and receive a prioritised improvement roadmap for your operations leadership.',
  positioning = 'Frontline experience audited: service gaps mapped, consistency failures identified, priorities set.',
  hero_summary = 'Assess how your branches, service centres, and in-person touchpoints are performing today, identify where frontline experience is inconsistent or inefficient, and receive a prioritised improvement roadmap for your operations leadership.',
  overview_paragraphs = '["The Physical & Frontline Channels Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps gaps and returns prioritised improvements across branches, kiosks, and digital handoffs.","See how physical channels and frontline experience perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for operations, cx & facilities leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews physical channels across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Mystery shopping and direct observation included, not just survey data","Digital-to-physical handoff gaps specifically assessed","Roadmap structured for operations teams, not just strategic leaders"]'::jsonb,
  why_it_matters = '{"hook":"Your physical and digital touchpoints must work as one, or customer journeys break at the seams.","problemParagraph":"Many organisations run phygital environments with disconnected touchpoints, inconsistent service paths, and no clear view of AI-enabled interactions. This assessment maps gaps and returns prioritised improvements across branches, kiosks, and digital handoffs.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Disconnected touchpoints","description":"Customers repeat steps or lose context between physical and digital channels."},{"title":"Inconsistent service paths","description":"Staff and self-service journeys vary by location without shared standards."},{"title":"No intelligent interaction baseline","description":"Routing, kiosk, and assistant opportunities are unclear and untested."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Unified journey priorities","description":"You know which phygital paths to fix first across locations and channels."},{"title":"Ranked improvement plan","description":"Gaps are ordered for design, technology, and operational investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and staged transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Physical Channels assessment.'
WHERE variant_id = 19;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Physical channel audit report', 'Location-by-location findings on service quality, process efficiency, staff tools, and customer experience consistency.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Digital-to-physical handoff analysis', 'Mapped gaps where digital journeys fail to connect with in-person service, with specific causes and recommended fixes.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Staff and process friction inventory', 'Identified workflow bottlenecks and tool gaps reducing frontline staff efficiency, with severity ratings.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (19, 'Prioritised physical channel roadmap', 'Sequenced improvement actions with customer experience scores, operational effort estimates, and suggested owners.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'How many locations do you visit for the audit?', 'A sample of locations is agreed during scoping based on your network size and geographic spread. Findings are extrapolated across the full estate.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'Do staff know they are being observed?', 'Mystery shopping visits are unannounced. Structured observation sessions are agreed with site managers in advance. The approach is confirmed with your team during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'Do you cover kiosks and automated service points as well as staffed counters?', 'Yes. All physical touchpoints within scope are included, whether staffed, self-service, or hybrid.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (19, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the location sample, access arrangements, and assessment scope.', 3);

-- Physical Channels (High-Impact) - Design (variant 20)
UPDATE product_content SET
  description = 'Design a consistent, connected physical service experience across your entire location network: standardised journeys, optimised staff workflows, and integrated digital handoffs specified for your operations team to implement.',
  positioning = 'Physical service reimagined: connected journeys, standard processes, and digital integration designed for every location.',
  hero_summary = 'Design a consistent, connected physical service experience across your entire location network: standardised journeys, optimised staff workflows, and integrated digital handoffs specified for your operations team to implement.',
  overview_paragraphs = '["The Physical & Frontline Channels Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines connected experiences across kiosks, branches, and digital touchpoints.","Turn physical channels and frontline experience goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for operations, cx & facilities leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate physical channels requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Frontline staff input built into the design process, not added at the end","Digital integration specified alongside physical journeys","Pilot-ready documentation for a test location before network rollout"]'::jsonb,
  why_it_matters = '{"hook":"Your physical and digital touchpoints must work as one, or customer journeys break at the seams.","problemParagraph":"Many organisations upgrade physical channels without integrated journey design, service standards, or specifications operations teams can deploy. This design engagement defines connected experiences across kiosks, branches, and digital touchpoints.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Siloed channel design","description":"Physical and digital experiences are planned without a shared customer model."},{"title":"Undefined service standards","description":"Staff workflows, signage, and digital handoffs lack consistent patterns."},{"title":"Deployment ambiguity","description":"Operations teams lack specs to roll out changes across locations."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Integrated experience designs","description":"Journeys connect physical and digital touchpoints with clear handoffs."},{"title":"Operational standards","description":"Service paths, staffing models, and technology requirements are defined upfront."},{"title":"Rollout-ready specifications","description":"Teams receive artefacts they can pilot and scale across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the Physical Channels Design service.'
WHERE variant_id = 20;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Redesigned service journey maps', 'Step-by-step service flows for each priority scenario, tested with frontline staff and validated against customer research.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Standard operating procedures', 'Documented service steps, decision rules, tool requirements, and escalation paths for each redesigned journey.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Digital-to-physical integration specification', 'Technical and process requirements for passing customer context between digital and in-person channels without friction.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (20, 'Environment and wayfinding guidance', 'Recommendations for signage, layout, and technology placement to align the physical environment with the redesigned service journeys.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'Do you design for a single location type or the whole network?', 'The design is built for your standard location model and adapted for variations (high-volume vs. smaller format, for example). Network rollout planning is included.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'How do you involve frontline staff in the design?', 'Structured interviews and co-design workshops with frontline teams are built into the engagement so the resulting SOPs reflect operational reality.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'Can the design accommodate different location formats across our estate?', 'Yes. The DigitalQatalyst team identifies the core journey standard and documents format-specific variations where needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (20, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your existing location formats and agree the design scope and pilot approach.', 3);

-- Physical Channels (High-Impact) - AI Design (variant 21)
UPDATE product_content SET
  description = 'Identify which AI tools will improve frontline service speed, reduce staff administrative burden, and make in-person experience more responsive, then validate those use cases and produce specifications ready for build.',
  positioning = 'AI for physical channels: queue intelligence, staff assistance, and in-store analytics designed before deployment.',
  hero_summary = 'Identify which AI tools will improve frontline service speed, reduce staff administrative burden, and make in-person experience more responsive, then validate those use cases and produce specifications ready for build.',
  overview_paragraphs = '["The Physical & Frontline Channels AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for physical channels and frontline experience, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for operations, cx & facilities leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for physical channels.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Camera and sensor AI use cases assessed with privacy and consent design built in","Edge AI options included for locations with limited connectivity","Integration specified against your existing POS and CRM stack"]'::jsonb,
  why_it_matters = '{"hook":"Your physical and digital touchpoints must work as one, or customer journeys break at the seams.","problemParagraph":"Many organisations apply AI to your phygital touchpoints without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for physical channels lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for physical channels are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the Physical Channels AI Design service.'
WHERE variant_id = 21;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Physical channel AI opportunity register', 'Ranked AI use cases for your location network, each scored on operational impact, hardware feasibility, and privacy considerations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Edge AI deployment assessment', 'Analysis of on-premise versus cloud AI options for locations with constrained connectivity, including hardware requirements.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Responsible AI design for physical contexts', 'Consent mechanisms, data handling procedures, and bias mitigation requirements for camera-based or biometric AI systems.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (21, 'Physical channel AI build specification', 'Integration contracts, hardware specifications, and data flows connecting AI tools to your existing branch and retail systems.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'Can AI tools work in locations with poor internet connectivity?', 'Edge AI deployment is assessed as part of this engagement. Many queue management and decision support tools can operate on-premise with periodic cloud sync.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'What regulations apply to AI in physical retail or branch environments?', 'Camera-based and biometric AI systems are subject to specific regional regulations. The design engagement includes a regulatory landscape review for your operating regions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'How do you get staff buy-in for AI tools in a physical environment?', 'Staff impact and change management are considered in the workflow design. The DigitalQatalyst team can include a change readiness assessment as part of the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (21, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm your location types, existing technology, and regulatory context before agreeing the design scope.', 3);

-- Physical Channels (High-Impact) - Deploy (variant 22)
UPDATE product_content SET
  description = 'Implement the designed physical channel improvements across your location network with phased rollout management, per-cohort sign-off, staff training, and operational handover so every location delivers the new experience from launch day.',
  positioning = 'Physical channel improvements deployed: configured, trained, and rolled out across your network.',
  hero_summary = 'Implement the designed physical channel improvements across your location network with phased rollout management, per-cohort sign-off, staff training, and operational handover so every location delivers the new experience from launch day.',
  overview_paragraphs = '["The Physical & Frontline Channels Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed physical channels and frontline experience changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for operations, cx & facilities leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated physical channels assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pilot location approach proves value before full network investment","Staff training delivered in-location, not just classroom-based","Full operations handover with documented maintenance procedures"]'::jsonb,
  why_it_matters = '{"hook":"Your physical and digital touchpoints must work as one, or customer journeys break at the seams.","problemParagraph":"Many organisations stall between approved designs and production for your phygital touchpoints, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for physical channels sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Physical Channels Deploy service.'
WHERE variant_id = 22;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Deployed physical channel improvements', 'Technology configured, processes implemented, and staff trained across all agreed locations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Pilot performance report', 'Measurement results from the pilot location including customer experience metrics, staff adoption rates, and identified adjustments applied to the network rollout.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Staff training materials', 'Role-specific training guides, quick reference cards, and e-learning content for ongoing staff onboarding.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (22, 'Operations handover pack', 'System documentation, maintenance procedures, escalation paths, and SLA terms for each deployed capability.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'How is the rollout sequenced across a large location network?', 'The DigitalQatalyst team designs a location tiering approach based on volume, geography, and complexity. The rollout sequence is agreed with your operations team before deployment begins.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'What happens if a location has specific technical constraints?', 'Location-specific constraints are assessed during the pilot phase. Configuration variations are documented before the network rollout begins.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'How is staff training managed across multiple shifts and locations?', 'Training is delivered in-location by DigitalQatalyst team trainers, with self-service guides and refresher materials for staff who join after go-live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (22, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the location scope, existing technology, and rollout timeline.', 3);

-- Physical Channels (High-Impact) - AI Deploy (variant 23)
UPDATE product_content SET
  description = 'Put AI tools into your branches, stores, and service centres with hardware deployed, safety controls active, and frontline staff trained to use and manage every AI-powered feature in their daily work.',
  positioning = 'AI in your physical locations: deployed, tested, and your frontline team trained and ready.',
  hero_summary = 'Put AI tools into your branches, stores, and service centres with hardware deployed, safety controls active, and frontline staff trained to use and manage every AI-powered feature in their daily work.',
  overview_paragraphs = '["The Physical & Frontline Channels AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled physical channels and frontline experience workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for operations, cx & facilities leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for physical channels with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Hardware and software deployment managed end-to-end","Frontline staff trained at the location, not in a classroom","Centralised monitoring dashboard covering the full location network"]'::jsonb,
  why_it_matters = '{"hook":"Your physical and digital touchpoints must work as one, or customer journeys break at the seams.","problemParagraph":"Many AI initiatives for your phygital touchpoints fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for physical channels fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about the Physical Channels AI Deploy service.'
WHERE variant_id = 23;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Deployed physical channel AI tools', 'AI hardware and software live at all agreed locations, integrated with branch systems and confirmed against acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Physical AI monitoring dashboard', 'Centralised view of AI tool performance, hardware health, and safety alerts across all locations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Frontline staff training and reference materials', 'In-location training sessions and quick reference guides for every AI tool deployed, covering normal operation and escalation procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (23, 'Physical AI operations guide', 'Maintenance schedules, incident response procedures, and escalation contacts for each deployed AI capability.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'Do you manage hardware procurement as part of this service?', 'Hardware specification and sourcing support are included. The DigitalQatalyst team can manage procurement or work alongside your existing vendor relationships.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'How do you handle locations where AI hardware fails?', 'The operations guide includes hardware fault escalation procedures and fallback processes so service continues without the AI tool until repair or replacement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'How do customers at each location know AI is being used?', 'Consent and disclosure requirements are implemented at each location in line with the responsible AI design specification. Signage, screen notices, and staff scripts are all included.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (23, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the hardware and infrastructure requirements.', 3);

-- Physical Channels (High-Impact) - Managed (variant 24)
UPDATE product_content SET
  description = 'Keep your physical channel technology performing and your frontline operations running smoothly with ongoing monitoring, maintenance, and optimisation managed by the DigitalQatalyst team under a defined SLA.',
  positioning = 'Physical operations managed: technology maintained, performance tracked, and issues resolved before they reach customers.',
  hero_summary = 'Keep your physical channel technology performing and your frontline operations running smoothly with ongoing monitoring, maintenance, and optimisation managed by the DigitalQatalyst team under a defined SLA.',
  overview_paragraphs = '["The Physical & Frontline Channels Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve physical channels and frontline experience with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for operations, cx & facilities leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for physical channels - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Preventive maintenance included to reduce unplanned downtime","SLA-backed incident response with monthly compliance reporting","Quarterly experience reviews keep operational improvements data-driven"]'::jsonb,
  why_it_matters = '{"hook":"Your physical and digital touchpoints must work as one, or customer journeys break at the seams.","problemParagraph":"Many organisations struggle to sustain performance across your phygital touchpoints after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"physical channels issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Physical Channels Managed service.'
WHERE variant_id = 24;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'Monthly operations report', 'Technology uptime, incident log, maintenance activity, and customer flow metrics across all managed locations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'SLA compliance record', 'Tracked resolution times for every incident against agreed SLA tiers, with root cause notes for recurring issues.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'Quarterly experience review', 'Physical channel performance against goals, with customer feedback synthesis and prioritised improvement recommendations.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (24, 'Technology lifecycle report', 'Annual review of hardware age, software version currency, and replacement or upgrade recommendations for each location.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'Do you manage technology at every location or just a subset?', 'The managed service can cover your full network or a defined subset. Location scope is agreed during onboarding and can be expanded as your network grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'How are hardware faults handled when they need on-site attendance?', 'The DigitalQatalyst team coordinates with your facilities teams and approved vendors for on-site faults. Remote resolution is attempted first to minimise wait times.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'What is the escalation path during a major incident affecting multiple locations?', 'A major incident protocol is agreed during onboarding. The DigitalQatalyst team activates the protocol and provides hourly updates until resolution.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'Can the managed service cover newly opened locations?', 'Yes. New location onboarding is part of the managed service. The DigitalQatalyst team adds locations to monitoring as they open.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (24, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your location network, existing technology, and agree the SLA terms.', 4);

-- Integrated Experience (High-Impact) - Assess (variant 25)
UPDATE product_content SET
  description = 'Assess the consistency, quality, and connectivity of your customer and employee experience across every channel, identify where journeys break down at channel transitions, and receive a prioritised transformation roadmap.',
  positioning = 'Your end-to-end experience audited: cross-channel gaps mapped, consistency failures scored, priorities agreed.',
  hero_summary = 'Assess the consistency, quality, and connectivity of your customer and employee experience across every channel, identify where journeys break down at channel transitions, and receive a prioritised transformation roadmap.',
  overview_paragraphs = '["The Integrated Experience Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps cross-channel gaps and returns prioritised improvements your CX and digital leaders can act on.","See how integrated customer and employee experience perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cx, digital, product & marketing leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews integrated experience across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["All active channels assessed in a single, connected audit","Employee experience included alongside customer journey findings","Roadmap prioritised by cross-channel impact, not channel silos"]'::jsonb,
  why_it_matters = '{"hook":"Connected digital experiences are how customers judge your brand, across every channel and journey.","problemParagraph":"Many organisations deliver experiences through disconnected channels, inconsistent personalisation, and no single view of journey performance. This assessment maps cross-channel gaps and returns prioritised improvements your CX and digital leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Channel fragmentation","description":"Customers receive inconsistent messaging and service across touchpoints."},{"title":"Weak journey measurement","description":"Teams optimise channels in isolation without shared journey metrics."},{"title":"Limited personalisation maturity","description":"Targeting and orchestration capabilities are unclear and unevenly adopted."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Cross-channel priorities","description":"You know which journeys and integrations to fix first."},{"title":"Ranked experience backlog","description":"Gaps are ordered for design, platform, and investment decisions."},{"title":"Leadership-ready roadmap","description":"Recommendations are structured for governance and staged delivery funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Integrated Experience assessment.'
WHERE variant_id = 25;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Cross-channel experience audit', 'End-to-end journey findings across all in-scope channels, with each handoff point rated for continuity, effort, and customer satisfaction impact.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Channel handoff analysis', 'Specific gaps where customer context is lost or repeated at channel transitions, with root cause and recommended fixes.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Employee experience snapshot', 'Frontline tool and process gaps identified through staff interviews, rated by impact on service quality.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (25, 'Integrated experience roadmap', 'Prioritised recommendations spanning all channels, with expected cross-channel impact, effort estimates, and sequencing rationale.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'How many channels do you cover in the audit?', 'The scope is agreed during the initial consultation based on your active channels. A typical integrated assessment covers web, mobile, social, and at least one physical touchpoint.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'Do you assess B2B and B2C journeys in the same engagement?', 'Yes, if both are in scope. The DigitalQatalyst team maps journeys separately by customer type and identifies shared platform or process dependencies.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'What if we do not have data on cross-channel journeys?', 'Direct observation, customer interviews, and mystery shopping are used alongside analytics. Good findings are possible even without mature cross-channel tracking.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (25, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the channel scope, data access requirements, and stakeholder involvement before work begins.', 3);

-- Integrated Experience (High-Impact) - Design (variant 26)
UPDATE product_content SET
  description = 'Design a connected, consistent customer and employee experience across every channel: unified journeys, shared data architecture, and an adoption plan your CX and technology teams can execute together.',
  positioning = 'Experience designed end-to-end: consistent journeys, unified data, and an adoption plan across every channel.',
  hero_summary = 'Design a connected, consistent customer and employee experience across every channel: unified journeys, shared data architecture, and an adoption plan your CX and technology teams can execute together.',
  overview_paragraphs = '["The Integrated Experience Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines connected journeys and build-ready experience specifications.","Turn integrated customer and employee experience goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cx, digital, product & marketing leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate integrated experience requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["All channels designed together, not as separate workstreams","Data architecture included so channels can actually share context","Employee experience designed alongside customer journeys"]'::jsonb,
  why_it_matters = '{"hook":"Connected digital experiences are how customers judge your brand, across every channel and journey.","problemParagraph":"Many organisations plan integrated experiences without orchestration models, personalisation standards, or specifications platform teams can implement. This design engagement defines connected journeys and build-ready experience specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined orchestration model","description":"Journey triggers, content rules, and channel handoffs are not designed end to end."},{"title":"Inconsistent personalisation","description":"Audience segments and experience rules vary by channel and team."},{"title":"Platform ambiguity","description":"Implementation teams lack specs for integration, data, and governance."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Connected journey designs","description":"Experiences are mapped across channels with clear orchestration logic."},{"title":"Personalisation standards","description":"Segmentation, content, and governance rules are defined upfront."},{"title":"Implementation-ready specs","description":"Platform teams receive artefacts that accelerate integrated delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about the Integrated Experience Design service.'
WHERE variant_id = 26;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Unified customer journey maps', 'End-to-end journey designs spanning every in-scope channel, with detailed channel handoff specifications and no identified gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Experience data architecture', 'Data model and flow design showing how customer context, preferences, and history are shared across channels and systems.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Personalisation framework', 'Segmentation approach, trigger logic, and content strategy for delivering relevant experiences across touchpoints.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (26, 'Experience adoption plan', 'Rollout sequencing, change management steps, and training approach for CX, technology, and frontline teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'Does this design work if we have different technology platforms per channel?', 'Yes. The experience data architecture is designed to work across your existing platform mix. Integration requirements are documented for each channel''s technology.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'How detailed is the personalisation framework?', 'The framework covers segmentation criteria, trigger events, content slot definitions, and a testing approach. It is specification-level, ready for your technology team to implement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'Can the design cover employee-facing tools as well as customer journeys?', 'Yes. Employee journey design and frontline tool requirements are included in the integrated experience design by default.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (26, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your channel landscape and agree the design scope and channel coverage.', 3);

-- Integrated Experience (High-Impact) - AI Design (variant 27)
UPDATE product_content SET
  description = 'Validate the AI use cases that will make your integrated experience genuinely more personalised and responsive, define responsible workflows for every validated use case, and produce specifications your technology teams can build to.',
  positioning = 'AI for integrated experience: personalisation engines, journey intelligence, and next-best-action workflows specified before build.',
  hero_summary = 'Validate the AI use cases that will make your integrated experience genuinely more personalised and responsive, define responsible workflows for every validated use case, and produce specifications your technology teams can build to.',
  overview_paragraphs = '["The Integrated Experience AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for integrated customer and employee experience, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cx, digital, product & marketing leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for integrated experience.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Data readiness assessed before any AI use case is committed to build","Responsible personalisation design built in from the start","Cross-channel integration specified so AI works across your full estate"]'::jsonb,
  why_it_matters = '{"hook":"Connected digital experiences are how customers judge your brand, across every channel and journey.","problemParagraph":"Many organisations apply AI to your integrated customer experiences without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for integrated experience lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for integrated experience are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the Integrated Experience AI Design service.'
WHERE variant_id = 27;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Integrated experience AI opportunity register', 'Ranked AI use cases for your cross-channel environment, each scored on personalisation impact, data readiness, and implementation complexity.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Data readiness assessment', 'Review of your customer data estate confirming which AI use cases are feasible today and what data gaps need addressing first.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Responsible AI personalisation design', 'Consent mechanisms, explainability requirements, bias testing criteria, and data retention rules for customer-facing AI features.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (27, 'Cross-channel AI integration specification', 'API contracts and data flow design showing how AI model outputs reach the right channel at the right moment in the customer journey.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'What if our customer data is fragmented across multiple systems?', 'The data readiness assessment identifies fragmentation and prioritises the data consolidation needed before each AI use case. Not all use cases require a full data platform.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'How do you ensure personalisation AI respects customer privacy preferences?', 'Every personalisation workflow design includes consent integration, preference management, and data minimisation requirements aligned to your regulatory context.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'Can AI orchestrate the customer journey across channels in real time?', 'Real-time journey orchestration is assessed as a use case. Feasibility depends on your existing data infrastructure, which the assessment confirms.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (27, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current AI maturity and agree the design scope.', 3);

-- Integrated Experience (High-Impact) - Deploy (variant 28)
UPDATE product_content SET
  description = 'Build and activate your integrated experience design across every channel: technology configured, data pipelines live, and your CX and technology teams handed a fully documented, operational cross-channel platform.',
  positioning = 'Integrated experience live: channels connected, data flowing, and your teams in control from day one.',
  hero_summary = 'Build and activate your integrated experience design across every channel: technology configured, data pipelines live, and your CX and technology teams handed a fully documented, operational cross-channel platform.',
  overview_paragraphs = '["The Integrated Experience Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed integrated customer and employee experience changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cx, digital, product & marketing leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated integrated experience assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["All channel integrations tested end-to-end before go-live","Unified customer data view configured as part of the deployment","Training and documentation for CX, technology, and operations teams"]'::jsonb,
  why_it_matters = '{"hook":"Connected digital experiences are how customers judge your brand, across every channel and journey.","problemParagraph":"Many organisations stall between approved designs and production for your integrated customer experiences, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for integrated experience sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Integrated Experience Deploy service.'
WHERE variant_id = 28;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'Integrated experience platform', 'All channels connected and integrated, with data flowing between systems and the unified customer view live and tested.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'QA and integration test report', 'Documented test results covering all cross-channel integration paths, data accuracy, and journey orchestration logic.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'Personalisation and orchestration configuration', 'All segments, triggers, and content rules configured and tested in the journey orchestration tool, with documented logic for each.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (28, 'Operations handover pack', 'Platform architecture documentation, data management procedures, and team training materials for CX, technology, and operations staff.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'How do you manage the complexity of integrating multiple channel platforms?', 'Integration is managed against a documented specification with each connection tested individually then end-to-end. A phased go-live reduces risk for complex multi-system environments.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'What if one of our channel platforms does not support the required integration?', 'Integration feasibility is confirmed during the design phase. Where platform limitations exist, the DigitalQatalyst team designs the best available workaround.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'How long does the team training take?', 'Training is scheduled across the final three weeks of deployment and tailored by role. Self-service guides cover every platform for ongoing reference.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (28, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the experience design specification and agree the deployment scope and timeline.', 3);

-- Integrated Experience (High-Impact) - AI Deploy (variant 29)
UPDATE product_content SET
  description = 'Deploy AI-powered personalisation, journey orchestration, and next-best-action capabilities across your full channel estate with safety controls active and your CX teams trained to manage every AI feature in production.',
  positioning = 'AI experience capabilities live: personalisation active, journey intelligence running, and your CX team in control.',
  hero_summary = 'Deploy AI-powered personalisation, journey orchestration, and next-best-action capabilities across your full channel estate with safety controls active and your CX teams trained to manage every AI feature in production.',
  overview_paragraphs = '["The Integrated Experience AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled integrated customer and employee experience workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cx, digital, product & marketing leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for integrated experience with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Personalisation and orchestration AI active across all channels simultaneously","A/B testing framework configured to measure AI feature impact from day one","CX team trained to manage and override AI recommendations independently"]'::jsonb,
  why_it_matters = '{"hook":"Connected digital experiences are how customers judge your brand, across every channel and journey.","problemParagraph":"Many AI initiatives for your integrated customer experiences fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for integrated experience fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about the Integrated Experience AI Deploy service.'
WHERE variant_id = 29;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'Deployed AI experience capabilities', 'Personalisation, orchestration, and next-best-action AI live across all agreed channels, integrated with your customer data platform and CRM.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'AI monitoring and performance dashboard', 'Real-time view of model accuracy, recommendation click-through, segment coverage, and safety control activity across channels.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'AI safety and consent configuration', 'Consent integration, bias monitoring rules, and output audit logging configured and verified before full production release.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (29, 'CX AI operations guide', 'Procedures for managing segment updates, reviewing AI recommendation performance, overriding outputs, and responding to AI incidents.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'How do you prevent AI personalisation from feeling intrusive to customers?', 'Personalisation rules and content logic are calibrated during testing to ensure relevance without overreach. Customers can also manage their preferences through the consent controls.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'What happens when an AI recommendation is wrong?', 'CX teams are trained to review and override AI recommendations. The monitoring dashboard flags low-performing recommendations automatically so corrections can be made quickly.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'How does the orchestration AI handle customers who move between channels?', 'Journey orchestration uses the unified customer profile to maintain context across channel switches. The handoff logic is tested end-to-end before full release.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (29, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review the AI design specification and confirm the deployment infrastructure and integration requirements.', 3);

-- Integrated Experience (High-Impact) - Managed (variant 30)
UPDATE product_content SET
  description = 'Keep your integrated customer experience performing, personalised, and consistent across all channels with ongoing operations, AI model governance, and cross-channel performance reporting managed by the DigitalQatalyst team.',
  positioning = 'Integrated experience managed end-to-end: all channels monitored, AI models governed, and performance improving monthly.',
  hero_summary = 'Keep your integrated customer experience performing, personalised, and consistent across all channels with ongoing operations, AI model governance, and cross-channel performance reporting managed by the DigitalQatalyst team.',
  overview_paragraphs = '["The Integrated Experience Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve integrated customer and employee experience with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cx, digital, product & marketing leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for integrated experience - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["All channels and AI features governed in a single managed service","Monthly AI model review included, not an optional add-on","Quarterly strategy sessions keep the experience aligned with business priorities"]'::jsonb,
  why_it_matters = '{"hook":"Connected digital experiences are how customers judge your brand, across every channel and journey.","problemParagraph":"Many organisations struggle to sustain performance across your integrated customer experiences after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"integrated experience issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Integrated Experience Managed service.'
WHERE variant_id = 30;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Monthly cross-channel performance report', 'Customer satisfaction, journey completion, channel adoption, and personalisation effectiveness across all managed channels.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Monthly AI governance report', 'Personalisation accuracy, segment coverage, bias monitoring outcomes, and model performance trends with recommended adjustments.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Content and segment management log', 'Record of all segment and content updates made during the month, with rationale and measured impact.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (30, 'Quarterly integrated experience review', 'Strategic assessment of cross-channel experience against business goals, with a prioritised improvement plan for the next quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'Does the managed service cover both the technology and the experience strategy?', 'Yes. The DigitalQatalyst team manages technology performance and governance while the quarterly review covers experience strategy and improvement prioritisation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'How are AI models updated if personalisation accuracy degrades?', 'The monthly AI governance review identifies accuracy degradation. The DigitalQatalyst team recommends and implements model updates or retraining within the managed service.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'What if we want to add a new channel to the managed service?', 'New channels are onboarded through a scoped addition to the managed service. The DigitalQatalyst team confirms integration requirements and extends monitoring before the channel goes live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'How is the cross-channel data kept accurate and current?', 'Data pipeline health is monitored continuously. The DigitalQatalyst team alerts your team to any pipeline issues and resolves them within agreed SLA timeframes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (30, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your channel estate, existing platform access, and agree the SLA and governance terms before onboarding.', 4);

-- CRM Solutions (High-Impact) - Assess (variant 31)
UPDATE product_content SET
  description = 'Audit your CRM platform and relationship management practices against current performance data, then receive a prioritised roadmap of the changes most likely to lift pipeline visibility and revenue consistency.',
  positioning = 'Understand exactly where your CRM is costing you deals, before you spend a pound on change.',
  hero_summary = 'Audit your CRM platform and relationship management practices against current performance data, then receive a prioritised roadmap of the changes most likely to lift pipeline visibility and revenue consistency.',
  overview_paragraphs = '["The CRM & Customer Relationship Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps maturity and returns a prioritised CRM improvement roadmap.","See how CRM and relationship management perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for sales, marketing, service & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews crm solutions across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope, no-obligation assessment completed within one week","Evidence-led findings grounded in your CRM data, not generic benchmarks","Roadmap ready for immediate stakeholder review and sign-off"]'::jsonb,
  why_it_matters = '{"hook":"Your CRM is the backbone of how you understand, serve, and retain customers.","problemParagraph":"Many organisations run CRM platforms with fragmented customer data, inconsistent sales and service processes, and limited insight into automation opportunities. This assessment maps maturity and returns a prioritised CRM improvement roadmap.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Incomplete customer view","description":"Teams work from conflicting records because data quality and ownership are unclear."},{"title":"Process inconsistency","description":"Sales, service, and marketing workflows vary by team without shared standards."},{"title":"Underused platform capability","description":"Integrations, automation, and reporting potential are not fully understood."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Shared CRM maturity view","description":"Leadership sees where data, process, and platform readiness stand today."},{"title":"Prioritised improvement plan","description":"Initiatives are ordered by customer impact, dependency, and feasibility."},{"title":"Investment clarity","description":"Your commercial and technology leaders can fund the right CRM fixes first."}]}}'::jsonb,
  faq_intro = 'Common questions about the CRM platform maturity assessment.'
WHERE variant_id = 31;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'CRM maturity scorecard', 'Ratings across data quality, adoption, pipeline hygiene, and integration coverage, with specific evidence for each score.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'Gap and root-cause register', 'Every identified gap linked to its business impact, so investment decisions are grounded in actual revenue and retention risk.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'Prioritised CRM improvement roadmap', 'Sequenced actions ranked by impact and effort, with suggested owners and logical dependencies your teams can execute.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (31, 'Executive summary', 'A concise brief for your leadership team covering findings, priorities, and the investment case for the next phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'What CRM platforms do you assess?', 'The DigitalQatalyst team works across Salesforce, HubSpot, Microsoft Dynamics, and other major CRM platforms. We confirm platform scope during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'What access do you need from us?', 'Primarily read-only access to CRM reports and configuration, plus 3-4 hours of stakeholder time across sales, marketing, and service leads. No write access is required.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'Will the roadmap tell us how much change will cost?', 'The roadmap includes effort estimates and sequencing. Detailed cost modelling comes in the Design or Deploy phase once scope is confirmed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'Is this assessment suitable if we are mid-implementation?', 'Yes. A mid-implementation assessment often catches misalignments before they become expensive to fix. The DigitalQatalyst team adjusts scope to focus on the most actionable findings.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (31, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm scope, stakeholders, and data access before any work begins.', 4);

-- CRM Solutions (High-Impact) - Design (variant 32)
UPDATE product_content SET
  description = 'Turn your CRM improvement goals into user-centred workflows, integration specifications, and a build-ready blueprint your delivery team can implement with confidence.',
  positioning = 'A CRM design blueprint that closes the gap between what the platform can do and what your teams actually need.',
  hero_summary = 'Turn your CRM improvement goals into user-centred workflows, integration specifications, and a build-ready blueprint your delivery team can implement with confidence.',
  overview_paragraphs = '["The CRM & Customer Relationship Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns CRM goals into user-centred workflows and build-ready specifications.","Turn CRM and relationship management goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for sales, marketing, service & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate crm solutions requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["User-centred design validated with your sales, marketing, and service teams","Build-ready specifications your delivery team can implement without ambiguity","Adoption plan included, not bolted on at the end"]'::jsonb,
  why_it_matters = '{"hook":"Your CRM is the backbone of how you understand, serve, and retain customers.","problemParagraph":"Many organisations customise CRM without aligned process design, data models, or specifications delivery teams can implement. This design engagement turns CRM goals into user-centred workflows and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined process models","description":"Sales, service, and marketing journeys are not designed against a shared customer lifecycle."},{"title":"Data model gaps","description":"Fields, integrations, and ownership rules lack consistent definitions."},{"title":"Build ambiguity","description":"Admins and developers lack specs to configure and integrate with confidence."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned CRM workflows","description":"Processes reflect how teams actually sell, serve, and retain customers."},{"title":"Consistent data standards","description":"Models, integrations, and governance rules are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive configuration and integration artefacts they can execute."}]}}'::jsonb,
  faq_intro = 'Questions about the CRM design engagement and what it produces.'
WHERE variant_id = 32;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'CRM workflow and journey designs', 'Role-specific journey maps and process flows for sales pipeline, account management, and customer service, validated with end users.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'Data model and field specification', 'Object structure, custom field definitions, validation rules, and data governance guidelines to ensure clean, reportable data from day one.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'Integration architecture document', 'Detailed specifications for each system integration including data flows, trigger logic, error handling, and API or middleware requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (32, 'Adoption and change plan', 'Role-based training outlines, communication milestones, success metrics, and the criteria your team must meet before go-live.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'Do we need the Assess first?', 'Not necessarily. If you have clear goals and existing documentation, the Design engagement can begin with a condensed discovery phase. The DigitalQatalyst team will advise during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'Which teams need to be involved?', 'Typically sales, marketing, customer service, and IT representatives. We keep individual time commitments manageable through structured workshops rather than open-ended availability.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'Does the design cover custom development?', 'Yes, where configuration alone cannot meet a requirement, the specifications will include custom development scope so your delivery team has full clarity.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (32, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your existing documentation, confirms the CRM platform, and agrees workshop participants before work begins.', 3);

-- CRM Solutions (High-Impact) - AI Design (variant 33)
UPDATE product_content SET
  description = 'Validate which AI use cases genuinely improve CRM outcomes, then produce responsible workflow designs and deployment specifications your team can build and govern with confidence.',
  positioning = 'AI capabilities for your CRM platform, scoped responsibly and specified for build before any budget is committed.',
  hero_summary = 'Validate which AI use cases genuinely improve CRM outcomes, then produce responsible workflow designs and deployment specifications your team can build and govern with confidence.',
  overview_paragraphs = '["The CRM & Customer Relationship AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for CRM and relationship management, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for sales, marketing, service & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for crm solutions.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation before build investment, not after","Governance and safety controls designed in from the start","Specifications compatible with your existing CRM platform architecture"]'::jsonb,
  why_it_matters = '{"hook":"Your CRM is the backbone of how you understand, serve, and retain customers.","problemParagraph":"Many organisations apply AI to your CRM capability without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for crm solutions lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for crm solutions are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the CRM AI design engagement.'
WHERE variant_id = 33;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'AI use-case scorecard', 'Each candidate use case rated by business value, data availability, risk, and build feasibility, with a clear recommendation on what to pursue and in what order.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'Responsible AI workflow designs', 'Workflow diagrams showing AI decision points, human override logic, bias mitigation steps, and data handling in accordance with your privacy obligations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'Technical deployment specification', 'Model inputs, outputs, integration points, infrastructure requirements, and the acceptance criteria your team will use to validate production readiness.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (33, 'AI governance framework', 'Monitoring plan, escalation procedures, model refresh cadence, and the roles responsible for ongoing AI oversight within your CRM operations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'Which AI capabilities are most commonly scoped for CRM?', 'Lead scoring, next-best-action recommendations, deal risk flagging, and customer churn prediction are the most frequently validated. The DigitalQatalyst team works through your specific pipeline to identify what your data actually supports.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'What data quality do we need before AI design is viable?', 'The data readiness assessment in week one determines this. Many organisations find targeted data cleaning in specific fields is sufficient; others discover the Assess or Design phases should come first.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'Does the output tell us which AI vendor or model to use?', 'Yes. The specifications include vendor and model recommendations with rationale based on your CRM platform, data volume, and budget constraints.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (33, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your CRM platform, existing data assets, and business priorities to shape the engagement scope.', 3);

-- CRM Solutions (High-Impact) - Deploy (variant 34)
UPDATE product_content SET
  description = 'Configure, integrate, test, and launch your CRM platform improvements with structured quality assurance and a controlled handover that leaves your team fully operational.',
  positioning = 'CRM changes delivered on time, tested against your requirements, and handed over so your teams can run them without dependency on us.',
  hero_summary = 'Configure, integrate, test, and launch your CRM platform improvements with structured quality assurance and a controlled handover that leaves your team fully operational.',
  overview_paragraphs = '["The CRM & Customer Relationship Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed CRM and relationship management changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for sales, marketing, service & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated crm solutions assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Full quality assurance cycle from system integration test to user acceptance","Go-live playbook and rollback plan included as standard","Hypercare period after launch to resolve early operational issues quickly"]'::jsonb,
  why_it_matters = '{"hook":"Your CRM is the backbone of how you understand, serve, and retain customers.","problemParagraph":"Many organisations stall between approved designs and production for your CRM capability, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for crm solutions sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Common questions about the CRM platform deployment engagement.'
WHERE variant_id = 34;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'Configured CRM environment', 'A fully built, tested CRM instance covering all approved workflows, fields, automations, and role-based permissions, ready for user acceptance.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'Integration test results', 'Documented test evidence for every integration covering expected behaviours, edge cases, and the resolution record for any defects raised.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'User acceptance test report', 'Signed-off UAT outcomes per business scenario, showing which criteria passed, any accepted exceptions, and the agreed go-live decision.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (34, 'Operational handover pack', 'Administrator guides, escalation contacts, support procedures, and a 30-day post-launch check schedule so your team owns the platform from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'Do we need a design specification before deploying?', 'Yes. The Deploy engagement builds from an agreed specification. If you do not have one, the DigitalQatalyst team can help you produce it through the Design engagement first.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'How is data migration handled?', 'Migration is scoped, mapped, and tested in a sandbox environment before production cutover. The DigitalQatalyst team runs data quality checks at each stage.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'What happens if issues arise after go-live?', 'The hypercare period provides direct access to the delivery team to resolve production issues quickly. After hypercare concludes, the Managed service can take over ongoing operations.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (34, 'How do we get started?', 'Share your approved specification or design outputs and the DigitalQatalyst team will confirm scope, resourcing, and a delivery timeline.', 3);

-- CRM Solutions (High-Impact) - AI Deploy (variant 35)
UPDATE product_content SET
  description = 'Deploy approved AI capabilities into your CRM platform with production-grade monitoring, safety controls, and a structured handover that gives your team full operational ownership.',
  positioning = 'AI in your CRM that works in production, with the governance and monitoring to keep it working reliably.',
  hero_summary = 'Deploy approved AI capabilities into your CRM platform with production-grade monitoring, safety controls, and a structured handover that gives your team full operational ownership.',
  overview_paragraphs = '["The CRM & Customer Relationship AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled CRM and relationship management workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for sales, marketing, service & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for crm solutions with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Staged deployment with safety validation at each production milestone","Monitoring dashboards and alert rules configured before handover","Operational runbook and team training included, not optional extras"]'::jsonb,
  why_it_matters = '{"hook":"Your CRM is the backbone of how you understand, serve, and retain customers.","problemParagraph":"Many AI initiatives for your CRM capability fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for crm solutions fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about the CRM AI deployment engagement.'
WHERE variant_id = 35;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'Production AI deployment', 'AI capabilities fully integrated into your CRM environment, validated against the agreed performance and safety acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'Monitoring and alerting configuration', 'Dashboards and alert rules covering model accuracy drift, bias indicators, data pipeline health, and business outcome metrics.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'AI operations runbook', 'Step-by-step procedures for monitoring, incident response, model refresh, and escalation, so your team can manage the AI capability without external dependency.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (35, 'Handover and training completion record', 'Confirmed training completion for each operational role, sign-off on acceptance criteria, and a 30-day post-handover support schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'What does the safety testing cover?', 'The DigitalQatalyst team tests for model accuracy degradation, demographic bias, data pipeline failures, and downstream CRM data corruption. All tests run against your agreed acceptance thresholds.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'Can AI capabilities be deployed to a staging environment first?', 'Yes. The deployment follows a staged approach: sandbox validation, then staging with production data samples, then controlled production rollout.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'What happens if model performance drops after go-live?', 'The monitoring configuration triggers alerts at agreed thresholds. The operations runbook covers the response procedure, and the DigitalQatalyst team provides post-launch support during the handover period.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (35, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm infrastructure requirements, deployment sequencing, and the production milestone schedule.', 3);

-- CRM Solutions (High-Impact) - Managed (variant 36)
UPDATE product_content SET
  description = 'Keep your CRM platform performing at the level your revenue operations depend on, with continuous monitoring, regular optimisation cycles, and a dedicated team accountable to your agreed service levels.',
  positioning = 'Your CRM platform, continuously maintained and improved, so your team focuses on customers, not system administration.',
  hero_summary = 'Keep your CRM platform performing at the level your revenue operations depend on, with continuous monitoring, regular optimisation cycles, and a dedicated team accountable to your agreed service levels.',
  overview_paragraphs = '["The CRM & Customer Relationship Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve CRM and relationship management with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for sales, marketing, service & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for crm solutions - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed operations with defined response times for incidents and change requests","Proactive optimisation, not just break-fix support","Quarterly roadmap reviews to keep the CRM aligned with your business direction"]'::jsonb,
  why_it_matters = '{"hook":"Your CRM is the backbone of how you understand, serve, and retain customers.","problemParagraph":"Many organisations struggle to sustain performance across your CRM capability after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"crm solutions issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the CRM managed service.'
WHERE variant_id = 36;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Monthly CRM performance report', 'Data quality scores, automation success rates, pipeline health metrics, and integration uptime, with commentary on trends and the next optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Optimisation change log', 'A record of every configuration change made, the business rationale, the test evidence, and the observed outcome, giving you a complete audit trail.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Release and update management record', 'Documentation of all platform updates applied, compatibility tests run, and any issues resolved before changes reached production.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (36, 'Quarterly roadmap review', 'A structured review of your CRM roadmap priorities, incorporating new business requirements, platform capability updates, and usage data from the previous quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'What does the SLA cover?', 'The SLA covers system availability monitoring, incident response for platform and integration failures, change management for configuration requests, and a monthly reporting cadence. Specific response and resolution targets are finalised during onboarding to reflect your operational requirements.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'Can we request new features or changes within the managed service?', 'Yes. A defined change request allowance is included each month. Larger scope changes are assessed and quoted separately so you remain in control of spend.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'How does the managed service interact with our internal IT team?', 'We operate as an extension of your team. Escalation paths, communication channels, and responsibility boundaries are agreed during onboarding and documented in the service agreement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (36, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current CRM environment, agrees the service baseline, and confirms the first reporting cycle.', 3);

-- Marketing Solutions (High-Impact) - Assess (variant 37)
UPDATE product_content SET
  description = 'Audit your marketing operations, campaign infrastructure, and attribution model to identify what is limiting performance, then leave with a prioritised plan your marketing leadership can act on.',
  positioning = 'Find out exactly why campaigns are underperforming before you invest in more technology or headcount.',
  hero_summary = 'Audit your marketing operations, campaign infrastructure, and attribution model to identify what is limiting performance, then leave with a prioritised plan your marketing leadership can act on.',
  overview_paragraphs = '["The Marketing Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps gaps and returns prioritised improvements your marketing and technology leaders can act on.","See how marketing operations and campaigns perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cmos, marketing ops & growth leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews marketing solutions across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment grounded in your actual campaign data and stack","Attribution and measurement review included as a core output","Completed within one week with no obligation to proceed further"]'::jsonb,
  why_it_matters = '{"hook":"Your marketing platforms determine how effectively you reach, engage, and convert audiences.","problemParagraph":"Many organisations run marketing stacks with siloed campaigns, weak attribution, and no clear view of automation or AI readiness. This assessment maps gaps and returns prioritised improvements your marketing and technology leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Siloed campaign execution","description":"Channels operate without shared audience data or coordinated journeys."},{"title":"Weak attribution","description":"Teams cannot connect spend, engagement, and conversion with confidence."},{"title":"Automation blind spots","description":"Personalisation and intelligence capabilities are discussed without a practical baseline."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Channel and journey priorities","description":"You know which capabilities and integrations to improve first."},{"title":"Ranked marketing backlog","description":"Gaps are ordered for design, platform, and budget decisions."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and investment planning."}]}}'::jsonb,
  faq_intro = 'Questions about the marketing operations assessment.'
WHERE variant_id = 37;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Marketing operations scorecard', 'Ratings across automation reliability, data quality, segmentation accuracy, and attribution credibility, each supported by specific evidence from your current campaigns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Attribution and measurement gap report', 'Identifies where your current measurement model is either over-crediting or under-crediting channels, and the specific changes needed to make investment decisions more accurate.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Audience and segmentation review', 'Assessment of how well your segments reflect buying behaviour, with concrete recommendations for better targeting that your platform can execute.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (37, 'Prioritised improvement roadmap', 'Sequenced actions covering quick wins and longer-term changes, with effort scores so your team can plan resourcing alongside business-as-usual activity.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'Which marketing platforms do you assess?', 'The DigitalQatalyst team works across HubSpot, Marketo, Salesforce Marketing Cloud, Klaviyo, and other leading platforms. We confirm scope during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'What data do you need from us?', 'Campaign performance reports, automation audit logs, and audience configuration exports. No personal customer data is required for the assessment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'Can this help us if we are about to re-platform?', 'Yes. A pre-migration assessment is one of the most valuable applications, as it identifies what is worth replicating and what should be redesigned before committing to a new platform.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (37, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the scope, data requirements, and stakeholder participants before the engagement begins.', 3);

-- Marketing Solutions (High-Impact) - Design (variant 38)
UPDATE product_content SET
  description = 'Design your marketing platform architecture, campaign structures, and audience models so your team can execute at scale with consistent measurement and predictable results.',
  positioning = 'A marketing blueprint built for how your organisation actually generates and converts demand.',
  hero_summary = 'Design your marketing platform architecture, campaign structures, and audience models so your team can execute at scale with consistent measurement and predictable results.',
  overview_paragraphs = '["The Marketing Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns marketing goals into campaign structures and build-ready specifications.","Turn marketing operations and campaigns goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cmos, marketing ops & growth leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate marketing solutions requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design validated with your marketing, sales, and analytics stakeholders","Attribution framework aligned to the decisions your leadership actually makes","Specifications your platform team can build from without additional discovery"]'::jsonb,
  why_it_matters = '{"hook":"Your marketing platforms determine how effectively you reach, engage, and convert audiences.","problemParagraph":"Many organisations buy marketing tools without journey design, audience models, or specifications teams can operationalise. This design engagement turns marketing goals into campaign structures and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined audience models","description":"Segmentation, triggers, and content rules are inconsistent across channels."},{"title":"Campaign design gaps","description":"Workflows for planning, approval, and publishing lack shared standards."},{"title":"Integration ambiguity","description":"Teams lack specs to connect CRM, analytics, and channel platforms."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned campaign designs","description":"Journeys and audiences are defined with clear orchestration logic."},{"title":"Consistent operating standards","description":"Governance, data, and workflow requirements are set upfront."},{"title":"Implementation-ready specs","description":"Teams receive artefacts that accelerate platform configuration and integration."}]}}'::jsonb,
  faq_intro = 'Questions about the marketing design engagement.'
WHERE variant_id = 38;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Campaign architecture blueprint', 'Structured campaign templates, channel strategy, trigger logic, and content cadence designs your marketing team can immediately begin building against.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Audience segmentation model', 'Defined segments, scoring criteria, lifecycle stages, and the personalisation rules that govern how each audience receives communications.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Measurement and attribution framework', 'A reporting structure aligned to your business objectives, covering the metrics, dashboards, and data sources that will give leadership credible campaign performance data.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (38, 'Integration and technology specification', 'Detailed connection specifications for your marketing platform, CRM, data warehouse, and any paid channel integrations, including sync frequency and data governance rules.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'Does the design cover content strategy or creative?', 'The design covers campaign structures, audience logic, and channel orchestration. Content strategy and creative direction are separate engagements; the DigitalQatalyst team can advise on scope.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'How do you handle multi-brand or multi-market complexity?', 'Brand and market segmentation is addressed in the architecture design. We have experience designing frameworks that accommodate multiple brands or regional variations within a single platform.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'Will the design work with our existing marketing technology?', 'Yes. The design starts from your current stack. Where platform limitations exist, the specifications will flag them with options rather than assuming a re-platform.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (38, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your existing documentation, confirms your platform landscape, and agrees the workshop participants before work begins.', 3);

-- Marketing Solutions (High-Impact) - AI Design (variant 39)
UPDATE product_content SET
  description = 'Validate which AI capabilities will genuinely improve marketing outcomes for your organisation, then produce responsible workflow designs and deployment specifications ready for build.',
  positioning = 'AI for marketing, validated against your data reality and scoped responsibly before a single line of code is written.',
  hero_summary = 'Validate which AI capabilities will genuinely improve marketing outcomes for your organisation, then produce responsible workflow designs and deployment specifications ready for build.',
  overview_paragraphs = '["The Marketing Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for marketing operations and campaigns, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cmos, marketing ops & growth leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for marketing solutions.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation before build commitment, not after","Privacy and consent controls designed in, not added as an afterthought","Data readiness report tells you exactly what data work is needed before build"]'::jsonb,
  why_it_matters = '{"hook":"Your marketing platforms determine how effectively you reach, engage, and convert audiences.","problemParagraph":"Many organisations apply AI to your marketing platforms without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for marketing solutions lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for marketing solutions are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the marketing AI design engagement.'
WHERE variant_id = 39;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'AI use-case prioritisation scorecard', 'Each candidate marketing AI use case rated by business value, data feasibility, risk, and implementation complexity, with a clear recommendation on what to build and when.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'Responsible AI workflow designs', 'Workflow diagrams showing model inputs, decision points, human review requirements, and the privacy and consent controls needed for compliance with your data obligations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'Data readiness report', 'Assessment of your marketing data against the requirements of each validated use case, including specific data quality actions needed before build can begin.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (39, 'Technical deployment specification', 'Model inputs, outputs, integration requirements, infrastructure needs, and the acceptance criteria your delivery team will use to validate production readiness.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'Which AI use cases are most commonly validated for marketing?', 'Predictive lead scoring, send-time optimisation, dynamic content personalisation, and budget allocation modelling are the most frequently scoped. The DigitalQatalyst team validates each against your specific data assets.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'What if our data is not ready for AI?', 'The data readiness report will tell you precisely what is missing. In many cases a targeted data improvement programme takes weeks rather than months. The DigitalQatalyst team will outline the options.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'Do we need to replace our existing marketing platform?', 'Usually not. The specifications are designed to integrate AI capabilities with your existing stack using available APIs or middleware. Re-platforming is only recommended when the current system creates an architectural barrier.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (39, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your marketing platform, data landscape, and AI ambitions to shape the engagement scope.', 3);

