  hero_summary = 'Build, integrate, test, and launch your marketing platform capabilities with structured quality assurance and a controlled handover so your team can execute campaigns from day one.',
  overview_paragraphs = '["The Marketing Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed marketing operations and campaigns changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
