WHERE variant_id = 40;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'Configured marketing platform', 'Fully built automation programmes, campaign templates, audience segments, and integrations, validated in a staging environment before production promotion.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'Integration test evidence pack', 'Test scenarios and results for every system integration, covering data sync accuracy, trigger reliability, and error handling behaviour.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'User acceptance test outcomes', 'Signed-off UAT results per campaign workflow and audience scenario, including accepted exceptions and the agreed launch decision.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (40, 'Marketing operations handover pack', 'Platform administration guide, campaign build procedures, escalation contacts, and a 30-day post-launch review schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'What if we need to migrate historical campaign data?', 'Data migration scope is defined and agreed upfront. The DigitalQatalyst team runs data mapping, transformation, and validation in a sandbox before any production migration.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'Can we run campaigns during the build period?', 'Yes, where the current platform remains available. The DigitalQatalyst team will advise on cutover sequencing to minimise disruption to active campaigns.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'How long does post-go-live support last?', 'The hypercare period and its terms are confirmed during scoping. After hypercare, the Managed service can provide ongoing operational support.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (40, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, resourcing, and a delivery timeline.', 3);

-- Marketing Solutions (High-Impact) - AI Deploy (variant 41)
UPDATE product_content SET
  description = 'Deploy validated AI capabilities into your marketing platform with production monitoring, privacy controls, and a team handover that gives your marketing operations function full ownership.',
  positioning = 'AI-powered marketing capabilities live in production, governed from the start, and run by your team.',
  hero_summary = 'Deploy validated AI capabilities into your marketing platform with production monitoring, privacy controls, and a team handover that gives your marketing operations function full ownership.',
  overview_paragraphs = '["The Marketing Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled marketing operations and campaigns workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cmos, marketing ops & growth leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for marketing solutions with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Privacy and consent controls validated in staging before any production deployment","Monitoring and alerting configured before handover, not after","Operational training included so your team runs the AI capability from day one"]'::jsonb,
  why_it_matters = '{"hook":"Your marketing platforms determine how effectively you reach, engage, and convert audiences.","problemParagraph":"Many AI initiatives for your marketing platforms fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for marketing solutions fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about the marketing AI deployment engagement.'
WHERE variant_id = 41;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'Production AI deployment', 'AI capabilities fully integrated into your marketing platform, validated against the agreed performance, accuracy, and safety acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'Privacy and consent validation report', 'Evidence that data handling, consent enforcement, and model inputs comply with your obligations, reviewed and signed off before production launch.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'Monitoring dashboard and alert configuration', 'Real-time visibility into model accuracy, data pipeline health, campaign impact metrics, and alert rules with defined response thresholds.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (41, 'AI operations runbook and training record', 'Step-by-step procedures for daily monitoring, incident response, model refresh, and escalation, with confirmed training completion for each operational role.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'How is personal data handled during model training and inference?', 'Data handling is governed by the specifications agreed in the AI Design phase. The DigitalQatalyst team validates compliance with those specifications before any model goes to production.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'What happens if a model starts producing poor results after launch?', 'The monitoring configuration triggers alerts when accuracy drops below agreed thresholds. The operations runbook covers the response procedure, including model rollback and the escalation path to the DigitalQatalyst team during the handover period.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'Can AI capabilities be deployed incrementally rather than all at once?', 'Yes. Staged deployment is the standard approach. Use cases go live in priority order so each is validated before the next is introduced.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (41, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm infrastructure requirements, compliance obligations, and the deployment milestone schedule.', 3);

-- Marketing Solutions (High-Impact) - Managed (variant 42)
UPDATE product_content SET
  description = 'Keep your marketing platform and campaigns operating at full capability, with monthly performance reporting, proactive optimisation, and a team accountable to your agreed service levels.',
  positioning = 'Your marketing operations, continuously maintained and improved, so campaigns keep delivering without platform bottlenecks.',
  hero_summary = 'Keep your marketing platform and campaigns operating at full capability, with monthly performance reporting, proactive optimisation, and a team accountable to your agreed service levels.',
  overview_paragraphs = '["The Marketing Operations Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve marketing operations and campaigns with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cmos, marketing ops & growth leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for marketing solutions - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed service with defined response targets for incidents and change requests","Proactive optimisation based on campaign data, not just reactive issue resolution","Quarterly performance reviews to align the platform roadmap with business priorities"]'::jsonb,
  why_it_matters = '{"hook":"Your marketing platforms determine how effectively you reach, engage, and convert audiences.","problemParagraph":"Many organisations struggle to sustain performance across your marketing platforms after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"marketing solutions issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the marketing managed service.'
WHERE variant_id = 42;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Monthly marketing operations report', 'Campaign performance KPIs, automation health metrics, data quality indicators, and integration uptime, with commentary on trends and the next optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Optimisation recommendations log', 'A record of every improvement implemented, the rationale behind it, the test evidence used, and the observed outcome, giving your team a full audit trail.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Platform release and update record', 'Documentation of all platform updates applied, compatibility tests completed, and any issues resolved before changes were promoted to production.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (42, 'Quarterly campaign performance review', 'A structured review of campaign results, audience performance, attribution accuracy, and the priorities for the next quarter, informed by data rather than assumption.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'Does the managed service include campaign strategy or creative?', 'The managed service covers platform operations and performance reporting. Campaign strategy and creative production are separate; the DigitalQatalyst team can discuss how these services can be combined.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'Can we request new automations or campaign templates within the service?', 'Yes. A defined change request allowance is included each month. Larger build requests are assessed and quoted separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'How do you report against our marketing KPIs?', 'Each month you receive a performance dashboard connected to your analytics stack and presenting the KPIs that matter to your leadership. Every quarter the DigitalQatalyst team runs a business review to interpret trends and agree priorities for the next period. KPI alignment is confirmed during onboarding so the first report reflects what you actually measure.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (42, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current platform, agrees the service baseline, and confirms the first reporting cycle.', 3);

-- Smart Sales & Quotation (High-Impact) - Assess (variant 43)
UPDATE product_content SET
  description = 'Audit your sales process and quotation workflows to identify where deals are slowing down, where pricing decisions are inconsistent, and where manual effort is creating conversion risk.',
  positioning = 'Find the bottlenecks costing you deals and margin before committing to platform or process change.',
  hero_summary = 'Audit your sales process and quotation workflows to identify where deals are slowing down, where pricing decisions are inconsistent, and where manual effort is creating conversion risk.',
  overview_paragraphs = '["The Smart Sales & Quotation Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps process and platform gaps and returns prioritised improvements your commercial leaders can act on.","See how sales and quotation perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for sales, commercial & revenue ops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews smart sales & quotation across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope, no-obligation assessment grounded in your actual transaction and quotation data","Pricing consistency analysis included as a core output","Completed within one week with stakeholder-ready findings"]'::jsonb,
  why_it_matters = '{"hook":"Your sales and quotation processes directly shape revenue velocity and customer confidence.","problemParagraph":"Many organisations run sales and quoting with manual steps, inconsistent pricing logic, and limited visibility into pipeline quality. This assessment maps process and platform gaps and returns prioritised improvements your commercial leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Manual quoting friction","description":"Teams rebuild quotes from spreadsheets instead of governed product and pricing rules."},{"title":"Inconsistent sales process","description":"Stages, approvals, and handoffs vary by team without shared standards."},{"title":"Weak pipeline insight","description":"Forecasting relies on incomplete data and subjective updates."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Process and platform priorities","description":"You know which quoting and sales capabilities to fix first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, CRM integration, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and revenue operations funding."}]}}'::jsonb,
  faq_intro = 'Questions about the sales and quotation assessment.'
WHERE variant_id = 43;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Sales and quotation process scorecard', 'Ratings across process adherence, quotation accuracy, approval cycle times, and pricing consistency, each supported by evidence from your actual transaction data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Bottleneck and root-cause register', 'Every identified delay or error linked to its impact on quote turnaround time, conversion rate, or margin, so improvement priorities are grounded in commercial evidence.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Pricing consistency analysis', 'Assessment of where pricing rules are being applied inconsistently across products, customer types, or sales team members, with specific recommendations for control improvements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (43, 'Prioritised improvement roadmap', 'Sequenced actions covering process, platform, and governance improvements, with effort scores so your commercial leadership can plan the next phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'What sales and CPQ platforms do you assess?', 'The DigitalQatalyst team works across Salesforce CPQ, HubSpot, SAP CPQ, and bespoke quotation systems. Platform scope is confirmed during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'What data do you need from us?', 'Quotation logs, approval cycle time data, win and loss records, and any existing process documentation. No personal customer data is required.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'Is this relevant if we use a manual or spreadsheet-based quotation process?', 'Yes. Manual processes are often where the most significant improvement opportunities exist. The assessment will identify which improvements require a platform and which are process or governance changes alone.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (43, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm data requirements, stakeholder participants, and the assessment scope.', 3);

-- Smart Sales & Quotation (High-Impact) - Design (variant 44)
UPDATE product_content SET
  description = 'Design the sales workflows, quotation logic, and pricing rules your team needs to produce accurate, approved quotes faster, with the integration and adoption plan to make it work in practice.',
  positioning = 'A quotation system design that gives your sales team speed and your commercial leadership confidence in every price sent.',
  hero_summary = 'Design the sales workflows, quotation logic, and pricing rules your team needs to produce accurate, approved quotes faster, with the integration and adoption plan to make it work in practice.',
  overview_paragraphs = '["The Smart Sales & Quotation Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines sales journeys and build-ready specifications.","Turn sales and quotation goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for sales, commercial & revenue ops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate smart sales & quotation requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Pricing logic and approval workflow designed to your commercial governance requirements","Integration specifications covering CRM, ERP, and contract systems","Adoption plan validated with your sales team before the specification is finalised"]'::jsonb,
  why_it_matters = '{"hook":"Your sales and quotation processes directly shape revenue velocity and customer confidence.","problemParagraph":"Many organisations digitise sales without designed quoting workflows, pricing governance, or specifications CRM and ERP teams can implement. This design engagement defines sales journeys and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined quote-to-cash flows","description":"Pricing, approval, and contract paths are not designed end to end."},{"title":"Governance gaps","description":"Discount rules, product bundles, and approvals lack clear controls."},{"title":"Build ambiguity","description":"Platform teams lack specs for CRM, ERP, and document integration."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Designed sales workflows","description":"Quoting and pipeline stages reflect how commercial teams actually sell."},{"title":"Pricing and approval standards","description":"Rules and controls are defined for governance and auditability."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts that accelerate CRM and ERP alignment."}]}}'::jsonb,
  faq_intro = 'Questions about the sales and quotation design engagement.'
WHERE variant_id = 44;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Sales journey and workflow designs', 'End-to-end sales process flows from lead to signed quote, covering role responsibilities, decision points, and the data required at each stage.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Quotation and pricing logic specification', 'Detailed rules for product configuration, pricing calculations, discount authorisation, and the conditions under which quotes require approval or escalation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Approval workflow and governance design', 'Defined approval tiers, delegation rules, exception handling, and the audit trail requirements needed for commercial governance and compliance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (44, 'Integration and system architecture specification', 'Data flow diagrams and API or middleware specifications connecting your CPQ platform to CRM, ERP, and downstream contract management systems.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'Can the design accommodate multiple pricing models or product families?', 'Yes. The quotation logic specification is built around your actual product and pricing complexity. Multi-tier pricing, bundles, and regional variations are all addressed during the design phase.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'How do you handle commercial sensitivity during workshops?', 'Pricing data and commercial rules are treated as confidential. The DigitalQatalyst team operates under NDAs and data handling agreements before any commercial information is shared.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'Does the design tell us which CPQ platform to use?', 'If you have not yet selected a platform, the design includes vendor assessment and a recommendation based on your requirements. If a platform is already chosen, the design works within that constraint.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (44, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your current quotation process and confirms the stakeholders needed for design workshops.', 3);

-- Smart Sales & Quotation (High-Impact) - AI Design (variant 45)
UPDATE product_content SET
  description = 'Validate which AI capabilities can meaningfully accelerate your quotation process and improve pricing decisions, then produce responsible workflow designs and deployment specifications ready for build.',
  positioning = 'AI for sales and quotation, scoped to the use cases your data supports and specified for responsible deployment.',
  hero_summary = 'Validate which AI capabilities can meaningfully accelerate your quotation process and improve pricing decisions, then produce responsible workflow designs and deployment specifications ready for build.',
  overview_paragraphs = '["The Smart Sales & Quotation AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for sales and quotation, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for sales, commercial & revenue ops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for smart sales & quotation.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["AI recommendations validated against your actual transaction and product data before build","Pricing authority boundaries and override logic built into every workflow design","Specifications compatible with your existing CPQ and CRM architecture"]'::jsonb,
  why_it_matters = '{"hook":"Your sales and quotation processes directly shape revenue velocity and customer confidence.","problemParagraph":"Many organisations apply AI to your sales and quoting processes without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for smart sales & quotation lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for smart sales & quotation are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the sales and quotation AI design engagement.'
WHERE variant_id = 45;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'AI use-case scorecard for sales and quotation', 'Each candidate use case rated by commercial value, data feasibility, implementation risk, and governance complexity, with a clear build recommendation and sequencing.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'Responsible AI workflow designs', 'Workflow diagrams showing AI-suggested pricing recommendations, human authority boundaries, override logic, and the audit trail requirements for commercial compliance.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'Data readiness assessment', 'Evaluation of your transaction history, product data, and win-loss records against the data requirements of each validated AI use case, with specific data improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (45, 'Technical deployment specification', 'Model input and output specifications, CPQ and CRM integration requirements, infrastructure needs, and the acceptance criteria for production validation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'Can AI actually improve pricing decisions in a complex product environment?', 'AI-assisted pricing works best where there is sufficient historical transaction data with outcome labels. The use-case scoring phase determines whether your data supports this. Simpler applications, such as configuration assistance or win-probability scoring, often have lower data requirements.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'How do you ensure AI pricing recommendations do not override commercial authority?', 'The workflow designs define explicit human authority boundaries. AI produces recommendations; approval and override controls remain with authorised roles. This is a core design requirement, not an option.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'Do we need a CPQ platform in place before this engagement?', 'Not necessarily. The AI design can be completed in parallel with CPQ selection, with specifications written to accommodate the chosen platform. The DigitalQatalyst team will advise on the optimal sequencing.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (45, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will review your current sales and pricing data landscape and shape the engagement scope accordingly.', 3);

-- Smart Sales & Quotation (High-Impact) - Deploy (variant 46)
UPDATE product_content SET
  description = 'Configure, integrate, test, and launch your CPQ and sales quotation platform with structured quality assurance and a handover that leaves your sales team fully equipped to operate independently.',
  positioning = 'Your CPQ platform live and tested, with your sales team confident in it before the first real quote goes out.',
  hero_summary = 'Configure, integrate, test, and launch your CPQ and sales quotation platform with structured quality assurance and a handover that leaves your sales team fully equipped to operate independently.',
  overview_paragraphs = '["The Smart Sales & Quotation Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed sales and quotation changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for sales, commercial & revenue ops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated smart sales & quotation assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pricing accuracy validation as a dedicated QA step, not part of general testing","Sales team training and readiness assessment before go-live","Go-live playbook and rollback plan included as standard"]'::jsonb,
  why_it_matters = '{"hook":"Your sales and quotation processes directly shape revenue velocity and customer confidence.","problemParagraph":"Many organisations stall between approved designs and production for your sales and quoting processes, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for smart sales & quotation sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the CPQ and sales quotation deployment engagement.'
WHERE variant_id = 46;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Configured CPQ environment', 'Fully built CPQ platform covering approved pricing rules, product configurations, approval workflows, and role permissions, validated in a staging environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Integration test evidence', 'Test scenarios and results for every system integration, covering data synchronisation accuracy, trigger reliability, and error handling across CRM, ERP, and contract management connections.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Quotation accuracy validation report', 'Test evidence confirming that CPQ outputs match expected pricing outcomes across representative product configurations, discounting scenarios, and approval conditions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (46, 'Sales operations handover pack', 'Administrator guides, pricing rule update procedures, escalation contacts, and a post-launch support schedule so your team owns the platform from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'How is pricing rule accuracy validated?', 'The DigitalQatalyst team builds a test matrix of representative product configurations, discount scenarios, and approval conditions, then validates CPQ outputs against your expected pricing outcomes before any user acceptance testing begins.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'What if we need to migrate existing quotes or contracts?', 'Migration scope is defined and agreed upfront. Historical data migration is mapped, transformed, and validated in a sandbox environment before production cutover.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'Can we continue taking manual quotes during the build period?', 'Yes. The DigitalQatalyst team designs the cutover approach to minimise disruption to active commercial activity, including parallel-running options where needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (46, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, the CPQ platform configuration approach, and a delivery timeline.', 3);

-- Smart Sales & Quotation (High-Impact) - AI Deploy (variant 47)
UPDATE product_content SET
  description = 'Deploy validated AI capabilities into your CPQ and sales platform with production monitoring, commercial authority controls, and a structured handover that gives your sales operations team full ownership.',
  positioning = 'AI-assisted pricing and sales recommendations in production, governed correctly from the first quote.',
  hero_summary = 'Deploy validated AI capabilities into your CPQ and sales platform with production monitoring, commercial authority controls, and a structured handover that gives your sales operations team full ownership.',
  overview_paragraphs = '["The Smart Sales & Quotation AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled sales and quotation workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for sales, commercial & revenue ops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for smart sales & quotation with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Commercial authority and override controls validated before any model goes live in production","Monitoring dashboard aligned to pricing accuracy and commercial impact metrics","Operational runbook and training included so your team operates the AI independently"]'::jsonb,
  why_it_matters = '{"hook":"Your sales and quotation processes directly shape revenue velocity and customer confidence.","problemParagraph":"Many AI initiatives for your sales and quoting processes fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for smart sales & quotation fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about the CPQ and sales AI deployment engagement.'
WHERE variant_id = 47;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'Production AI deployment for CPQ', 'AI capabilities fully integrated into your CPQ and CRM environment, validated against pricing accuracy, recommendation quality, and commercial authority acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'Commercial authority control validation report', 'Evidence that override controls, approval boundaries, and escalation paths operate correctly across representative pricing scenarios before production launch.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'AI performance monitoring dashboard', 'Real-time visibility into recommendation acceptance rates, pricing accuracy trends, model confidence scores, and the business impact metrics agreed during design.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (47, 'AI operations runbook and training record', 'Procedures for daily monitoring, model performance review, incident response, and model refresh, with confirmed training completion for sales operations and commercial roles.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'How is the commercial authority boundary enforced technically?', 'Override controls are implemented at the CPQ integration layer. AI recommendations are presented as suggestions; the CPQ workflow requires authorised human approval before any non-standard pricing is accepted. The DigitalQatalyst team validates this in staging before production deployment.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'What if the AI recommendations are wrong more often than expected?', 'The monitoring dashboard surfaces acceptance rates and accuracy metrics in near-real time. If performance falls below agreed thresholds, the operations runbook covers the investigation and response procedure, including model rollback.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'Can AI recommendations be limited to specific product lines or deal sizes initially?', 'Yes. Staged rollout by product category or deal value threshold is the standard approach, allowing the team to build confidence before broader deployment.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (47, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm CPQ integration requirements and the production deployment schedule.', 3);

-- Smart Sales & Quotation (High-Impact) - Managed (variant 48)
UPDATE product_content SET
  description = 'Keep your CPQ platform and quotation operations running at full commercial accuracy, with monthly health checks, pricing rule maintenance, and a team accountable to your agreed service levels.',
  positioning = 'Your quotation platform continuously maintained so pricing stays accurate and sales teams can generate quotes without delay.',
  hero_summary = 'Keep your CPQ platform and quotation operations running at full commercial accuracy, with monthly health checks, pricing rule maintenance, and a team accountable to your agreed service levels.',
  overview_paragraphs = '["The Smart Sales & Quotation Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve sales and quotation with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for sales, commercial & revenue ops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for smart sales & quotation - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Pricing rule maintenance included, not charged as a separate request","Monthly reports covering quote cycle times and commercial exception rates","Quarterly reviews to align the CPQ roadmap with your commercial strategy"]'::jsonb,
  why_it_matters = '{"hook":"Your sales and quotation processes directly shape revenue velocity and customer confidence.","problemParagraph":"Many organisations struggle to sustain performance across your sales and quoting processes after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"smart sales & quotation issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the CPQ and sales quotation managed service.'
WHERE variant_id = 48;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Monthly CPQ operations report', 'Quote volume, approval cycle times, pricing exception rates, integration uptime, and a commentary on trends and next-period maintenance priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Pricing rule and catalogue update log', 'A record of every pricing rule or product catalogue change made, the commercial rationale, the test evidence, and the observed outcome in production.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Platform release and test record', 'Documentation of all CPQ platform updates applied, pricing accuracy tests run, and any issues resolved before changes were promoted to the live environment.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (48, 'Quarterly commercial alignment review', 'A structured review of CPQ performance against commercial objectives, incorporating new product requirements, pricing model changes, and usage data from the previous quarter.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'What happens when we add new products or change pricing?', 'Pricing rule and product catalogue updates are included within the managed service. The DigitalQatalyst team tests changes in a staging environment and validates pricing accuracy before promoting to production.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'Can the managed service cover integration maintenance if a connected system changes?', 'Yes. Integration maintenance for connected CRM, ERP, and contract systems is included within the service scope. Major re-integrations caused by third-party platform changes are assessed and agreed separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'How do you handle urgent pricing changes that need to go live quickly?', 'Priority change procedures with defined response times are included in the service agreement. The DigitalQatalyst team confirms the specific turnaround commitments during onboarding.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'How is our commercial and customer data kept secure?', 'Your data is processed within the cloud region agreed at contract signature. Access to your CPQ environment is role-controlled and limited to the DigitalQatalyst team members assigned to your account. On contract end, data is deleted or returned in full per the terms agreed in your service agreement.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (48, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your CPQ environment, agrees the service baseline and pricing rule audit, and confirms the first reporting cycle.', 4);

-- Customer Support & Success (High-Impact) - Assess (variant 49)
UPDATE product_content SET
  description = 'Audit your customer support and success operations to identify where resolution times are lagging, where customer effort is highest, and where your current tooling is creating agent and customer friction.',
  positioning = 'Understand exactly where your support operation is losing customers and agent productivity before investing in change.',
  hero_summary = 'Audit your customer support and success operations to identify where resolution times are lagging, where customer effort is highest, and where your current tooling is creating agent and customer friction.',
  overview_paragraphs = '["The Customer Support & Success Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps support maturity and returns prioritised improvements your CX and operations leaders can act on.","See how customer support and success perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for customer service, success & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews customer support & success across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment grounded in your actual case data and agent feedback","Customer effort and agent productivity analysis included as core outputs","Completed within one week with no obligation to proceed further"]'::jsonb,
  why_it_matters = '{"hook":"Customer support is where brand promises are kept, or broken, at scale.","problemParagraph":"Many organisations run support operations with fragmented channels, inconsistent service levels, and limited insight into automation opportunities. This assessment maps support maturity and returns prioritised improvements your CX and operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented support channels","description":"Customers repeat information across chat, email, phone, and self-service."},{"title":"Inconsistent service levels","description":"Response targets, escalation paths, and knowledge bases vary by team."},{"title":"Limited automation view","description":"Deflection, routing, and assistant use cases lack a practical readiness baseline."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Support journey priorities","description":"You know which channels, processes, and tools to improve first."},{"title":"Ranked service backlog","description":"Gaps are ordered for design, platform, and staffing investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and service transformation funding."}]}}'::jsonb,
  faq_intro = 'Questions about the customer support and success operations assessment.'
WHERE variant_id = 49;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Support operations scorecard', 'Ratings across resolution speed, first-contact resolution, customer effort, agent productivity, and escalation control, each supported by evidence from your actual case data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Customer effort and friction map', 'A channel-by-channel assessment of where customers are experiencing unnecessary effort, with specific process and tooling recommendations to reduce abandonment and escalation.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Agent productivity gap report', 'Identifies the specific tooling limitations, knowledge gaps, and process inconsistencies adding handle time and reducing agent capacity to resolve cases at first contact.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (49, 'Prioritised improvement roadmap', 'Sequenced actions ranked by impact on customer experience and operational efficiency, with effort scores so your CX and operations leadership can plan the next phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'Which support platforms do you assess?', 'The DigitalQatalyst team works across Zendesk, Salesforce Service Cloud, ServiceNow, Freshdesk, and other platforms. Scope is confirmed during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'Do you interview frontline agents as well as managers?', 'Yes. Agent interviews are a core part of the assessment because they surface friction points that management reporting often does not capture. We keep sessions focused and respect agent time.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'Can this assessment cover digital self-service as well as live support?', 'Yes. The assessment covers all channels in scope, including knowledge bases, chatbots, and IVR, alongside live agent channels.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (49, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm data requirements, channel scope, and stakeholder participants before the engagement begins.', 3);

-- Customer Support & Success (High-Impact) - Design (variant 50)
UPDATE product_content SET
  description = 'Design the support workflows, knowledge architecture, and channel strategy your team needs to resolve cases faster, reduce escalations, and deliver a consistent customer experience at scale.',
  positioning = 'A support operations design that gives your agents the right information at the right moment and your customers a resolution without unnecessary effort.',
  hero_summary = 'Design the support workflows, knowledge architecture, and channel strategy your team needs to resolve cases faster, reduce escalations, and deliver a consistent customer experience at scale.',
  overview_paragraphs = '["The Customer Support & Success Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines support experiences and build-ready specifications.","Turn customer support and success goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for customer service, success & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate customer support & success requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Knowledge architecture designed for both agent use and customer self-service","Routing logic tailored to your SLA tiers and customer segment requirements","Agent workspace design validated with frontline input, not just management"]'::jsonb,
  why_it_matters = '{"hook":"Customer support is where brand promises are kept, or broken, at scale.","problemParagraph":"Many organisations upgrade support tools without designed service journeys, knowledge models, or specifications operations teams can run. This design engagement defines support experiences and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined service journeys","description":"Intake, resolution, and escalation paths are unclear across channels."},{"title":"Knowledge fragmentation","description":"Articles, macros, and training content are inconsistent or out of date."},{"title":"Operational ambiguity","description":"Teams lack specs for routing, integrations, and SLA reporting."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned support designs","description":"Journeys reflect how customers seek help and how agents resolve issues."},{"title":"Consistent knowledge standards","description":"Content, taxonomy, and governance rules are defined upfront."},{"title":"Implementation-ready specs","description":"Operations teams receive artefacts they can configure and train against."}]}}'::jsonb,
  faq_intro = 'Questions about the customer support and success design engagement.'
WHERE variant_id = 50;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Customer support journey maps', 'End-to-end journey designs for each support channel, covering contact entry points, resolution paths, escalation triggers, and handoff specifications between teams and systems.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Knowledge management architecture', 'Structure, taxonomy, ownership model, and maintenance procedures for your support knowledge base, designed to serve both agent-assisted and customer self-service channels.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Case routing and prioritisation logic', 'Rule definitions for case assignment, priority scoring, SLA clock management, and re-routing criteria, with the data fields required to power each rule.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (50, 'Agent workspace and adoption plan', 'Agent desktop layout specifications, knowledge access workflow designs, and an adoption plan covering training outlines, change communication milestones, and go-live criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'Does the design cover chatbot or AI-powered self-service?', 'The journey and channel design includes self-service touchpoints. Detailed AI self-service design is addressed in the AI Design engagement, which can run in sequence or in parallel.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'How do you handle multi-tier or multi-region support complexity?', 'Tiered support structures and regional variations are addressed in the routing logic and escalation design. The DigitalQatalyst team has experience designing frameworks that scale across multiple support levels and geographies.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'Will the design work within our existing support platform?', 'Yes. The design starts from your current platform. Where platform limitations exist, the specifications will flag them with options rather than assuming a platform change.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (50, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your current support operation and confirms the stakeholders needed for design workshops.', 3);

-- Customer Support & Success (High-Impact) - AI Design (variant 51)
UPDATE product_content SET
  description = 'Validate which AI capabilities can genuinely improve resolution speed and customer effort in your support operation, then produce responsible workflow designs and deployment specifications ready for build.',
  positioning = 'AI for customer support, scoped to use cases your data and platform support, with guardrails that protect customers and agents.',
  hero_summary = 'Validate which AI capabilities can genuinely improve resolution speed and customer effort in your support operation, then produce responsible workflow designs and deployment specifications ready for build.',
  overview_paragraphs = '["The Customer Support & Success AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for customer support and success, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for customer service, success & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for customer support & success.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation grounded in your actual case and knowledge data before any build commitment","Customer-facing transparency requirements designed into every AI workflow","Escalation paths to human agents built into every automated interaction design"]'::jsonb,
  why_it_matters = '{"hook":"Customer support is where brand promises are kept, or broken, at scale.","problemParagraph":"Many organisations apply AI to your customer support operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for customer support & success lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for customer support & success are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the customer support AI design engagement.'
WHERE variant_id = 51;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'AI use-case scorecard for support', 'Each candidate AI use case rated by impact on resolution time, customer effort, agent productivity, and implementation feasibility, with a clear recommendation on what to build first.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'Responsible AI workflow designs', 'Workflow diagrams showing AI decision points, human escalation triggers, transparency requirements for customer-facing AI, and the bias controls needed for equitable service.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'Data readiness report', 'Assessment of your case history, knowledge base quality, and customer data against the requirements of each validated AI use case, with specific data preparation actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (51, 'Technical deployment specification', 'Model inputs, outputs, platform integration requirements, infrastructure needs, and the acceptance criteria for validating AI performance before production deployment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'Which AI use cases are most commonly validated for support operations?', 'Intelligent case triage and routing, agent next-best-action suggestions, knowledge article recommendation, and automated tier-one resolution are the most frequently scoped. The DigitalQatalyst team validates each against your specific case data and platform capabilities.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'How do you ensure AI does not make customer interactions feel impersonal?', 'Transparency and escalation requirements are designed into every customer-facing AI workflow. Customers are told when they are interacting with an automated system and can reach a human agent at any point. This is a core design requirement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'What data quality does our knowledge base need to support AI?', 'The data readiness assessment evaluates knowledge base completeness, consistency, and freshness against the requirements of each use case. Many organisations find targeted knowledge improvement is needed before AI can reliably recommend articles.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (51, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your support platform, case data, and AI ambitions to shape the engagement scope.', 3);

-- Customer Support & Success (High-Impact) - Deploy (variant 52)
UPDATE product_content SET
  description = 'Configure, integrate, test, and launch your customer support platform improvements with structured quality assurance and a controlled handover that leaves your agents and service leaders fully operational.',
  positioning = 'Support capabilities delivered and tested before your team takes a single live case through the new system.',
  hero_summary = 'Configure, integrate, test, and launch your customer support platform improvements with structured quality assurance and a controlled handover that leaves your agents and service leaders fully operational.',
  overview_paragraphs = '["The Customer Support & Success Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed customer support and success changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for customer service, success & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated customer support & success assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Agent user acceptance testing with your frontline team before any live cases are handled","Knowledge base built and validated as part of the deployment, not treated as a separate work stream","Post-launch hypercare period to resolve early operational issues quickly"]'::jsonb,
  why_it_matters = '{"hook":"Customer support is where brand promises are kept, or broken, at scale.","problemParagraph":"Many organisations stall between approved designs and production for your customer support operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for customer support & success sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the customer support platform deployment engagement.'
WHERE variant_id = 52;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Configured support platform', 'Fully built case management environment covering routing rules, queue configurations, SLA timers, permission sets, and knowledge base integration, validated in a staging environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Integration test evidence pack', 'Test scenarios and results for every system integration, covering case sync accuracy, CRM data exchange, and error handling across connected platforms.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Agent UAT outcomes report', 'Signed-off user acceptance test results per support scenario and channel, including accepted exceptions and the agreed go-live decision from service leadership.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (52, 'Support operations handover pack', 'Administrator guides, routing rule update procedures, escalation contacts, and a 30-day post-launch review schedule so your team owns the platform from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'How is the knowledge base built and validated?', 'The DigitalQatalyst team works with your subject matter experts to structure, author or migrate, and then quality-check knowledge articles before publication. Agents validate accuracy during user acceptance testing.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'Can we continue handling cases on the existing system during the build?', 'Yes. The cutover approach is designed to minimise disruption to live case volumes. Parallel-running options and off-peak cutover windows are considered during planning.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'What happens to open cases at the point of cutover?', 'Open case migration is planned, mapped, and tested before cutover. The DigitalQatalyst team produces a cutover playbook covering data migration steps, rollback triggers, and the communication plan for agents and customers.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (52, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, platform configuration approach, and a delivery timeline.', 3);

-- Customer Support & Success (High-Impact) - AI Deploy (variant 53)
UPDATE product_content SET
  description = 'Deploy validated AI capabilities into your customer support platform with production monitoring, human escalation controls, and a structured handover so your service operations team can manage the capability independently.',
  positioning = 'AI-assisted support in production, with the guardrails and monitoring your team needs to operate it confidently.',
  hero_summary = 'Deploy validated AI capabilities into your customer support platform with production monitoring, human escalation controls, and a structured handover so your service operations team can manage the capability independently.',
  overview_paragraphs = '["The Customer Support & Success AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled customer support and success workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for customer service, success & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for customer support & success with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Human escalation controls validated before any AI capability goes live with real customers","Agent training included so your frontline team understands how AI is supporting their work","Monitoring dashboard aligned to resolution outcomes and customer satisfaction, not just model metrics"]'::jsonb,
  why_it_matters = '{"hook":"Customer support is where brand promises are kept, or broken, at scale.","problemParagraph":"Many AI initiatives for your customer support operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for customer support & success fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about the customer support AI deployment engagement.'
WHERE variant_id = 53;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'Production AI deployment for support', 'AI capabilities fully integrated into your support platform, validated against resolution accuracy, escalation behaviour, and the accepted performance criteria before production sign-off.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'Human escalation control validation report', 'Evidence that escalation to live agents triggers correctly across representative contact scenarios, including edge cases where AI confidence is low or customer sentiment indicates distress.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'AI performance monitoring dashboard', 'Real-time visibility into AI resolution rates, escalation volumes, customer satisfaction indicators, and model accuracy metrics, with alert rules at agreed performance thresholds.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (53, 'Service team training record and AI operations runbook', 'Confirmed training completion for agents, team leads, and platform administrators, plus step-by-step procedures for monitoring, incident response, and model refresh.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'How do you test that customers can always reach a human agent?', 'The DigitalQatalyst team runs escalation scenario tests covering low-confidence AI responses, repeated failed resolution attempts, high-sentiment distress signals, and explicit customer requests for a human. All must trigger the correct handoff before production deployment proceeds.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'How will agents know when AI has already interacted with a customer?', 'AI interaction context is surfaced in the agent workspace as part of the deployment configuration. Agents see the contact history, what the AI attempted, and why the escalation was triggered, so they do not ask customers to repeat themselves.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'What happens if the AI starts producing inaccurate resolutions?', 'The monitoring configuration triggers alerts when resolution accuracy drops below agreed thresholds. The operations runbook covers the investigation and response procedure, including model rollback and the escalation path to the DigitalQatalyst team during the handover period.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (53, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm platform integration requirements and the production deployment schedule.', 3);

-- Customer Support & Success (High-Impact) - Managed (variant 54)
UPDATE product_content SET
  description = 'Keep your customer support and success platform running at the service levels your customers and agents depend on, with continuous monitoring, proactive optimisation, and regular performance reporting.',
  positioning = 'Your support operation continuously maintained and improved, so your team focuses on customers, not platform issues.',
  hero_summary = 'Keep your customer support and success platform running at the service levels your customers and agents depend on, with continuous monitoring, proactive optimisation, and regular performance reporting.',
  overview_paragraphs = '["The Customer Support & Success Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve customer support and success with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for customer service, success & cx leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for customer support & success - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Knowledge base maintenance included as an ongoing service deliverable","Monthly reports aligned to your SLA tiers and customer satisfaction targets","Quarterly service reviews to keep the platform roadmap aligned with your business"]'::jsonb,
  why_it_matters = '{"hook":"Customer support is where brand promises are kept, or broken, at scale.","problemParagraph":"Many organisations struggle to sustain performance across your customer support operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"customer support & success issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the customer support managed service.'
WHERE variant_id = 54;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Monthly support operations report', 'Resolution rates, SLA compliance by tier, first-contact resolution trends, customer satisfaction scores, and commentary on the next period optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Knowledge base maintenance log', 'A record of every knowledge article created, updated, or retired, the accuracy validation method used, and the agent or self-service usage data that informed each change.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Platform change and update record', 'Documentation of all platform updates applied, regression tests completed, and any issues resolved before changes reached the production environment.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (54, 'Quarterly service review', 'A structured assessment of support performance against your agreed KPIs, incorporating business volume changes, new product requirements, and emerging customer contact drivers.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'What does the managed service cover for knowledge maintenance?', 'The DigitalQatalyst team reviews knowledge article accuracy monthly, updates content based on case trend analysis and agent feedback, and archives or retires articles that no longer reflect current products or processes.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'Can we request new routing rules or queue changes within the service?', 'Yes. A defined change request allowance is included each month. Larger structural changes are assessed and agreed separately so you remain in control of scope and spend.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'How do you track and report customer satisfaction?', 'The DigitalQatalyst team integrates with your existing CSAT or NPS tooling. Where no measurement is in place, we can recommend a lightweight approach to capture and report customer feedback within the managed service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (54, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current support environment, agrees the service baseline and SLA framework, and confirms the first reporting cycle.', 3);

-- Digital Workplace (High-Impact) - Assess (variant 55)
UPDATE product_content SET
  description = 'A focused assessment of your collaboration tools, intranet, and employee-facing platforms that surfaces the gaps stopping people from finding information, communicating, and getting work done. You leave with a maturity rating and a prioritised improvement roadmap.',
  positioning = 'Understand where your digital workplace is losing productivity, then fix the highest-impact gaps first.',
  hero_summary = 'A focused assessment of your collaboration tools, intranet, and employee-facing platforms that surfaces the gaps stopping people from finding information, communicating, and getting work done. You leave with a maturity rating and a prioritised improvement roadmap.',
  overview_paragraphs = '["The Digital Workplace Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps digital workplace maturity and returns prioritised improvements your operations and IT leaders can act on.","See how digital workplace and collaboration perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for hr, it & internal comms leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews digital workplace across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed scope covering your collaboration tools, intranet, and adoption posture -- confirmed with you before day one so there are no surprises","Covers both technical configuration and human adoption factors","Findings playback with the DigitalQatalyst team included"]'::jsonb,
  why_it_matters = '{"hook":"Your digital workplace is how teams collaborate, decide, and deliver every day.","problemParagraph":"Many organisations adopt workplace tools without aligned collaboration models, adoption metrics, or a clear view of productivity gaps. This assessment maps digital workplace maturity and returns prioritised improvements your operations and IT leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Tool sprawl","description":"Collaboration happens across disconnected apps with no shared workflow model."},{"title":"Uneven adoption","description":"Teams use platforms differently, reducing productivity gains."},{"title":"Unclear productivity signals","description":"Leaders lack evidence on where friction costs time and decision quality."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Workplace priority map","description":"You know which tools, workflows, and integrations to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, change management, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and workplace funding."}]}}'::jsonb,
  faq_intro = 'Common questions about the Digital Workplace assessment.'
WHERE variant_id = 55;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Digital Workplace Maturity Assessment', 'Scored evaluation across collaboration, communication, knowledge management, and adoption dimensions with evidence from interviews and usage data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Gap and Friction Register', 'Documented pain points tied to specific tools and workflows, ranked by frequency and business impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Prioritised Improvement Roadmap', 'Sequenced recommendations with effort estimates, dependencies, and ownership suggestions your IT and HR teams can execute against.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (55, 'Executive Summary', 'A concise read for senior stakeholders covering maturity position, top risks, and recommended first investments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'Which platforms does the assessment cover?', 'Microsoft 365, Teams, SharePoint, and connected productivity tools are the primary focus. The DigitalQatalyst team confirms scope during the initial briefing.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'Do you need access to our Microsoft tenant?', 'Read-only access to usage analytics is helpful but not required. The assessment can run on interview data, screenshots, and documentation alone.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'Who should be involved from our side?', 'An IT or M365 lead, an HR or Internal Comms representative, and a handful of end users across different functions give us the breadth we need.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'What do we get at the end of the week?', 'A maturity scorecard, a gap register, a prioritised roadmap, and an executive summary, all walked through in a findings session.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (55, 'How do we get started?', 'Book a brief scoping call. The DigitalQatalyst team will confirm participants, access needs, and the week''s schedule before work begins.', 4);

-- Digital Workplace (High-Impact) - Design (variant 56)
UPDATE product_content SET
  description = 'Turn your digital workplace goals into user-centred wireframes, information architecture, and build-ready specifications covering Microsoft 365 configuration, intranet structure, and adoption planning, delivered across a focused four-week design engagement.',
  positioning = 'Turn workplace collaboration goals into a blueprint your IT team can build and your employees will actually use.',
  hero_summary = 'Turn your digital workplace goals into user-centred wireframes, information architecture, and build-ready specifications covering Microsoft 365 configuration, intranet structure, and adoption planning, delivered across a focused four-week design engagement.',
  overview_paragraphs = '["The Digital Workplace Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns workplace goals into user-centred designs and build-ready specifications.","Turn digital workplace and collaboration goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for hr, it & internal comms leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate digital workplace requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Designs tested against real user journeys, not just IT requirements","Build-ready specification handed over at the end of week four","Adoption plan included so launch success is designed in from the start"]'::jsonb,
  why_it_matters = '{"hook":"Your digital workplace is how teams collaborate, decide, and deliver every day.","problemParagraph":"Many organisations adopt tools without aligned workflows, adoption plans, or specifications that implementation teams can build against. This design engagement turns workplace goals into user-centred designs and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Tool sprawl","description":"Collaboration happens across disconnected apps with no shared workflow model."},{"title":"Uneven adoption","description":"Teams use platforms differently, reducing productivity gains."},{"title":"Build ambiguity","description":"Delivery teams lack journey maps, standards, and specs to implement with confidence."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned workplace experience","description":"Journeys and workflows reflect how teams actually work."},{"title":"Consistent standards","description":"UX, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Build teams receive artefacts that reduce rework and accelerate delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about the Digital Workplace design engagement.'
WHERE variant_id = 56;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'User Journey Maps', 'Step-by-step flows for the tasks employees perform most, showing where today''s tools create friction and where the redesign removes it.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'Information Architecture and Wireframes', 'Site structure, navigation taxonomy, and annotated wireframes for intranet pages and team spaces ready for a SharePoint developer to build against.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'Microsoft 365 Configuration Specification', 'Detailed settings, permissions, and integration requirements across Teams, SharePoint, and connected apps, formatted for the delivery team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (56, 'Adoption and Launch Plan', 'A champions programme outline, training schedule, and communication templates to ensure employees actually shift to the new ways of working.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'What design tools do you produce artefacts in?', 'Wireframes are delivered in Figma by default. The DigitalQatalyst team can adapt to your preferred tooling if agreed at the start.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'Do we need to have completed an assessment first?', 'An assessment or equivalent discovery findings are helpful, but the design engagement includes its own discovery workshops so you can start here if your requirements are already clear.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'Can this cover a full intranet rebuild or just improvements?', 'Both. The scope is confirmed in week one and can range from targeted improvements to a full SharePoint intranet architecture.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (56, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm scope, stakeholder availability, and the week-one workshop schedule.', 3);

-- Digital Workplace (High-Impact) - AI Design (variant 57)
UPDATE product_content SET
  description = 'Find the AI use cases that will genuinely reduce friction in your digital workplace, validate each for feasibility and responsibility, and produce governed workflow specifications ready for build, all within a four-week AI design engagement.',
  positioning = 'Find the AI use cases that will genuinely improve employee productivity, and design them safely before spending on build.',
  hero_summary = 'Find the AI use cases that will genuinely reduce friction in your digital workplace, validate each for feasibility and responsibility, and produce governed workflow specifications ready for build, all within a four-week AI design engagement.',
  overview_paragraphs = '["The Digital Workplace AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for digital workplace and collaboration, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for hr, it & internal comms leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for digital workplace.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Responsible AI criteria applied to every use case before a line of build begins","Copilot for Microsoft 365 readiness included as a standard workstream","Specifications handed over in a format your delivery team can act on immediately"]'::jsonb,
  why_it_matters = '{"hook":"Your digital workplace is how teams collaborate, decide, and deliver every day.","problemParagraph":"Many organisations apply AI to your digital workplace without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for digital workplace lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for digital workplace are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the Digital Workplace AI design engagement.'
WHERE variant_id = 57;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'AI Use-Case Shortlist and Scoring Matrix', 'Validated workplace AI scenarios ranked by employee impact, data readiness, and risk level, with a recommended build sequence.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'Copilot Readiness Report', 'Assessment of your Microsoft 365 data governance, sensitivity labelling, and licence position against the requirements for a safe Copilot deployment.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'Responsible AI Workflow Specifications', 'Detailed workflow designs for the prioritised use cases, including human review points, override mechanisms, and audit trail requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (57, 'Build and Rollout Plan', 'Phased deployment sequence with dependency mapping, pilot cohort definition, and success metrics for each AI capability.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'Does this only cover Microsoft Copilot?', 'Copilot for Microsoft 365 is the primary focus, but the DigitalQatalyst team can evaluate other AI tooling such as Viva Insights or third-party assistants within the same engagement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'What data governance work is needed before AI can go live?', 'That depends on your current labelling and access-control maturity. The Copilot readiness report identifies exactly what needs to be in place and in what order.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'Can we proceed straight to AI Deploy without a prior design engagement?', 'Only if you already have validated use cases and governance specifications. If not, this design engagement prevents costly rework during build.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (57, 'How do we get started?', 'Reach out to the DigitalQatalyst team. They will confirm your Microsoft 365 licence position, data landscape, and the workshop schedule before work begins.', 3);

-- Digital Workplace (High-Impact) - Deploy (variant 58)
UPDATE product_content SET
  description = 'Get your Microsoft 365 digital workplace environment built, integrated, and adopted, covering SharePoint intranet, Teams governance, and the structured adoption programme your employees need to shift their working habits, delivered across twelve weeks.',
  positioning = 'Get your digital workplace built, tested, and adopted, not just switched on.',
  hero_summary = 'Get your Microsoft 365 digital workplace environment built, integrated, and adopted, covering SharePoint intranet, Teams governance, and the structured adoption programme your employees need to shift their working habits, delivered across twelve weeks.',
  overview_paragraphs = '["The Digital Workplace Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed digital workplace and collaboration changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for hr, it & internal comms leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated digital workplace assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Full build, test, and launch, not a configuration-only handover","Adoption programme runs alongside the technical build","Hypercare support included in the final two weeks"]'::jsonb,
  why_it_matters = '{"hook":"Your digital workplace is how teams collaborate, decide, and deliver every day.","problemParagraph":"Many organisations stall between approved designs and production for your digital workplace, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for digital workplace sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the Digital Workplace deployment engagement.'
WHERE variant_id = 58;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Configured SharePoint Intranet', 'A built and content-populated intranet matching the approved architecture, with templates, permissions, and search configured for your organisation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Teams Governance Ruleset', 'Enforced naming conventions, provisioning policies, guest-access rules, and lifecycle settings keeping your Teams environment manageable at scale.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Integration Build and Test Evidence', 'Documented and tested connections to HRIS, ITSM, and other agreed systems, with test scripts and sign-off records.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (58, 'Adoption Programme Outcomes Report', '30-day usage data, champion engagement summary, and recommended actions for sustaining adoption after handover.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'What Microsoft 365 licence do we need?', 'Business Premium or E3 covers the core scope. The DigitalQatalyst team confirms exact licence requirements during the kickoff sprint.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'Can you migrate content from our old intranet?', 'Yes. Content migration is scoped during weeks one to two. Volume, format, and metadata complexity determine the effort estimate.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'What if our employees do not adopt the new tools?', 'The adoption programme is built into the engagement, not bolted on. Champions are trained, communications are scheduled, and usage is tracked so issues surface early.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (58, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved design specification or existing requirements. They will confirm the sprint plan and environment access needed to begin.', 3);

-- Digital Workplace (High-Impact) - AI Deploy (variant 59)
UPDATE product_content SET
  description = 'Put AI to work across your digital workplace with governance, monitoring, and adoption built in from the start, including Microsoft Copilot, automated knowledge surfacing, and AI-assisted communication tools deployed over twelve weeks.',
  positioning = 'Put AI to work in your digital workplace with governance, monitoring, and adoption built in from the start.',
  hero_summary = 'Put AI to work across your digital workplace with governance, monitoring, and adoption built in from the start, including Microsoft Copilot, automated knowledge surfacing, and AI-assisted communication tools deployed over twelve weeks.',
  overview_paragraphs = '["The Digital Workplace AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled digital workplace and collaboration workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for hr, it & internal comms leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for digital workplace with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Governance controls configured before any AI capability goes live","Pilot cohort approach reduces risk before full organisational rollout","Monitoring dashboard handed over so your team can manage AI use independently"]'::jsonb,
  why_it_matters = '{"hook":"Your digital workplace is how teams collaborate, decide, and deliver every day.","problemParagraph":"Many AI initiatives for your digital workplace fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for digital workplace fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about deploying AI capabilities into your digital workplace.'
WHERE variant_id = 59;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'Copilot Deployment with Governance Controls', 'Microsoft 365 Copilot live for your user base with sensitivity labels enforced, usage policies published, and employee guidance distributed.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'AI Search and Knowledge Configuration', 'Microsoft Search or equivalent tuned to surface relevant, permission-correct results from SharePoint, Teams, and connected repositories.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'Automated Workflow Builds', 'Power Automate flows handling agreed employee request scenarios, tested and handed over with documentation for your support team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (59, 'AI Monitoring Dashboard', 'A live view of Copilot usage, prompt patterns, and adoption by department so your IT team can optimise and govern AI use on an ongoing basis.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'What Microsoft licences are required for Copilot?', 'Microsoft 365 Copilot requires an E3 or E5 base licence plus the Copilot add-on. The DigitalQatalyst team confirms your exact licence position at kickoff.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'How do you prevent Copilot surfacing data employees should not see?', 'Sensitivity labels and permissions are audited and corrected before Copilot is enabled. The readiness checklist from the AI design phase drives this work.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'What happens if employees misuse AI tools?', 'Usage policies, monitoring alerts, and manager-visible reporting are all configured. The DigitalQatalyst team trains your IT team to act on the signals.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (59, 'How do we get started?', 'Share your AI design specification and current licence position with the DigitalQatalyst team. They will confirm the pilot cohort, governance prerequisites, and kickoff schedule.', 3);

-- Digital Workplace (High-Impact) - Managed (variant 60)
UPDATE product_content SET
  description = 'Ongoing managed operations for your Microsoft 365 digital workplace environment, covering platform health monitoring, licence and configuration governance, adoption reporting, and monthly optimisation to keep the environment aligned to how your organisation works.',
  positioning = 'Keep your digital workplace performing, adopted, and fit for purpose without loading internal IT with platform management.',
  hero_summary = 'Ongoing managed operations for your Microsoft 365 digital workplace environment, covering platform health monitoring, licence and configuration governance, adoption reporting, and monthly optimisation to keep the environment aligned to how your organisation works.',
  overview_paragraphs = '["The Digital Workplace Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve digital workplace and collaboration with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for hr, it & internal comms leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for digital workplace - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed response times for configuration issues affecting employee access","Licence optimisation reviewed annually to avoid paying for unused capacity","Monthly adoption reporting included as standard, not an add-on"]'::jsonb,
  why_it_matters = '{"hook":"Your digital workplace is how teams collaborate, decide, and deliver every day.","problemParagraph":"Many organisations struggle to sustain performance across your digital workplace after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"digital workplace issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the Digital Workplace managed service.'
WHERE variant_id = 60;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Monthly Health and Adoption Report', 'Usage metrics, configuration status, and adoption trends across Teams, SharePoint, and connected apps, with recommended actions for the following month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Configuration Change Log', 'Documented record of every setting change, policy update, and integration modification applied during the month, with rationale and sign-off.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Feature Update Briefings', 'Monthly summary of incoming Microsoft 365 feature releases assessed for relevance and readiness, with a recommended rollout plan for your organisation.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (60, 'Quarterly Roadmap Review', 'A structured session with the DigitalQatalyst team to reassess priorities, adjust the backlog, and confirm the next quarter''s improvement focus.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'What does the managed service cover that our IT team does not already do?', 'Proactive configuration drift detection, adoption analytics interpretation, and Microsoft feature-update planning are typically the gaps. The DigitalQatalyst team handles these so your IT team can focus on internal requests.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'Can we add new capabilities under the managed service?', 'Minor enhancements are included. Larger additions are scoped as separate engagements. The monthly review session is the right place to flag new requirements.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'What are the SLA response times?', 'Response times are agreed at onboarding. The standard plan covers critical issues within four business hours and standard changes within five business days.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (60, 'How do we get started?', 'Contact the DigitalQatalyst team. They will complete a baseline health audit of your Microsoft 365 environment before the first SLA period begins.', 3);

-- Business Process Automation (High-Impact) - Assess (variant 61)
UPDATE product_content SET
  description = 'Find out which manual processes cost the most time and which are genuinely ready to automate, with a prioritised roadmap and an honest view of the tooling and data readiness required, delivered within one week.',
  positioning = 'Find the manual processes that cost the most time, then get a clear plan to automate the right ones first.',
  hero_summary = 'Find out which manual processes cost the most time and which are genuinely ready to automate, with a prioritised roadmap and an honest view of the tooling and data readiness required, delivered within one week.',
  overview_paragraphs = '["The Business Process Automation Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps automation maturity and returns prioritised improvements your operations leaders can act on.","See how business process automation performs today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for coos, operations & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews business process automation across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed scope across your agreed process areas -- no scope creep and no open-ended discovery billing","Tool-neutral: recommends the right automation approach for each process","Business case summary included for stakeholder sign-off"]'::jsonb,
  why_it_matters = '{"hook":"Manual processes and disconnected workflows are among the biggest drains on operational performance.","problemParagraph":"Many organisations automate ad hoc tasks without end-to-end process visibility, governance, or a clear view of ROI. This assessment maps automation maturity and returns prioritised improvements your operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Manual handoffs","description":"Work stalls between systems because steps are not orchestrated end to end."},{"title":"Process inconsistency","description":"Teams run the same work differently without documented standards."},{"title":"Unclear automation candidates","description":"High-value workflows are not ranked by effort, risk, and return."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Process-led priorities","description":"You know which workflows to automate or redesign first."},{"title":"Ranked automation backlog","description":"Candidates are ordered by impact, feasibility, and dependency."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and automation investment."}]}}'::jsonb,
  faq_intro = 'Questions about the Business Process Automation assessment.'
WHERE variant_id = 61;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Process Inventory and Scoring Matrix', 'Every in-scope process documented and rated for automation potential, with volume, error rate, and complexity noted for each.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Tool Fit Analysis', 'Assessment of which automation approach, RPA, low-code workflow, or API integration, suits each candidate given your existing platforms and IT constraints.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Prioritised Automation Roadmap', 'Sequenced list of automation candidates with estimated effort, expected hours saved per month, and recommended tooling for each initiative.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (61, 'Business Case Summary', 'A concise document for COO and finance stakeholders covering total addressable saving and recommended first investment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'Which processes are in scope?', 'Scope is agreed at the start of the week. Most assessments cover operations, finance approvals, HR onboarding, and IT service requests. Additional areas can be included.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'Do we need to have a specific automation tool already chosen?', 'No. The assessment is tool-neutral and will recommend the right approach, whether that is Power Automate, UiPath, Zapier, or custom API integration, based on your existing stack.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'What if we already know which processes we want to automate?', 'The DigitalQatalyst team will validate those candidates and assess them alongside others you may not have considered, ensuring the roadmap reflects the full opportunity.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (61, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. They will confirm which departments to include and what documentation to prepare before day one.', 3);

-- Business Process Automation (High-Impact) - Design (variant 62)
UPDATE product_content SET
  description = 'Eliminate the ambiguity that causes automation rework: get detailed process specifications, tool configurations, and test plans your delivery team can build and launch each workflow against, completed across a focused four-week design engagement.',
  positioning = 'Design your automations properly before building them: fewer rework cycles, faster go-live, and workflows that hold up in production.',
  hero_summary = 'Eliminate the ambiguity that causes automation rework: get detailed process specifications, tool configurations, and test plans your delivery team can build and launch each workflow against, completed across a focused four-week design engagement.',
  overview_paragraphs = '["The Business Process Automation Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines process automation and build-ready specifications.","Turn business process automation goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for coos, operations & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate business process automation requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Exception and escalation paths designed in, not discovered during build","Platform-specific configuration specifications, not generic process diagrams","Test plan included so QA can begin immediately after build"]'::jsonb,
  why_it_matters = '{"hook":"Manual processes and disconnected workflows are among the biggest drains on operational performance.","problemParagraph":"Many organisations launch automation without designed workflows, exception handling, or specifications platform teams can implement. This design engagement defines process automation and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined workflow models","description":"Triggers, approvals, and exceptions are not designed before build."},{"title":"Integration gaps","description":"Systems of record lack clear APIs, events, and data contracts."},{"title":"Governance ambiguity","description":"Teams lack controls for monitoring, audit, and change management."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Designed automation flows","description":"Workflows reflect real operations with clear human-in-the-loop points."},{"title":"Integration standards","description":"Data, events, and platform requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts that accelerate reliable automation."}]}}'::jsonb,
  faq_intro = 'Questions about the Business Process Automation design engagement.'
WHERE variant_id = 62;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'As-Is and To-Be Process Maps', 'Detailed flow diagrams for each automation candidate showing current manual steps and the redesigned automated flow, including all exception and escalation paths.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'Automation Configuration Specifications', 'Step-by-step build instructions for your chosen platform, covering triggers, actions, field mappings, conditions, and error-handling logic.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'Integration Architecture Document', 'API connection designs, data transformation rules, and authentication approaches for each system the automation touches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (62, 'Test Plan and Acceptance Criteria', 'A ready-to-execute test script covering happy paths, edge cases, and failure scenarios with pass/fail criteria for each.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'How many automation workflows does the design engagement cover?', 'Typically three to five workflows depending on complexity. The DigitalQatalyst team confirms scope based on your prioritised roadmap during week one.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'Can you design for any automation platform?', 'Yes. The DigitalQatalyst team designs to your chosen platform, whether Power Automate, UiPath, Automation Anywhere, Make, or another tool.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'Do we need development resources available during the design phase?', 'A technical contact who understands your systems and APIs is helpful in weeks two and three to validate integration assumptions.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (62, 'How do we get started?', 'Share your prioritised automation roadmap or assessment output with the DigitalQatalyst team and confirm which platform you are building on.', 3);

-- Business Process Automation (High-Impact) - AI Design (variant 63)
UPDATE product_content SET
  description = 'Identify where intelligent automation, including document processing, decision support, and predictive routing, can extend your process automation beyond what rules-based tools handle, with responsible design and deployment specifications for each use case, ready after four weeks.',
  positioning = 'Design the AI layer that takes your process automation from rules-based to genuinely intelligent, safely and with governance built in.',
  hero_summary = 'Identify where intelligent automation, including document processing, decision support, and predictive routing, can extend your process automation beyond what rules-based tools handle, with responsible design and deployment specifications for each use case, ready after four weeks.',
  overview_paragraphs = '["The Business Process Automation AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for business process automation, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for coos, operations & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for business process automation.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Focused on processes where AI genuinely outperforms rules, not where it adds complexity without value","Responsible AI criteria applied at design stage, not retrofitted after build","Governance and model management plan included so the AI stays reliable over time"]'::jsonb,
  why_it_matters = '{"hook":"Manual processes and disconnected workflows are among the biggest drains on operational performance.","problemParagraph":"Many organisations apply AI to your business processes without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for business process automation lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for business process automation are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about designing AI capabilities for business process automation.'
WHERE variant_id = 63;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'AI Use-Case Feasibility Report', 'Scored assessment of each AI candidate covering data readiness, model options, implementation complexity, and responsible AI considerations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'Intelligent Document Processing Specification', 'Design for AI-powered extraction and classification of unstructured documents, including field mapping, confidence scoring, and exception routing.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'AI Workflow Designs', 'Detailed workflow specifications for each prioritised use case, showing where AI decisions are made, where humans review, and where the audit trail is recorded.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (63, 'Governance and Model Management Plan', 'Confidence thresholds, human-in-the-loop rules, monitoring metrics, and retraining triggers for each AI model deployed in a process.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'What kinds of processes benefit most from AI rather than standard automation?', 'Processes involving unstructured data, variable inputs, or judgement-based decisions: invoice processing, contract review, complaint classification, and demand forecasting are common examples.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'Do we need to have our own AI models or data science team?', 'No. The DigitalQatalyst team designs for pre-built AI services, such as Azure AI Document Intelligence or AWS Textract, so you do not need in-house model training capability.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'How do you handle cases where the AI makes the wrong decision?', 'Confidence thresholds and human-review triggers are designed in from the start. Every AI decision that falls below the threshold routes to a human before any action is taken.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (63, 'How do we get started?', 'Bring your existing automation roadmap and the DigitalQatalyst team will identify which processes are candidates for AI extension. A brief scoping call is the first step.', 3);

-- Business Process Automation (High-Impact) - Deploy (variant 64)
UPDATE product_content SET
  description = 'Get your automation workflows built, tested, and running in production, covering RPA bots, low-code automations, and API integrations, with a documented handover including runbooks and administrator sign-off to the teams who will maintain them, delivered across twelve weeks.',
  positioning = 'Get your automation workflows built, tested, and running in production, with the documentation and training your team needs to own them.',
  hero_summary = 'Get your automation workflows built, tested, and running in production, covering RPA bots, low-code automations, and API integrations, with a documented handover including runbooks and administrator sign-off to the teams who will maintain them, delivered across twelve weeks.',
  overview_paragraphs = '["The Business Process Automation Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed business process automation changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for coos, operations & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated business process automation assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Builds delivered in fortnightly sprints so you see working automations before the project ends","Business sign-off on acceptance criteria before any workflow goes live","Runbooks and administrator training included in the final two weeks"]'::jsonb,
  why_it_matters = '{"hook":"Manual processes and disconnected workflows are among the biggest drains on operational performance.","problemParagraph":"Many organisations stall between approved designs and production for your business processes, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for business process automation sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the Business Process Automation deployment engagement.'
WHERE variant_id = 64;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'Built and Tested Automation Workflows', 'Live automations running in your production environment, tested against the agreed acceptance criteria and signed off by business stakeholders.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'API Integration Connections', 'Functioning and documented connections between your automation platform and the source systems each workflow depends on.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'Test Evidence Pack', 'Executed test scripts, defect log, and sign-off records covering all tested scenarios for audit and governance purposes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (64, 'Operations Runbook and Training', 'Step-by-step runbooks for each automation, monitoring alert setup, and hands-on training for the team responsible for day-to-day oversight.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'How many workflows can be built in twelve weeks?', 'Typically five to ten workflows depending on complexity. The sprint plan confirms scope in week one based on the approved design specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'What if we discover a workflow is more complex than the design assumed?', 'Scope changes are assessed in the affected sprint. The DigitalQatalyst team will present options: simplify the design, adjust other scope, or extend with a change request.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'Do we need dedicated technical resources from our side?', 'A system access contact and a business owner for each workflow are required. Dedicated developer time from your side is helpful but not essential.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (64, 'How do we get started?', 'Provide your approved design specifications and the DigitalQatalyst team will confirm environment access, tooling licences, and the sprint-one schedule.', 3);

-- Business Process Automation (High-Impact) - AI Deploy (variant 65)
UPDATE product_content SET
  description = 'Put governed AI automation into production, including intelligent document processing, AI-driven decision routing, and predictive workflow triggers, with monitoring active from day one and a pilot-first approach that contains risk before full scale.',
  positioning = 'Put governed AI automation into production: document intelligence, decision support, and predictive routing, live and monitored.',
  hero_summary = 'Put governed AI automation into production, including intelligent document processing, AI-driven decision routing, and predictive workflow triggers, with monitoring active from day one and a pilot-first approach that contains risk before full scale.',
  overview_paragraphs = '["The Business Process Automation AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled business process automation workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for coos, operations & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for business process automation with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pilot cohort approach confirms accuracy before full-scale automation runs","Governance controls and audit logging configured before any AI decision affects a live process","Monitoring handed over to your team with trained operators, not just dashboards"]'::jsonb,
  why_it_matters = '{"hook":"Manual processes and disconnected workflows are among the biggest drains on operational performance.","problemParagraph":"Many AI initiatives for your business processes fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for business process automation fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about deploying AI automation capabilities into production.'
WHERE variant_id = 65;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'Deployed Intelligent Document Processing', 'AI document extraction and classification running in production with agreed field accuracy rates, confidence thresholds, and human-review queue configured.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'AI Decision-Routing Integration', 'AI-powered routing logic embedded in your workflow orchestration, with audit logs recording every decision and its confidence score.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'Monitoring and Alerting Configuration', 'Live dashboards and alert rules covering model accuracy, throughput, exception rates, and human-review queue depth for your operations team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (65, 'Pilot Outcome Report', 'Accuracy benchmarks, exception rates, and throughput data from the pilot period, with recommendations for threshold adjustments before full production scale.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'What accuracy rates can we expect from intelligent document processing?', 'Accuracy depends on document quality and variability. The DigitalQatalyst team sets baseline targets during the pilot and tunes extraction rules before full rollout.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'What happens when an AI decision is wrong?', 'Every decision below the confidence threshold routes to a human reviewer before any downstream action is taken. The audit log records the AI output and the human decision.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'Can we use our existing document processing tool, or do we need a new one?', 'The DigitalQatalyst team will assess your existing tooling. If it meets the requirements, the engagement extends its capability rather than replacing it.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (65, 'How do we get started?', 'Share your AI workflow design specifications and the DigitalQatalyst team will confirm the pilot cohort, governance prerequisites, and environment access needed to begin.', 3);

-- Business Process Automation (High-Impact) - Managed (variant 66)
UPDATE product_content SET
  description = 'Ongoing managed operations for your business process automation environment, covering bot health monitoring, exception queue management, platform updates, and monthly performance reporting so your automations keep delivering the savings they were built to produce.',
  positioning = 'Keep your automation estate healthy and producing savings, without your team spending time on bot maintenance and exception triaging.',
  hero_summary = 'Ongoing managed operations for your business process automation environment, covering bot health monitoring, exception queue management, platform updates, and monthly performance reporting so your automations keep delivering the savings they were built to produce.',
  overview_paragraphs = '["The Business Process Automation Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve business process automation with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for coos, operations & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for business process automation - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Daily monitoring with SLA-backed response times for automation failures","Exception queue triage included so your operations team is not manually firefighting bot failures","Change impact assessments prevent unexpected automation breakage during system upgrades"]'::jsonb,
  why_it_matters = '{"hook":"Manual processes and disconnected workflows are among the biggest drains on operational performance.","problemParagraph":"Many organisations struggle to sustain performance across your business processes after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"business process automation issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the Business Process Automation managed service.'
WHERE variant_id = 66;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Monthly Automation Performance Report', 'Hours saved, exception rates, queue health, and SLA adherence for every automation in the managed estate, with a recommended actions list.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Exception and Incident Log', 'Documented record of every automation failure, root cause, resolution action, and recurrence prevention measure taken during the month.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Change Impact Assessments', 'Assessment of how upcoming system changes, such as ERP upgrades or API version changes, affect your automations, with remediation plans and effort estimates.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (66, 'Quarterly Optimisation Review', 'Structured session with the DigitalQatalyst team to review performance trends, retire underperforming bots, and prioritise new automation candidates.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'What is included in exception queue management?', 'The DigitalQatalyst team performs first-line triage on failed automation runs: diagnosing the cause, applying fixes where possible, and escalating to your team with a documented root cause when a code change is needed.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'How do you handle changes to the systems our automations connect to?', 'The DigitalQatalyst team monitors announced changes from your ERP, CRM, and other connected platforms and produces an impact assessment before each change lands.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'Can we add new automations under the managed service?', 'Minor enhancements and small new workflows are included within capacity. Larger additions are scoped as separate engagements and flagged in the quarterly review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (66, 'How do we get started?', 'Contact the DigitalQatalyst team with an inventory of your current automation estate. They will complete a health baseline before the first SLA period begins.', 3);

-- Specialised Operations (High-Impact) - Assess (variant 73)
UPDATE product_content SET
  description = 'Most specialist operations work -- barely. Facilities management teams run on spreadsheets and tribal knowledge. Legal ops functions manage matter intake through email. Field service scheduling lives in a supervisor''s head. This one-week assessment maps the workflows, bottlenecks, and tech debt unique to your operational function and tells you where you are losing money, creating compliance risk, and building fragility into something the business depends on.',
  positioning = 'Walk away with a clear picture of where your specialist operation is haemorrhaging time and risk, and which fixes will pay back fastest.',
  hero_summary = 'Most specialist operations work -- barely. Facilities management teams run on spreadsheets and tribal knowledge. Legal ops functions manage matter intake through email. Field service scheduling lives in a supervisor''s head. This one-week assessment maps the workflows, bottlenecks, and tech debt unique to your operational function and tells you where you are losing money, creating compliance risk, and building fragility into something the business depends on.',
  overview_paragraphs = '["The Specialised Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your domain leaders can act on.","See how specialised operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for business unit & domain operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews specialised operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed scope covering your specific operational function -- no assumptions about what your domain looks like until we have mapped your workflows","Interview-led methodology captures operational reality, not just what systems report","Findings playback with the DigitalQatalyst team included"]'::jsonb,
  why_it_matters = '{"hook":"Specialised operational capabilities are what differentiate your organisation in complex environments.","problemParagraph":"Many organisations run specialised operations with bespoke processes, limited standardisation, and unclear technology fit. This assessment maps operational maturity and returns prioritised improvements your domain leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Bespoke process drift","description":"Critical workflows evolve informally without documented standards."},{"title":"Technology misalignment","description":"Tools do not match the specificity of operational requirements."},{"title":"Limited performance visibility","description":"Leaders lack shared metrics on throughput, quality, and risk."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which processes and systems to improve first."},{"title":"Ranked transformation backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and programme funding."}]}}'::jsonb,
  faq_intro = 'Questions about the Specialised Operations assessment.'
WHERE variant_id = 73;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Operational Function Assessment Report', 'Documented review of your specialist function covering workflow maturity, tooling fit, bottleneck locations, and the specific gaps limiting throughput and control.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Bottleneck and Tech Debt Register', 'Every identified constraint and workaround scored by operational impact and remediation effort, with risk flags for gaps carrying compliance or safety implications.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Prioritised Improvement Roadmap', 'Sequenced recommendations with effort estimates, dependency mapping, and ownership suggestions your operational and IT leads can plan against immediately.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (73, 'Executive Briefing', 'A concise summary of findings, risk exposures, and recommended first investments formatted for your business unit and technology leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'What kinds of specialist operations does this cover?', 'Field service management, asset and facilities operations, quality management, supply chain execution, and other domain-specific functions. The DigitalQatalyst team confirms fit during the scoping call.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'Can you assess a function that uses a niche or legacy system we built internally?', 'Yes. The assessment is focused on the operational function, not just commercial platforms. Custom and legacy systems are reviewed as part of the tooling analysis.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'Who from our organisation needs to be available?', 'The operational function lead, two to three front-line staff, and the system owner for the primary operational platform are the minimum. Additional stakeholders can be included if scope warrants it.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (73, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team to confirm the operational function in scope, the stakeholders to involve, and any documentation to prepare in advance.', 3);

-- Specialised Operations (High-Impact) - Design (variant 74)
UPDATE product_content SET
  description = 'Your assessment identified the highest-priority problems. Now you need a blueprint that actually fixes them -- process redesigns your operational staff will recognise, system configurations your delivery team can build, and integration specifications that close the gaps between your operational platform and the ERP, scheduling, and reporting tools it needs to talk to. This four-week design engagement produces that blueprint, built for your specific domain.',
  positioning = 'Get build-ready process redesigns and system specifications that solve the problems your assessment identified, not a generic operating model document.',
  hero_summary = 'Your assessment identified the highest-priority problems. Now you need a blueprint that actually fixes them -- process redesigns your operational staff will recognise, system configurations your delivery team can build, and integration specifications that close the gaps between your operational platform and the ERP, scheduling, and reporting tools it needs to talk to. This four-week design engagement produces that blueprint, built for your specific domain.',
  overview_paragraphs = '["The Specialised Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement turns operational goals into structured designs and build-ready specifications.","Turn specialised operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for business unit & domain operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate specialised operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Process redesigns validated with front-line operational staff, not just management requirements","Integration architecture included so downstream systems are part of the design, not an afterthought","Build-ready specifications handed over at end of week four"]'::jsonb,
  why_it_matters = '{"hook":"Specialised operational capabilities are what differentiate your organisation in complex environments.","problemParagraph":"Many organisations digitise specialised operations without designed workflows, controls, or specifications delivery teams can implement. This design engagement turns operational goals into structured designs and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational models","description":"Workflows, roles, and controls are not designed against business rules."},{"title":"Inconsistent standards","description":"Teams interpret procedures differently across sites or functions."},{"title":"Build ambiguity","description":"Delivery teams lack specs aligned to domain constraints and compliance."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect domain requirements with clear accountability."},{"title":"Consistent control standards","description":"Governance, data, and integration rules are defined upfront."},{"title":"Implementation-ready specs","description":"Teams receive artefacts tailored to specialised operational delivery."}]}}'::jsonb,
  faq_intro = 'Questions about the Specialised Operations design engagement.'
WHERE variant_id = 74;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'Redesigned Process Maps', 'To-be workflow diagrams for each priority area, showing role, system, data, and decision at every step, with exceptions and escalations mapped and ready for build.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'System Configuration Specification', 'Detailed build instructions for your operational platform covering objects, fields, screens, rules, and automation triggers, formatted for your delivery team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'Integration Architecture Document', 'API contracts, data transformation rules, and connection design for each integration between your operational system and the platforms it depends on.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (74, 'Adoption and Change Plan', 'Training outline, communication timeline, and cut-over guidance for the operational staff and managers affected by the redesigned workflows.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'Can this cover a purpose-built or niche operational platform?', 'Yes. The DigitalQatalyst team designs to the platform your function uses, whether a leading field service tool, a bespoke case management system, or a sector-specific application.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'How do you capture what operational staff actually need versus what management thinks they need?', 'Week one includes structured sessions with front-line operational staff. Their task walkthroughs and friction points directly shape the to-be design.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'Do we need an existing system in place, or can this design a new one?', 'Both. The design engagement can specify a new operational platform or redesign the workflows in an existing one.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (74, 'How do we get started?', 'Contact the DigitalQatalyst team with details of your operational function and the platform in scope. They will confirm the week-one workshop schedule and participants.', 3);

-- Specialised Operations (High-Impact) - AI Design (variant 75)
UPDATE product_content SET
  description = 'Identify where AI can genuinely improve your facilities management, field service, quality, or other specialist operational workflows, from predictive scheduling and anomaly detection to AI-assisted decision support, with feasibility validation and responsible design specifications for each use case.',
  positioning = 'Identify where AI genuinely improves specialist operational performance, and design it responsibly before investing in build.',
  hero_summary = 'Identify where AI can genuinely improve your facilities management, field service, quality, or other specialist operational workflows, from predictive scheduling and anomaly detection to AI-assisted decision support, with feasibility validation and responsible design specifications for each use case.',
  overview_paragraphs = '["The Specialised Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for specialised operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for business unit & domain operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for specialised operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Domain-specific risk assessment applied to every AI use case","Data readiness evaluated before any build investment is committed","Governance specification included so responsible AI is built in, not added later"]'::jsonb,
  why_it_matters = '{"hook":"Specialised operational capabilities are what differentiate your organisation in complex environments.","problemParagraph":"Many organisations apply AI to your specialised operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for specialised operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for specialised operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about designing AI for specialist operational functions.'
WHERE variant_id = 75;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'AI Use-Case Feasibility Assessment', 'Scored evaluation of each candidate AI use case covering data availability, model suitability, operational risk, and responsible AI considerations specific to your domain.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'Domain-Specific AI Workflow Designs', 'Detailed workflow specifications for prioritised use cases showing where AI acts, where humans review, and where the decision record is kept.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'Data Readiness Report', 'Assessment of whether your operational data, in terms of volume, quality, and labelling, supports the identified AI models, with remediation steps where gaps exist.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (75, 'Governance and Monitoring Specification', 'Confidence thresholds, override controls, audit logging requirements, and model performance metrics for each AI capability to be deployed.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'What types of AI are most relevant to specialist operations?', 'Predictive maintenance, intelligent scheduling, anomaly and quality defect detection, and AI-assisted case triage tend to offer the highest returns in domain-specific operations. The DigitalQatalyst team validates which apply to your function.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'What if our operational data is not clean enough for AI?', 'The data readiness report identifies exactly what needs to improve and in what order. Some use cases can proceed with targeted data remediation; others may need to wait.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'Are there safety or regulatory considerations for AI in our operational function?', 'Domain-specific risk is assessed in week two. Where regulatory or safety considerations apply, the DigitalQatalyst team incorporates them into the responsible AI framework for each use case.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (75, 'How do we get started?', 'Contact the DigitalQatalyst team with details of your operational function and the processes you think could benefit from AI. They will confirm scope and the week-one workshop schedule.', 3);

-- Specialised Operations (High-Impact) - Deploy (variant 76)
UPDATE product_content SET
  description = 'Get your specialist operational system, whether for field service, facilities management, quality management, or case handling, configured, integrated, tested, and live in twelve weeks, with week-by-week knowledge transfer and handover documentation so your team can manage the environment independently.',
  positioning = 'Get your specialist operational system configured, connected, and live, with the training and documentation to own it after handover.',
  hero_summary = 'Get your specialist operational system, whether for field service, facilities management, quality management, or case handling, configured, integrated, tested, and live in twelve weeks, with week-by-week knowledge transfer and handover documentation so your team can manage the environment independently.',
  overview_paragraphs = '["The Specialised Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed specialised operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for business unit & domain operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated specialised operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Front-line operational staff involved in acceptance testing, not just IT reviewers","Knowledge transfer and administrator training built into the final two weeks","Hypercare support included so issues surfacing after go-live are resolved quickly"]'::jsonb,
  why_it_matters = '{"hook":"Specialised operational capabilities are what differentiate your organisation in complex environments.","problemParagraph":"Many organisations stall between approved designs and production for your specialised operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for specialised operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the Specialised Operations deployment engagement.'
WHERE variant_id = 76;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'Configured Operational Platform', 'Your specialist operational system live in production, configured to the approved specification and signed off by operational stakeholders.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'Integration Connections', 'Tested and documented connections between your operational platform and ERP, scheduling, reporting, and other agreed systems.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'User Acceptance Test Evidence', 'Executed test scripts covering role-specific operational scenarios, with defect log and sign-off records for audit and governance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (76, 'Administrator Runbooks and Training', 'Step-by-step operational guides, configuration documentation, and hands-on training for the team responsible for maintaining the system.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'Can you configure a niche or sector-specific operational platform?', 'Yes, provided the DigitalQatalyst team has the relevant platform expertise or you can provide a certified implementation partner to collaborate with. Scope is confirmed at kickoff.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'What happens if operational staff reject the new system during testing?', 'User acceptance testing in weeks nine and ten is designed to surface usability issues before go-live. Findings are addressed in the same testing window to protect the launch date.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'Do we need to migrate historical data?', 'Data migration scope is confirmed in weeks one to two. Volume, quality, and format complexity determine effort. Not all deployments require historical data migration.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (76, 'How do we get started?', 'Provide your approved design specification and the DigitalQatalyst team will confirm environment access, data migration scope, and the sprint-one schedule.', 3);

-- Specialised Operations (High-Impact) - AI Deploy (variant 77)
UPDATE product_content SET
  description = 'Deploy AI into your specialist operational environment, whether field service, facilities management, quality, or logistics, including predictive models, intelligent routing, and anomaly detection, with governance controls and performance monitoring active from the pilot phase.',
  positioning = 'Deploy AI into your specialist operational workflows with the governance, accuracy monitoring, and staff enablement your domain requires.',
  hero_summary = 'Deploy AI into your specialist operational environment, whether field service, facilities management, quality, or logistics, including predictive models, intelligent routing, and anomaly detection, with governance controls and performance monitoring active from the pilot phase.',
  overview_paragraphs = '["The Specialised Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled specialised operations workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for business unit & domain operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for specialised operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pilot-first approach validates accuracy in your specific operational context before full deployment","Governance and override controls configured before any AI recommendation affects an operational decision","Staff enablement programme ensures adoption rather than resistance"]'::jsonb,
  why_it_matters = '{"hook":"Specialised operational capabilities are what differentiate your organisation in complex environments.","problemParagraph":"Many AI initiatives for your specialised operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for specialised operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about deploying AI into specialist operational functions.'
WHERE variant_id = 77;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Deployed AI Models in Operational Workflows', 'Validated AI capabilities running in your operational platform, integrated into the workflows your staff use, with agreed accuracy benchmarks met before full rollout.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Governance and Override Configuration', 'Confidence thresholds, human-review queues, and audit logging active for every AI decision that affects an operational outcome.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Pilot Accuracy and Performance Report', 'Precision, recall, and throughput data from the pilot period with analysis of exception patterns and threshold recommendations for production.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (77, 'Staff Enablement Materials', 'Role-specific guidance on how to interpret AI recommendations, when to act on them, and how to escalate concerns through the override process.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'How do you validate that AI predictions are accurate enough for our operational context?', 'The pilot phase runs the model against real operational scenarios with monitoring against agreed accuracy thresholds. The DigitalQatalyst team does not move to full production until those thresholds are met.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'What if operational staff do not trust the AI recommendations?', 'The staff enablement programme explains how the model works and when its recommendations are reliable. Override controls are always available so staff remain in control.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'Can the AI models be retrained if operational conditions change?', 'Yes. The monitoring configuration includes triggers for retraining when accuracy degrades. The DigitalQatalyst team can advise on retraining cadence as part of the managed service.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (77, 'How do we get started?', 'Share your AI design specifications and the DigitalQatalyst team will confirm the pilot cohort, data pipeline requirements, and the governance prerequisites needed to begin.', 3);

-- Specialised Operations (High-Impact) - Managed (variant 78)
UPDATE product_content SET
  description = 'Ongoing managed operations for your specialist operational systems and workflows, covering platform health, data quality monitoring, user support, and monthly performance reporting so your domain function stays at operating capacity without straining internal resources.',
  positioning = 'Keep your specialist operational systems performing at capacity, with proactive monitoring and expert support when domain-specific issues arise.',
  hero_summary = 'Ongoing managed operations for your specialist operational systems and workflows, covering platform health, data quality monitoring, user support, and monthly performance reporting so your domain function stays at operating capacity without straining internal resources.',
  overview_paragraphs = '["The Specialised Operations Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve specialised operations with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for business unit & domain operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for specialised operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Domain-specific support expertise, not generic IT helpdesk coverage","Data quality monitoring included so operational decisions are based on accurate information","Quarterly review keeps the system aligned to how your function evolves over time"]'::jsonb,
  why_it_matters = '{"hook":"Specialised operational capabilities are what differentiate your organisation in complex environments.","problemParagraph":"Many organisations struggle to sustain performance across your specialised operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"specialised operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the Specialised Operations managed service.'
WHERE variant_id = 78;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Monthly Operational System Performance Report', 'Uptime, throughput, data quality metrics, and SLA adherence for your specialist operational platform, with recommended actions for the following month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Support and Incident Log', 'Documented record of every issue raised, resolution time, root cause, and recurrence prevention action taken during the month.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Change Management Assessments', 'Impact assessment for each planned change to your operational system or connected integrations, with a risk rating and recommended implementation approach.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (78, 'Quarterly Operational Review', 'A structured session with the DigitalQatalyst team to review performance trends, address emerging operational requirements, and adjust the improvement backlog.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'What does domain-specific support mean in practice?', 'The DigitalQatalyst team assigned to your function understands both the platform and the operational context. They can resolve workflow configuration issues, data quality problems, and integration failures without needing extensive briefing from your team.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'Is user training included in the managed service?', 'Training for new users onboarded to the system is included within agreed limits. Larger training programmes for significant process changes are scoped separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'How quickly are operational system issues resolved?', 'Response and resolution times are set by the SLA agreed at onboarding. Critical issues affecting operational throughput are given the highest response priority.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (78, 'How do we get started?', 'Contact the DigitalQatalyst team with your current system documentation. They will complete a health baseline audit before the first SLA period begins.', 3);

-- Enterprise Operations (High-Impact) - Assess (variant 79)
UPDATE product_content SET
  description = 'Your quarterly planning cycle finishes two weeks late. Cross-functional projects stall in approval queues nobody owns. Performance reporting takes a fortnight to produce and is already out of date by the time it reaches the COO. These are not technology problems -- they are coordination failures baked into how your enterprise operates. This one-week assessment maps those failures, names where decision rights are ambiguous, and tells you what to fix first.',
  positioning = 'Get a COO-ready view of the coordination failures slowing your enterprise down, and a sequenced plan for fixing them.',
  hero_summary = 'Your quarterly planning cycle finishes two weeks late. Cross-functional projects stall in approval queues nobody owns. Performance reporting takes a fortnight to produce and is already out of date by the time it reaches the COO. These are not technology problems -- they are coordination failures baked into how your enterprise operates. This one-week assessment maps those failures, names where decision rights are ambiguous, and tells you what to fix first.',
  overview_paragraphs = '["The Enterprise Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns a prioritised enterprise improvement roadmap.","See how enterprise operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for coos, strategy & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews enterprise operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Delivered within one week without disrupting active planning cycles -- interviews and documentation review only, no operational access required","Interview-led methodology captures coordination failures that system metrics miss","Covers operating model design, technology, and data in one integrated assessment"]'::jsonb,
  why_it_matters = '{"hook":"Enterprise operations span the systems and workflows that keep your organisation running at scale.","problemParagraph":"Many organisations coordinate enterprise operations across siloed functions, inconsistent data, and overlapping technology investments. This assessment maps operational maturity and returns a prioritised enterprise improvement roadmap.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Functional silos","description":"Operations, finance, and supply teams work from different data and priorities."},{"title":"Process fragmentation","description":"End-to-end workflows break at system and organisational boundaries."},{"title":"Unclear investment focus","description":"Transformation spend is spread without a shared enterprise view."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Enterprise priority map","description":"Leadership sees where process, data, and platform gaps matter most."},{"title":"Prioritised improvement plan","description":"Initiatives are ordered by enterprise impact and dependency."},{"title":"Investment clarity","description":"Your operations and technology leaders can fund the right fixes first."}]}}'::jsonb,
  faq_intro = 'Questions about the Enterprise Operations assessment.'
WHERE variant_id = 79;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Enterprise Operating Model Assessment', 'Documented review of planning cadences, cross-functional handoffs, decision rights, and performance visibility across your enterprise functions, with identified failures and their business impact.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Decision Rights and Coordination Gap Register', 'Every identified coordination failure and ambiguous decision right scored by impact on execution speed, with recommended ownership and resolution approach.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Prioritised Improvement Roadmap', 'Sequenced recommendations covering operating model design, technology, and data, with effort estimates and ownership assignments your COO can act on.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (79, 'Executive Briefing Pack', 'A concise summary of findings, top coordination risks, and recommended first investments formatted for COO and board-level review.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'Is this focused on technology or on how the organisation operates?', 'Both. The assessment covers operating model design, decision rights, and coordination patterns alongside the technology that enables or constrains them.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'How many functions does the assessment cover?', 'Scope is agreed at the start of the engagement. Most assessments cover COO, finance, supply chain, and IT as a minimum, with additional functions added based on priority.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'Do you benchmark our operating model against industry standards?', 'The DigitalQatalyst team uses reference models for enterprise operations to contextualise findings, though benchmarking against named competitors is not included in this engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (79, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. They will confirm the functions in scope, the stakeholders to involve, and any documentation to prepare in advance.', 3);

-- Enterprise Operations (High-Impact) - Design (variant 80)
UPDATE product_content SET
  description = 'Your assessment named the coordination failures. Now you need something the COO can bring to the business: redesigned processes that close the planning cycle gaps, a governance framework that resolves the decision rights disputes, and a decision authority matrix that tells each function what they own. This four-week design engagement produces those outputs -- changes your organisation can actually implement, not a slide deck about operating model theory.',
  positioning = 'Get the process redesigns, governance frameworks, and decision authority structures your COO needs to bring operating model change to the business.',
  hero_summary = 'Your assessment named the coordination failures. Now you need something the COO can bring to the business: redesigned processes that close the planning cycle gaps, a governance framework that resolves the decision rights disputes, and a decision authority matrix that tells each function what they own. This four-week design engagement produces those outputs -- changes your organisation can actually implement, not a slide deck about operating model theory.',
  overview_paragraphs = '["The Enterprise Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines enterprise workflows and build-ready specifications.","Turn enterprise operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for coos, strategy & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate enterprise operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Operating model design and technology specification developed together, not in isolation","Cross-functional stakeholders involved in design to prevent implementation conflict later","Governance framework and decision authority matrix included so the COO has something concrete to socialise with the business"]'::jsonb,
  why_it_matters = '{"hook":"Enterprise operations span the systems and workflows that keep your organisation running at scale.","problemParagraph":"Many organisations plan enterprise change without integrated operating models, data standards, or specifications programme teams can deliver. This design engagement defines enterprise workflows and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operating models","description":"Cross-functional processes lack shared design and accountability."},{"title":"Data and integration gaps","description":"Systems of record do not exchange information with clear contracts."},{"title":"Programme ambiguity","description":"Delivery teams lack specs for phased rollout and governance."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Integrated process designs","description":"Workflows connect functions with clear handoffs and controls."},{"title":"Enterprise standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Programme teams receive artefacts that accelerate coordinated delivery."}]}}'::jsonb,
  faq_intro = 'Questions about the Enterprise Operations design engagement.'
WHERE variant_id = 80;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Redesigned Cross-Functional Process Maps', 'Detailed to-be workflows for planning, performance review, escalation, and operational reporting, with roles, decision rights, and data flows documented for each.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Governance Framework', 'Operating model governance structure specifying decision-making forums, cadences, accountabilities, and escalation paths across enterprise functions.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Decision Authority Matrix', 'Role-level specification of what each function can decide independently, what requires cross-functional consensus, and what escalates to executive leadership.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (80, 'Platform Configuration Specification', 'Build instructions for ERP or operational platform changes required to support the redesigned processes, with data model updates and integration requirements included.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'Does the design engagement cover organisation design as well as process and technology?', 'The primary focus is process and technology design. Operating model decisions that affect team structure and reporting lines are flagged but formal organisation design is a separate workstream.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'How do you align stakeholders across multiple functions during the design?', 'Week one includes a cross-functional alignment workshop. The design is reviewed with representatives from each function in weeks two and three before sign-off in week four.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'Can the design cover a specific platform such as SAP or Oracle?', 'Yes. The DigitalQatalyst team designs to your target platform. Platform-specific expertise is confirmed during the scoping call.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (80, 'How do we get started?', 'Contact the DigitalQatalyst team with your assessment findings or a summary of the operational improvements you need to achieve. They will confirm the cross-functional stakeholders to engage from day one.', 3);

-- Enterprise Operations (High-Impact) - AI Design (variant 81)
UPDATE product_content SET
  description = 'Design AI capabilities that improve enterprise operational decisions, not just automate them, covering demand forecasting, resource optimisation, and operational risk detection, with responsible design and governance specifications for each validated use case.',
  positioning = 'Design AI capabilities that improve enterprise operational decisions, not just automate them.',
  hero_summary = 'Design AI capabilities that improve enterprise operational decisions, not just automate them, covering demand forecasting, resource optimisation, and operational risk detection, with responsible design and governance specifications for each validated use case.',
  overview_paragraphs = '["The Enterprise Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for enterprise operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for coos, strategy & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for enterprise operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Enterprise-specific responsible AI framework, not a generic policy document","Multi-system integration designed from the start so AI outputs actually reach decision-makers","Data readiness assessed before any build commitment is made"]'::jsonb,
  why_it_matters = '{"hook":"Enterprise operations span the systems and workflows that keep your organisation running at scale.","problemParagraph":"Many organisations apply AI to your enterprise operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for enterprise operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for enterprise operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about designing AI for enterprise operational decision-making.'
WHERE variant_id = 81;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'Enterprise AI Use-Case Assessment', 'Scored evaluation of AI opportunities across enterprise operational functions, ranked by strategic impact, data readiness, and responsible AI risk profile.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'Data Readiness and Architecture Report', 'Assessment of enterprise data quality, accessibility, and lineage requirements for the prioritised AI use cases, with remediation steps for gaps.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'Responsible AI Framework', 'Governance principles, bias testing approach, explainability requirements, and human oversight rules designed for your enterprise operational decision context.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (81, 'AI Integration and Workflow Specifications', 'Detailed design for how AI outputs integrate with ERP, planning, and reporting systems, with data flow diagrams, API contracts, and monitoring requirements.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'Which enterprise AI use cases tend to deliver the most operational value?', 'Demand forecasting, supply chain risk detection, capacity optimisation, and operational anomaly alerting are consistently high-value. The DigitalQatalyst team validates which apply to your operational context.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'How do you handle AI explainability for enterprise decisions?', 'Explainability requirements are defined in the responsible AI framework for each use case. Where decisions affect employees, suppliers, or customers, the framework specifies how explanations are generated and made available.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'Our enterprise data is spread across multiple ERPs and data warehouses. Can AI still work?', 'The data readiness report maps exactly what is available, where quality issues exist, and what integration work is needed. Some use cases can proceed with targeted data remediation; others may need to wait.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (81, 'How do we get started?', 'Contact the DigitalQatalyst team with your enterprise operational priorities. They will confirm the use-case discovery scope and the stakeholders to involve in week one.', 3);

-- Enterprise Operations (High-Impact) - Deploy (variant 82)
UPDATE product_content SET
  description = 'Large operating model change programmes fail for predictable reasons: adoption collapses when the new processes conflict with how people actually work, political resistance kills cross-functional changes that no single function owns, and the new governance structures do not stick without active reinforcement. This twelve-week deployment programme embeds change adoption directly into delivery -- with cross-functional programme management, per-function sign-off at each phase, and a change champion network that keeps adoption from sliding once the DigitalQatalyst team hands over.',
  positioning = 'Deploy operating model changes that stick -- with adoption built into delivery, not bolted on at the end.',
  hero_summary = 'Large operating model change programmes fail for predictable reasons: adoption collapses when the new processes conflict with how people actually work, political resistance kills cross-functional changes that no single function owns, and the new governance structures do not stick without active reinforcement. This twelve-week deployment programme embeds change adoption directly into delivery -- with cross-functional programme management, per-function sign-off at each phase, and a change champion network that keeps adoption from sliding once the DigitalQatalyst team hands over.',
  overview_paragraphs = '["The Enterprise Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed enterprise operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for coos, strategy & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated enterprise operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Change adoption embedded in every phase of delivery, not addressed only at launch","Per-function stakeholder sign-off at each phase gate prevents the political resistance that derails enterprise change programmes","Post-go-live adoption tracking included so the business can see whether the new operating model is actually taking hold"]'::jsonb,
  why_it_matters = '{"hook":"Enterprise operations span the systems and workflows that keep your organisation running at scale.","problemParagraph":"Many organisations stall between approved designs and production for your enterprise operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for enterprise operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the Enterprise Operations deployment engagement.'
WHERE variant_id = 82;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Configured Enterprise Operational Platform', 'ERP and operational system modules live in production, configured to the approved specification and accepted by cross-functional business owners at each phase gate.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Integrated Operational Data Flows', 'Tested and documented connections between ERP, data warehouse, and operational dashboards, delivering a consistent enterprise view of performance for decision-makers.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Change Champion Network and Adoption Materials', 'Trained change champions within each function, with role-specific adoption guides, FAQs, and escalation paths for the post-go-live period.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (82, 'Post-Launch Adoption and Performance Baseline', '30-day measurement of process adherence, governance forum participation, and operational visibility metrics to evidence adoption and establish the improvement baseline.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'How do you manage cross-functional stakeholder alignment during a twelve-week build?', 'The sprint plan includes fortnightly review sessions with cross-functional business owners. Change impact is tracked and communicated as configuration decisions are made.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'What if our ERP does not support the configuration changes in the design?', 'Weeks one to two include a technical feasibility review. Any gaps between the design and platform capability are surfaced early with options: alternative configuration, middleware, or design adjustment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'How do you handle data migration from legacy operational systems?', 'Data migration scope is confirmed in weeks one to two. The DigitalQatalyst team designs the migration approach, validates data quality, and runs reconciliation checks before go-live.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (82, 'How do we get started?', 'Provide your approved design specification and the DigitalQatalyst team will confirm environment access, migration scope, and the sprint-one schedule with your cross-functional leads.', 3);

-- Enterprise Operations (High-Impact) - AI Deploy (variant 83)
UPDATE product_content SET
  description = 'Put AI-driven decision support into your enterprise operational workflows, including demand forecasting models, supply chain risk detection, and operational anomaly alerting, with governance controls and executive visibility built in from day one of a twelve-week deployment.',
  positioning = 'Put AI-driven decision support into your enterprise operational workflows, with the governance and accuracy monitoring that enterprise risk requires.',
  hero_summary = 'Put AI-driven decision support into your enterprise operational workflows, including demand forecasting models, supply chain risk detection, and operational anomaly alerting, with governance controls and executive visibility built in from day one of a twelve-week deployment.',
  overview_paragraphs = '["The Enterprise Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled enterprise operations workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for coos, strategy & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for enterprise operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pilot-first deployment validates accuracy in your operational context before enterprise rollout","Explainability built into every model output so managers can make informed decisions","Executive governance dashboard included so AI performance is visible to leadership"]'::jsonb,
  why_it_matters = '{"hook":"Enterprise operations span the systems and workflows that keep your organisation running at scale.","problemParagraph":"Many AI initiatives for your enterprise operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for enterprise operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about deploying AI decision support into enterprise operations.'
WHERE variant_id = 83;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'Deployed Forecasting and Risk Detection Models', 'AI models running in production and integrated into your planning and operational systems, validated against agreed accuracy thresholds during the pilot phase.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'Operational Risk Alert Configuration', 'Alert rules, escalation routing, and notification templates configured for supply chain and operational risk scenarios, tested against historical data before go-live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'AI Explainability Layer', 'Explanation outputs accompanying every AI recommendation, formatted for the operational managers who will act on or override them.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (83, 'Executive AI Governance Dashboard', 'Live view of model accuracy, override rates, alert volumes, and decision outcomes across enterprise functions, handed over with trained dashboard administrators.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'How do you validate forecasting accuracy before full production rollout?', 'During the pilot phase, forecasts are run against historical data and compared to actual outcomes. The DigitalQatalyst team sets accuracy targets at kickoff and does not proceed to full rollout until they are met.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'What if enterprise leaders override AI recommendations frequently?', 'Override rates are tracked in the governance dashboard. High override rates trigger a review of confidence thresholds and model assumptions with the DigitalQatalyst team.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'How does the AI handle unexpected events that fall outside its training data?', 'Model confidence scores drop for out-of-distribution scenarios, triggering human review rather than automated action. The governance framework defines the escalation path for these situations.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (83, 'How do we get started?', 'Share your AI design specifications and data pipeline documentation with the DigitalQatalyst team. They will confirm model configuration prerequisites and the pilot cohort before work begins.', 3);

-- Enterprise Operations (High-Impact) - Managed (variant 84)
UPDATE product_content SET
  description = 'Ongoing managed operations for your enterprise operational platforms and AI capabilities, covering system health monitoring, model performance tracking, operational reporting, and continuous improvement to keep your enterprise operating model performing as your business evolves.',
  positioning = 'Keep your enterprise operational systems and AI capabilities running at the performance levels your business depends on.',
  hero_summary = 'Ongoing managed operations for your enterprise operational platforms and AI capabilities, covering system health monitoring, model performance tracking, operational reporting, and continuous improvement to keep your enterprise operating model performing as your business evolves.',
  overview_paragraphs = '["The Enterprise Operations Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve enterprise operations with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for coos, strategy & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for enterprise operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["AI model accuracy tracked monthly and recalibrated before drift affects operational decisions","Proactive ERP change impact assessment prevents unexpected system breakage","Quarterly roadmap reviews keep the enterprise operational estate aligned to business strategy"]'::jsonb,
  why_it_matters = '{"hook":"Enterprise operations span the systems and workflows that keep your organisation running at scale.","problemParagraph":"Many organisations struggle to sustain performance across your enterprise operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"enterprise operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the Enterprise Operations managed service.'
WHERE variant_id = 84;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'Monthly Enterprise Operations Report', 'System uptime, data quality metrics, AI model accuracy, and SLA adherence across your enterprise operational estate, with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'AI Model Performance Review', 'Monthly accuracy and drift analysis for each AI model in production, with threshold recalibration recommendations and retraining triggers where needed.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'Change Impact Assessments', 'Assessment of every planned ERP update, data model change, or operational process change for impact on platform configuration and AI model performance.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (84, 'Quarterly Enterprise Roadmap Review', 'A structured session with the DigitalQatalyst team to review operational performance trends, prioritise improvement initiatives, and align the backlog to business priorities.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'What does AI model maintenance involve on an ongoing basis?', 'Monthly accuracy reviews compare model outputs against actual outcomes. When accuracy drifts below threshold, the DigitalQatalyst team initiates recalibration or retraining and documents the change.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'How do you handle major ERP upgrades under the managed service?', 'The DigitalQatalyst team assesses every planned ERP upgrade for impact on configuration, integrations, and AI data pipelines, providing a remediation plan before the upgrade lands.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'Can we add new operational capabilities under the managed service?', 'Minor enhancements are included within capacity. Significant new capabilities are scoped as separate engagements and discussed in the quarterly roadmap review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (84, 'How do we get started?', 'Contact the DigitalQatalyst team with your current platform and AI estate documentation. They will complete a health baseline before the first SLA period begins.', 3);

-- Governance, Risk & Compliance (High-Impact) - Assess (variant 85)
UPDATE product_content SET
  description = 'Map your governance, risk, and compliance posture against the controls that matter most, and leave with a prioritised remediation plan your board can sign off.',
  positioning = 'See where compliance gaps create real exposure, then fix the highest-risk ones first.',
  hero_summary = 'Map your governance, risk, and compliance posture against the controls that matter most, and leave with a prioritised remediation plan your board can sign off.',
  overview_paragraphs = '["The Governance, Risk & Compliance Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps governance maturity and returns prioritised improvements your risk and compliance leaders can act on.","See how governance, risk and compliance perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for risk, compliance, audit & legal leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews governance, risk & compliance across governance, risk, and platform reliability.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope, no-obligation assessment completed within one week","Framework-aligned to ISO 27001, NIST CSF, SOC 2, or your target standard","Board-ready findings delivered before the engagement closes"]'::jsonb,
  why_it_matters = '{"hook":"Governance and compliance are not overhead, they are what makes sustainable transformation possible.","problemParagraph":"Many organisations run GRC programmes with informal controls, inconsistent policy application, and limited visibility into risk exposure. This assessment maps governance maturity and returns prioritised improvements your risk and compliance leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Informal controls","description":"Policies exist on paper but are not consistently applied in operations."},{"title":"Fragmented risk view","description":"Teams track issues in spreadsheets without a single assurance picture."},{"title":"Compliance blind spots","description":"Regulatory and audit requirements are not mapped to live processes."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Shared GRC maturity view","description":"Leadership sees where controls, risk, and compliance posture stand today."},{"title":"Prioritised remediation plan","description":"Gaps are ordered by regulatory exposure, impact, and feasibility."},{"title":"Investment clarity","description":"Your assurance leaders can fund the right control improvements first."}]}}'::jsonb,
  faq_intro = 'Common questions about the Governance, Risk and Compliance assessment.'
WHERE variant_id = 85;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Control gap assessment', 'Every in-scope control rated against your target framework, with evidence reviewed and specific gaps documented for remediation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Scored risk register', 'Risks ranked by likelihood and business impact so the highest-exposure items receive attention before lower-priority ones.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Prioritised remediation roadmap', 'Sequenced actions with named owners, effort estimates, and dependencies your teams can execute against in the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (85, 'Board-ready executive summary', 'A concise read on current exposure, priority actions, and recommended investment framed for non-technical stakeholders.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'Which compliance frameworks do you assess against?', 'ISO 27001, NIST CSF, SOC 2 Type II, and sector-specific standards such as PCI DSS and HIPAA. The DigitalQatalyst team confirms the target framework during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'What access do you need to our systems?', 'The assessment runs on documentation, policy evidence, and stakeholder interviews. If read-only access to a specific tool would accelerate evidence collection, we agree the exact scope with your IT security team in advance -- it is never a requirement to proceed.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'How quickly will we see results?', 'The full assessment, scored risk register, and remediation roadmap are delivered within one week of the engagement starting.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'Can the roadmap feed directly into our next budget cycle?', 'Yes. The roadmap includes effort estimates and business impact scores formatted to support prioritisation conversations with finance and leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (85, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm scope, target framework, and stakeholders before any work begins.', 4);

-- Governance, Risk & Compliance (High-Impact) - Design (variant 86)
UPDATE product_content SET
  description = 'Turn your compliance goals and risk appetite into a fully specified GRC operating model, with process designs, control architectures, and implementation blueprints your delivery teams can build against.',
  positioning = 'A delivery-ready GRC blueprint: operating model, controls architecture, and integration specifications in four weeks.',
  hero_summary = 'Turn your compliance goals and risk appetite into a fully specified GRC operating model, with process designs, control architectures, and implementation blueprints your delivery teams can build against.',
  overview_paragraphs = '["The Governance, Risk & Compliance Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines GRC operating models and build-ready specifications.","Turn governance, risk and compliance goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for risk, compliance, audit & legal leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate governance, risk & compliance requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Operating model and controls architecture tailored to your risk profile","Build-ready specifications so deployment begins without rework","Adoption plan included to accelerate stakeholder uptake"]'::jsonb,
  why_it_matters = '{"hook":"Governance and compliance are not overhead, they are what makes sustainable transformation possible.","problemParagraph":"Many organisations update policies without designed control frameworks, workflows, or specifications assurance teams can operationalise. This design engagement defines GRC operating models and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined control frameworks","description":"Policies are not translated into testable controls and workflows."},{"title":"Inconsistent assurance processes","description":"Testing, evidence, and remediation vary by team and system."},{"title":"Platform ambiguity","description":"Teams lack specs for GRC tooling, data, and reporting integration."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Designed control models","description":"Frameworks connect policy to operational controls and owners."},{"title":"Consistent assurance standards","description":"Testing, evidence, and escalation rules are defined upfront."},{"title":"Implementation-ready specs","description":"Teams receive artefacts that accelerate governed GRC operations."}]}}'::jsonb,
  faq_intro = 'Key questions about the Governance, Risk and Compliance design engagement.'
WHERE variant_id = 86;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'GRC operating model', 'Defined roles, accountabilities, governance cadences, and escalation paths for ongoing risk and compliance operations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'Controls architecture', 'Specified controls mapped to gaps from assessment, with automation points, tooling choices, and integration requirements documented.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'Process and workflow designs', 'End-to-end workflow diagrams and process specifications for risk identification, compliance monitoring, and incident response.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (86, 'Build handover package', 'Complete implementation specifications, data requirements, acceptance criteria, and an adoption plan ready for a deployment team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'Do we need to have completed an assessment first?', 'An assessment is strongly recommended as it informs the design priorities. If you have existing audit findings or a gap analysis, the DigitalQatalyst team can use those as the starting point.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'Which GRC platforms do you design for?', 'We design platform-agnostic specifications and can align to ServiceNow GRC, Microsoft Purview, Archer, or your preferred tooling. Platform selection is confirmed during week one.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'How involved does our team need to be?', 'We run focused workshops in weeks one and three. Between sessions your team reviews drafts and provides feedback. We handle the documentation and specification work.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'What happens after the design is signed off?', 'The handover package goes directly to a deployment team, either your internal resources or the DigitalQatalyst team through a Deploy engagement.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (86, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team will review your objectives and any existing assessment findings before the engagement kicks off.', 4);

-- Governance, Risk & Compliance (High-Impact) - AI Design (variant 87)
UPDATE product_content SET
  description = 'Identify where AI can strengthen your GRC capability, validate those use cases against data, regulatory, and ethical requirements, and produce deployment-ready specifications before any build investment is committed.',
  positioning = 'AI-powered GRC starts here: validated use cases, responsible workflows, and specifications ready to build.',
  hero_summary = 'Identify where AI can strengthen your GRC capability, validate those use cases against data, regulatory, and ethical requirements, and produce deployment-ready specifications before any build investment is committed.',
  overview_paragraphs = '["The Governance, Risk & Compliance AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for governance, risk and compliance, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for risk, compliance, audit & legal leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for governance, risk & compliance.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use cases validated before any build budget is committed","Responsible AI assessment built into every specification","Guardrails and human-in-the-loop controls defined from the outset"]'::jsonb,
  why_it_matters = '{"hook":"Governance and compliance are not overhead, they are what makes sustainable transformation possible.","problemParagraph":"Many organisations apply AI to your GRC programme without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for governance, risk & compliance lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for governance, risk & compliance are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about AI design for Governance, Risk and Compliance.'
WHERE variant_id = 87;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'AI use-case register', 'Validated list of AI applications for GRC, each assessed for feasibility, data readiness, regulatory compatibility, and expected value.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'Responsible AI assessment', 'Documented findings on bias risk, data quality, explainability obligations, and regulatory constraints for each prioritised use case.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'AI workflow designs', 'Process specifications showing how AI outputs integrate into risk identification, compliance monitoring, and incident escalation workflows.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (87, 'Deployment specification package', 'Technical and governance requirements for each use case: model criteria, human-in-the-loop controls, monitoring thresholds, and audit logging.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'What kinds of AI use cases typically emerge in GRC?', 'Common validated use cases include continuous control monitoring, anomaly detection in transaction data, automated regulatory change alerts, and AI-assisted policy review. The DigitalQatalyst team works with your context to identify which apply.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'How do you handle regulatory constraints on AI in compliance functions?', 'The responsible AI assessment covers applicable regulations, including explainability requirements under GDPR, sector-specific AI rules, and your own internal AI policy. Constraints are documented in the deployment spec.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'What data do you need access to during the design?', 'Primarily data inventories, schema documentation, and sample datasets for feasibility assessment. No production data is required; the design phase works from specifications.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'Can we run this without a prior GRC assessment?', 'Yes, though an assessment or existing gap analysis makes the use-case prioritisation more precise. The DigitalQatalyst team will review available materials during scoping.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (87, 'How do we get started?', 'Contact the DigitalQatalyst team to arrange a scoping call covering your current GRC tooling, data landscape, and AI objectives.', 4);

-- Governance, Risk & Compliance (High-Impact) - Deploy (variant 88)
UPDATE product_content SET
  description = 'Configure, integrate, test, and launch your GRC capability across the agreed scope, with staged testing and signed acceptance criteria at every phase and a controlled handover that leaves your operations team ready to run.',
  positioning = 'From design to live GRC operations: configured controls, integrated systems, and a tested, handed-over capability.',
  hero_summary = 'Configure, integrate, test, and launch your GRC capability across the agreed scope, with staged testing and signed acceptance criteria at every phase and a controlled handover that leaves your operations team ready to run.',
  overview_paragraphs = '["The Governance, Risk & Compliance Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed governance, risk and compliance changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for risk, compliance, audit & legal leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated governance, risk & compliance assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Twelve-week phased delivery with named milestones and stakeholder checkpoints","Testing evidence pack suitable for internal audit and regulator review","Hypercare period included so operations teams are not left unsupported at go-live"]'::jsonb,
  why_it_matters = '{"hook":"Governance and compliance are not overhead, they are what makes sustainable transformation possible.","problemParagraph":"Many organisations stall between approved designs and production for your GRC programme, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for governance, risk & compliance sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying a Governance, Risk and Compliance capability.'
WHERE variant_id = 88;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Configured GRC platform', 'Your chosen GRC tooling fully configured to your control framework, risk taxonomy, and reporting requirements, with all agreed integrations live.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Integration and data pipeline documentation', 'Documented connections between GRC platform and upstream data sources, with data flow diagrams and monitoring configurations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Testing evidence pack', 'Full test results across functional, integration, and user acceptance phases, with defect resolution records for audit and assurance purposes.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (88, 'Operational handover package', 'Runbooks, administrator guides, user training materials, and a hypercare plan so your team can operate the GRC capability independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'Which GRC platforms can you deploy and configure?', 'ServiceNow GRC, Microsoft Purview Compliance, RSA Archer, LogicGate, and other leading platforms. The DigitalQatalyst team confirms platform fit during pre-deployment scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'How do you manage integration with our existing data sources?', 'Integration requirements are scoped in the first three weeks. The team builds and tests connections to HR, IT, financial, and operational data sources as agreed in the design specifications.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'What does the hypercare period cover?', 'Hypercare runs for two weeks post-launch and includes daily check-ins, priority defect resolution, and on-call support for your compliance and operations teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'What if we do not have a completed design?', 'A design specification is a prerequisite for deployment. The DigitalQatalyst team can run a condensed design phase before committing to the deployment schedule.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (88, 'How do we get started?', 'Provide your design specification or assessment findings and the DigitalQatalyst team will scope the deployment timeline and resource requirements within five working days.', 4);

-- Governance, Risk & Compliance (High-Impact) - AI Deploy (variant 89)
