INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'Production AI deployment', 'Approved models live in your workforce management platform with data pipelines, override controls, and logging in place.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'Model performance dashboard', 'Real-time view of scheduling accuracy, forecast error rates, fairness indicators, and alert thresholds for your operations team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'Override and escalation playbook', 'Step-by-step procedures for managers when AI recommendations need to be overridden, and when to escalate to the DigitalQatalyst team.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (101, 'AI governance handover pack', 'Model cards, data lineage documentation, retraining schedule, and accountability assignments for ongoing responsible operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'What happens if a model starts performing poorly after launch?', 'Monitoring dashboards alert the DigitalQatalyst team and your operations leads. Retraining or rollback procedures are defined in the governance handover pack.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'Can managers override AI scheduling recommendations?', 'Yes. Override workflows are embedded in the scheduling tool. All overrides are logged for quality review and model improvement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'How do you handle regulatory requirements around automated workforce decisions?', 'Accountability, explainability, and human oversight controls are designed into the deployment. We confirm applicable obligations during scoping.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (101, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment and pilot cohort.', 3);

-- Workforce Management (High-Impact) - Managed (variant 102)
UPDATE product_content SET
  description = 'Keep your workforce management platform performing at pace with your business: SLA-backed scheduling system operations, monthly performance reporting, and ongoing optimisation as your workforce grows or changes.',
  positioning = 'Ongoing management of your workforce management platform so scheduling accuracy and visibility never degrade.',
  hero_summary = 'Keep your workforce management platform performing at pace with your business: SLA-backed scheduling system operations, monthly performance reporting, and ongoing optimisation as your workforce grows or changes.',
  overview_paragraphs = '["The Workforce Management Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve workforce management with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for hr, workforce planning & operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for workforce management - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed operations with defined incident response times","Monthly reporting and quarterly optimisation included as standard","Configuration updates covered as workforce structures evolve"]'::jsonb,
  why_it_matters = '{"hook":"Workforce systems shape how you deploy talent, manage capacity, and respond to demand.","problemParagraph":"Many organisations struggle to sustain performance across your workforce systems after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"workforce management issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the workforce management managed service.'
WHERE variant_id = 102;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Monthly performance report', 'Scheduling fill rates, overtime trends, absenteeism patterns, and system health metrics with commentary and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Incident and change log', 'Transparent record of all incidents, configuration changes, and SLA performance across the reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Quarterly optimisation review', 'Analysis of workforce trends, platform capability gaps, and prioritised improvement actions for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (102, 'Annual workforce management roadmap', 'Forward-looking plan covering platform updates, capability additions, and structural changes needed to support business growth.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'What is covered under the managed service?', 'Platform monitoring, incident response, configuration changes, monthly reporting, and quarterly optimisation reviews. Scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'What SLAs apply?', 'Response and resolution times are agreed during onboarding based on the criticality of your scheduling operations. Typical targets range from 4-hour response for critical incidents to next-business-day for low-priority items.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'Can we add new workforce categories or locations over time?', 'Yes. Configuration updates for new sites, roles, or scheduling rules are included within agreed change volumes. Larger changes are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (102, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the platform in scope, current configuration baseline, and SLA requirements before the service agreement is drafted.', 3);

-- Enterprise Data Platform (High-Impact) - Assess (variant 103)
UPDATE product_content SET
  description = 'Pinpoint the architecture weaknesses, governance gaps, and pipeline failures holding your data platform back from becoming a trusted enterprise asset, and leave with a scored maturity view and prioritised roadmap your CDO and engineering leads can act on immediately.',
  positioning = 'Pinpoint the data quality, governance, and architecture gaps blocking your platform from becoming a trusted enterprise asset.',
  hero_summary = 'Pinpoint the architecture weaknesses, governance gaps, and pipeline failures holding your data platform back from becoming a trusted enterprise asset, and leave with a scored maturity view and prioritised roadmap your CDO and engineering leads can act on immediately.',
  overview_paragraphs = '["The Enterprise Data Platform Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps maturity and returns a prioritised roadmap for a trusted enterprise data platform.","See how enterprise data platform performs today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement maps your data maturity across governance, quality, platform readiness, and pipeline gaps.","You receive a prioritised roadmap for a scalable enterprise data platform your leadership team can act on."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment completed within one week, no build commitment required","Covers architecture, data quality, lineage, and governance in a single engagement","Output calibrated for both technical leads and executive sponsors"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations hold data across siloed systems with inconsistent quality, weak governance, and pipelines that cannot scale. This assessment maps maturity and returns a prioritised roadmap for a trusted enterprise data platform.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Inconsistent data quality","description":"Reports conflict because definitions and ownership are unclear."},{"title":"Governance gaps","description":"Access, lineage, and stewardship are informal or absent."},{"title":"Platform scaling risk","description":"Pipelines and architecture cannot support analytics or AI at scale."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Shared maturity view","description":"Leadership sees where governance, quality, and platform readiness stand today."},{"title":"Prioritised platform roadmap","description":"Initiatives are ordered by impact, dependency, and feasibility."},{"title":"Investment clarity","description":"Your data and technology leaders can fund the right fixes first."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform assessment.'
WHERE variant_id = 103;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Data platform maturity scorecard', 'A domain-by-domain rating of ingestion, transformation, storage, and consumption layers, with evidence for each score.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Gap and root-cause register', 'Every identified gap mapped to its root cause, the business risk it carries, and the effort band required to close it.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Prioritised roadmap', 'A sequenced action plan with owners, dependencies, and effort estimates so your teams can start closing the highest-risk gaps immediately.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (103, 'Executive summary pack', 'A concise board-ready presentation covering current state, priority findings, and recommended investment.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'What do you review during the assessment?', 'The DigitalQatalyst team reviews your ingestion pipelines, storage architecture, transformation logic, data quality controls, lineage tooling, and governance policies. We focus on what is actually in place, not what is documented.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'Do you need access to production systems?', 'We work primarily from architecture diagrams, pipeline configurations, and stakeholder interviews. Any read-only access to tooling is agreed upfront and scoped to the minimum needed.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'What if we are mid-way through a migration?', 'That is common. We assess your current and target state together so the roadmap accounts for in-flight work and avoids duplicating effort.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will align on scope, confirm the relevant stakeholders, and agree a kick-off date before any work begins.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (103, 'What does the roadmap look like?', 'A sequenced list of prioritised actions, each with an owner role, an effort band (days of work), key dependencies, and a recommended delivery sequence.', 4);

-- Enterprise Data Platform (High-Impact) - Design (variant 104)
UPDATE product_content SET
  description = 'Turn your enterprise data platform goals into an architecture blueprint, data model specifications, and a governance framework your engineering teams can build against with confidence.',
  positioning = 'Go from data platform ambition to build-ready specifications: architecture, contracts, governance, and an adoption plan in one engagement.',
  hero_summary = 'Turn your enterprise data platform goals into an architecture blueprint, data model specifications, and a governance framework your engineering teams can build against with confidence.',
  overview_paragraphs = '["The Enterprise Data Platform Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines data platform blueprints and build-ready specifications.","Turn enterprise data platform goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate enterprise data platform requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Architecture validated against your existing technology investments and team capabilities","Governance design integrated into the architecture, not bolted on afterwards","Build plan ready to hand directly to your delivery squads"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations plan data platforms without aligned architecture, governance models, or specifications engineering teams can build against. This design engagement defines data platform blueprints and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined platform architecture","description":"Ingestion, storage, and consumption patterns are not designed coherently."},{"title":"Governance design gaps","description":"Catalogues, lineage, and access models lack operational detail."},{"title":"Build ambiguity","description":"Engineering teams lack specs for pipelines, APIs, and platform services."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned platform designs","description":"Architecture reflects analytics, AI, and operational data needs."},{"title":"Governance standards","description":"Ownership, quality, and access rules are defined upfront."},{"title":"Implementation-ready specs","description":"Engineering receives artefacts that accelerate platform delivery."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform design engagement.'
WHERE variant_id = 104;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Target-state architecture blueprint', 'A detailed diagram and narrative covering each platform layer, technology choices, and the rationale for each decision.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Canonical data model and domain definitions', 'Domain-level entity definitions, ownership assignments, and the data contracts your teams will build to.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Governance and quality framework', 'Policies, tooling recommendations, and process designs for lineage tracking, cataloguing, access control, and quality measurement.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (104, 'Phased build and adoption plan', 'A sequenced delivery roadmap with team roles, sprint milestones, and a change management guide to drive adoption across data consumers.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'Do you design for a specific cloud provider or technology stack?', 'The DigitalQatalyst team designs for your chosen stack. We are fluent across the major cloud data platforms and will work within your existing technology constraints or help you select where the choice is still open.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'How much input does our team need to provide?', 'We run structured workshops in weeks one and two. Your data engineers, architects, and domain leads will need half-day availability across those sessions. We handle the synthesis and design work between workshops.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'What is a data contract and why does it matter?', 'A data contract is a formal agreement between a data producer and its consumers specifying schema, quality guarantees, and SLAs. It prevents the silent breaking changes that erode trust in platform data.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'Does the design include a migration plan if we are replacing a legacy system?', 'Yes. Where a legacy system is in scope, the architecture blueprint includes a migration strategy covering data extraction, transformation, parallel running, and cutover.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (104, 'How do we get started?', 'Contact the DigitalQatalyst team to discuss your platform goals. We will confirm scope, identify the right stakeholders, and propose a kick-off schedule.', 4);

-- Enterprise Data Platform (High-Impact) - AI Design (variant 105)
UPDATE product_content SET
  description = 'Identify the highest-value AI use cases your data platform can reliably support, validate their feasibility, and leave with responsible workflow designs and deployment-ready specifications before any build investment is committed.',
  positioning = 'Validate which AI capabilities your data platform can reliably support, and leave with responsible workflow designs your team can build without reinventing guardrails.',
  hero_summary = 'Identify the highest-value AI use cases your data platform can reliably support, validate their feasibility, and leave with responsible workflow designs and deployment-ready specifications before any build investment is committed.',
  overview_paragraphs = '["The Enterprise Data Platform AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for enterprise data platform, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for enterprise data platform.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use cases selected based on your actual data assets, not aspirational scenarios","Ethics and responsibility considerations built into each workflow design","Specifications include monitoring and drift detection from the outset"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations apply AI to your enterprise data platform without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for enterprise data platform lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for enterprise data platform are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform AI design engagement.'
WHERE variant_id = 105;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'AI use-case prioritisation matrix', 'Each candidate use case scored on data readiness, technical complexity, business value, and risk, with a clear build-or-defer recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'Responsible AI workflow designs', 'End-to-end workflow diagrams for each prioritised use case, including bias controls, explainability hooks, and human-in-the-loop decision points.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'Data readiness gap report', 'A precise list of the data quality, coverage, and lineage gaps that must be resolved before each use case can proceed to build.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (105, 'Deployment-ready AI specifications', 'Feature pipeline definitions, model requirements, inference architecture, and monitoring specifications your engineering team can build against.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'How do you decide which AI use cases to prioritise?', 'The DigitalQatalyst team scores each candidate against four factors: data readiness, technical feasibility, business value, and governance risk. Only use cases that score above a defined threshold proceed to full specification.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'What does responsible AI mean in practice for a data platform?', 'It means designing bias detection into training pipelines, defining explainability requirements before model selection, and specifying the human review points where an automated decision must be checked before acting.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'Do we need an existing ML platform to begin?', 'No. If you do not have an ML platform, the specifications will include platform requirements. If you do, we design within your existing tooling.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (105, 'How do we get started?', 'Reach out to the DigitalQatalyst team with your candidate use cases or business problems. We will assess your starting position and propose a scoped engagement.', 3);

-- Enterprise Data Platform (High-Impact) - Deploy (variant 106)
UPDATE product_content SET
  description = 'Configure, integrate, and launch your enterprise data platform with sprint-gated quality assurance, full pipeline testing, and a clean handover to your operations and data engineering teams, within a fixed twelve-week programme.',
  positioning = 'Move from approved architecture to a live, tested data platform, with every pipeline validated, every integration confirmed, and your team ready to operate it.',
  hero_summary = 'Configure, integrate, and launch your enterprise data platform with sprint-gated quality assurance, full pipeline testing, and a clean handover to your operations and data engineering teams, within a fixed twelve-week programme.',
  overview_paragraphs = '["The Enterprise Data Platform Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed enterprise data platform changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated enterprise data platform assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Pipeline acceptance criteria agreed before build begins, so there is no ambiguity at launch","Parallel running period built in to confirm data fidelity before full cutover","Runbooks and handover materials produced as part of the engagement, not as an afterthought"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations stall between approved designs and production for your enterprise data platform, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for enterprise data platform sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform deployment engagement.'
WHERE variant_id = 106;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Configured and tested data platform', 'A fully provisioned platform environment with all agreed pipelines live, tested against acceptance criteria, and confirmed ready for production traffic.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Integration test results and sign-off', 'Test evidence covering each source-to-destination data flow, with defects resolved and results signed off by your technical lead.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Operations runbook set', 'Step-by-step runbooks for pipeline monitoring, incident triage, scheduled maintenance, and common failure scenarios.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (106, 'Handover and knowledge transfer pack', 'Session recordings, architecture documentation, and a competency checklist confirming your team can operate the platform independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'What does the knowledge transfer programme involve in practice?', 'Your operations and engineering teams join live sessions covering platform monitoring, pipeline triage, and incident response. They receive runbooks, architecture documentation, and a sign-off checklist before the DigitalQatalyst team steps back.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'How do you handle data quality during migration?', 'We define acceptance criteria for each pipeline before build. During testing, every pipeline output is validated against those criteria. Any deviation is classified and resolved before that pipeline goes live.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'What if a source system integration is more complex than expected?', 'Scope changes are assessed formally. The DigitalQatalyst team will identify the impact on timeline and budget and agree any adjustment with you before proceeding.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (106, 'How do we get started?', 'The deployment engagement follows directly from a completed design. Share your architecture blueprint with the DigitalQatalyst team and we will confirm scope, resourcing, and a kick-off date.', 3);

-- Enterprise Data Platform (High-Impact) - AI Deploy (variant 107)
UPDATE product_content SET
  description = 'Put your designed AI capabilities into production on the enterprise data platform with governance controls, drift monitoring, and safety checks built in from the first day of operation.',
  positioning = 'Launch AI models on your data platform the right way: governed, monitored, and production-hardened before your business depends on them.',
  hero_summary = 'Put your designed AI capabilities into production on the enterprise data platform with governance controls, drift monitoring, and safety checks built in from the first day of operation.',
  overview_paragraphs = '["The Enterprise Data Platform AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled enterprise data platform workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for enterprise data platform with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Governance and monitoring configured before go-live, not retrofitted after an incident","Rollback capability tested and confirmed before any model goes live in production","Handover includes retraining triggers and a model lifecycle management guide"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many AI initiatives for your enterprise data platform fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for enterprise data platform fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform AI deployment engagement.'
WHERE variant_id = 107;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Production AI deployment', 'AI models serving live predictions via governed endpoints, with version control, rollback capability, and environment isolation confirmed working.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Monitoring and alerting configuration', 'Drift detection, performance dashboards, and alert thresholds configured so your team knows immediately when a model needs attention.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'Governance and audit controls', 'Audit logs, prediction traceability records, and access control configurations meeting your compliance and responsible AI requirements.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (107, 'ML operations handover pack', 'Incident playbooks, retraining triggers, monitoring guides, and a sign-off checklist confirming your ML team can operate and maintain the models independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'What does model drift monitoring look like?', 'We configure statistical checks on input feature distributions and prediction output distributions. When either drifts beyond agreed thresholds, your team receives an alert and the incident playbook tells them what to investigate first.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'How do you handle model versioning in production?', 'Every model version is tagged, stored in a model registry, and deployed with a documented rollback path. Promoting a new version requires a passing validation suite, so production is never overwritten without evidence.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'What if a model underperforms in production?', 'The incident playbook covers this. Your team can roll back to the previous version immediately. The DigitalQatalyst team will support a root-cause review if the underperformance is not explained by drift.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (107, 'How do we get started?', 'The AI deployment engagement follows from a completed AI design. Share your deployment specifications with the DigitalQatalyst team and we will confirm scope, ML infrastructure requirements, and a timeline.', 3);

-- Enterprise Data Platform (High-Impact) - Managed (variant 108)
UPDATE product_content SET
  description = 'Keep your enterprise data platform running, governed, and improving every month, with SLA-backed pipeline monitoring, incident response, data quality reporting, and continuous optimisation by the DigitalQatalyst team.',
  positioning = 'Keep your data platform trusted and performant every month, with proactive monitoring, rapid incident resolution, and a continuous improvement cycle built into the service.',
  hero_summary = 'Keep your enterprise data platform running, governed, and improving every month, with SLA-backed pipeline monitoring, incident response, data quality reporting, and continuous optimisation by the DigitalQatalyst team.',
  overview_paragraphs = '["The Enterprise Data Platform Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve enterprise data platform with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cdos, cios, data & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for enterprise data platform - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed incident response with defined detection and resolution time targets","Monthly quality reporting gives leadership a consistent view of platform health","Optimisation reviews prevent cost and performance drift over time"]'::jsonb,
  why_it_matters = '{"hook":"Your data platform is the foundation for reporting, analytics, automation, and every AI initiative you pursue.","problemParagraph":"Many organisations struggle to sustain performance across your enterprise data platform after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"enterprise data platform issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise Data Platform managed service.'
WHERE variant_id = 108;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Monthly data quality report', 'A scored view of platform data quality across completeness, accuracy, freshness, and lineage, with trend analysis and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Incident log and resolution record', 'A complete log of every pipeline incident, the time to detect and resolve, the root cause, and the preventive action taken.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Quarterly performance and cost review', 'An analysis of platform query performance, compute and storage costs, and the optimisations applied or recommended for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (108, 'Governance compliance summary', 'A periodic report confirming that access controls, lineage coverage, and data retention policies remain compliant with your governance framework.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'What SLAs apply to the managed service?', 'SLAs are agreed during onboarding and typically cover time to detect a pipeline failure, time to notify, and time to resolve by severity level. Your account is reviewed against these targets in the monthly report.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'What happens when a pipeline fails?', 'The DigitalQatalyst team receives an alert, assesses severity, and begins remediation within the agreed response window. You are notified immediately and kept updated until resolution.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'Can we request changes or new pipelines under the managed service?', 'Yes. Change requests are scoped and delivered within the service. Larger changes that exceed the included capacity are quoted separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (108, 'How do we get started?', 'The managed service typically follows a completed deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs, and schedule the onboarding period.', 3);

-- Business Intelligence & Analytics (High-Impact) - Assess (variant 109)
UPDATE product_content SET
  description = 'Surface the data, tooling, and governance gaps that limit management visibility and leave key decisions relying on spreadsheets rather than trusted reports, and leave with a prioritised plan to close what matters most to your decision-makers.',
  positioning = 'Find out exactly where your BI and analytics capability falls short, and leave with a prioritised plan to close the gaps that matter most to your decision-makers.',
  hero_summary = 'Surface the data, tooling, and governance gaps that limit management visibility and leave key decisions relying on spreadsheets rather than trusted reports, and leave with a prioritised plan to close what matters most to your decision-makers.',
  overview_paragraphs = '["The Business Intelligence & Analytics Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps analytics maturity and returns prioritised improvements your data and business leaders can act on.","See how business intelligence and analytics perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews business intelligence & analytics across data, analytics, and intelligent automation.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Covers tooling, data quality, KPI definitions, and governance in a single assessment week","Decision-gap register connects BI improvements directly to business outcomes","No commitment to further work required to receive the full findings pack"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many organisations invest in dashboards without trusted metrics, consistent definitions, or adoption across leadership. This assessment maps analytics maturity and returns prioritised improvements your data and business leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Metric inconsistency","description":"Teams debate numbers because KPIs are defined differently across functions."},{"title":"Low report adoption","description":"Dashboards exist but do not drive decisions in planning and operations."},{"title":"Data trust issues","description":"Source quality and lineage are unclear for critical business metrics."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Analytics priority map","description":"You know which metrics, models, and platforms to fix first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, data, and investment decisions."},{"title":"Leadership-ready roadmap","description":"Recommendations support governed analytics transformation funding."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics assessment.'
WHERE variant_id = 109;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'BI maturity scorecard', 'A capability-by-capability rating of your current BI and analytics environment, with evidence and the specific gaps to close.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'Report and dashboard audit', 'An inventory of existing reports identifying duplication, conflicting definitions, stale data sources, and reports nobody uses.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'Decision-gap register', 'A log of the business decisions currently made without reliable data, the risk that carries, and the data changes needed to fix it.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (109, 'Prioritised BI improvement roadmap', 'A sequenced action plan covering quick wins and strategic investments, with effort estimates and recommended owners.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'Which BI tools do you review?', 'The DigitalQatalyst team reviews whatever tools you use, whether that is Power BI, Tableau, Looker, Qlik, or a custom-built solution. The assessment is tool-agnostic.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'How do you identify which gaps matter most?', 'We interview the people who make decisions and ask them which questions they cannot answer reliably, how often those questions arise, and what the cost of the uncertainty is. That drives the prioritisation.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'What if our biggest problem is data quality rather than the BI tools?', 'That is a common finding. The roadmap will distinguish between BI-layer fixes and upstream data fixes, and recommend which to tackle first based on the impact on decision-making.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (109, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We will confirm scope, identify the right stakeholders for interviews, and agree a kick-off date.', 3);

-- Business Intelligence & Analytics (High-Impact) - Design (variant 110)
UPDATE product_content SET
  description = 'Turn your business intelligence and analytics goals into user-centred dashboard specifications, a semantic layer design, and a governed data model your delivery teams can build against, with metrics agreed and signed off before a single report is built.',
  positioning = 'Design the BI and analytics environment your decision-makers actually need: agreed metrics, clean data models, and dashboards specified before a single report is built.',
  hero_summary = 'Turn your business intelligence and analytics goals into user-centred dashboard specifications, a semantic layer design, and a governed data model your delivery teams can build against, with metrics agreed and signed off before a single report is built.',
  overview_paragraphs = '["The Business Intelligence & Analytics Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines BI solutions and build-ready specifications.","Turn business intelligence and analytics goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate business intelligence & analytics requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Metrics agreed and signed off before any build, eliminating conflicting numbers at launch","Semantic layer design prevents the metric fragmentation that plagues large BI estates","Specifications include self-service analytics requirements alongside governed reports"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many organisations build reports without designed metric frameworks, semantic models, or specifications analytics teams can implement. This design engagement defines BI solutions and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined metric frameworks","description":"KPIs and dimensions lack shared definitions and ownership."},{"title":"Semantic model gaps","description":"Self-service and enterprise reporting pull from inconsistent logic."},{"title":"Delivery ambiguity","description":"Teams lack specs for dashboards, alerts, and data products."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned analytics designs","description":"Metrics and models reflect how leaders actually make decisions."},{"title":"Consistent semantic standards","description":"Definitions and governance rules are set upfront."},{"title":"Implementation-ready specs","description":"Analytics teams receive artefacts that accelerate trusted reporting."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics design engagement.'
WHERE variant_id = 110;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Metrics catalogue', 'Every agreed KPI defined with its calculation logic, source data, owner, refresh frequency, and the decisions it supports.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Semantic layer and data model specification', 'A logical data model and semantic layer design ensuring every report calculates the same metric in the same way, regardless of which tool produces it.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Dashboard and report specifications', 'Wireframes and functional specifications for each dashboard, mapped to the user roles and decision workflows they serve.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (110, 'Governance and certification design', 'Policies and process designs for report certification, data ownership, access control, and the lifecycle management of dashboards.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'What is a semantic layer and why does it matter for BI?', 'A semantic layer sits between your raw data and your BI tools, translating database fields into business terms and centralising metric calculation logic. It means every tool that queries it returns the same number for revenue, margin, or any other KPI.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'How do you get stakeholders to agree on metric definitions?', 'We run facilitated definition workshops in week one where each metric owner presents their current definition and we mediate towards a single agreed version. The DigitalQatalyst team documents every decision and its rationale.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'Do we need to replace our existing BI tools to benefit from the design?', 'No. The design works with your chosen tools. Where we identify tooling gaps, we make recommendations but do not require tool changes as a condition of the engagement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (110, 'How do we get started?', 'Contact the DigitalQatalyst team with your BI goals and a list of the decisions you want better data for. We will propose a scoped engagement and identify the stakeholders needed.', 3);

-- Business Intelligence & Analytics (High-Impact) - AI Design (variant 111)
UPDATE product_content SET
  description = 'Identify where machine learning and AI-driven insights can augment your business intelligence and analytics capability, validate each use case against your actual data, and leave with responsible workflow designs and deployment-ready specifications ready for engineering.',
  positioning = 'Design AI-augmented analytics your organisation can trust: use cases validated against your data, workflows designed responsibly, specifications ready to build.',
  hero_summary = 'Identify where machine learning and AI-driven insights can augment your business intelligence and analytics capability, validate each use case against your actual data, and leave with responsible workflow designs and deployment-ready specifications ready for engineering.',
  overview_paragraphs = '["The Business Intelligence & Analytics AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for business intelligence and analytics, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for business intelligence & analytics.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use cases validated against your actual analytics data, not theoretical capability","Responsible AI requirements designed in, not added as compliance afterthought","Integration design ensures AI insights surface within your existing BI tools"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many organisations apply AI to your analytics capability without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for business intelligence & analytics lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for business intelligence & analytics are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics AI design engagement.'
WHERE variant_id = 111;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'AI use-case prioritisation assessment', 'Each proposed AI capability scored on data readiness, technical feasibility, business value, and responsible AI risk, with a build or defer recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'Responsible AI workflow designs', 'End-to-end workflow diagrams for each prioritised use case, specifying human review points, confidence thresholds, and the actions to take when the model is uncertain.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'Technical specifications', 'Model requirements, feature pipeline designs, and integration architecture for each approved use case, ready for your engineering team to build against.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (111, 'Data gap remediation plan', 'A targeted list of the data quality and coverage improvements needed before each AI use case can train and run reliably.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'What kinds of AI capabilities work well for BI and analytics?', 'Forecasting and scenario modelling, anomaly and outlier detection, natural language querying of data, automated narrative generation for reports, and smart alerting that identifies which metric changes actually matter.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'How do you assess data readiness for AI?', 'The DigitalQatalyst team reviews the data sources that would feed each use case, checking completeness, consistency, history depth, and refresh frequency against the minimum requirements for the proposed AI capability.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'Do we need a separate ML platform or does this work with our BI tool?', 'It depends on the use case. Some AI capabilities are native to modern BI tools. Others require a separate ML platform. The specifications will tell you exactly what infrastructure each use case needs.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (111, 'How do we get started?', 'Share your BI goals and the decisions you want to make faster or more accurately with the DigitalQatalyst team. We will assess your starting position and propose an engagement scope.', 3);

-- Business Intelligence & Analytics (High-Impact) - Deploy (variant 112)
UPDATE product_content SET
  description = 'Build, connect, and launch your agreed BI and analytics environment, from data pipeline integration and semantic layer implementation to certified dashboards and a trained self-service user community, within a milestone-gated twelve-week programme.',
  positioning = 'Get your BI and analytics environment live: data connected, metrics consistent, dashboards certified, and your users confident before the engagement ends.',
  hero_summary = 'Build, connect, and launch your agreed BI and analytics environment, from data pipeline integration and semantic layer implementation to certified dashboards and a trained self-service user community, within a milestone-gated twelve-week programme.',
  overview_paragraphs = '["The Business Intelligence & Analytics Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed business intelligence and analytics changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated business intelligence & analytics assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Dashboard certification process confirms every report shows the right number before go-live","Self-service enablement built into the deployment, not added later","Handover includes administrator training so your team owns the environment from day one"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many organisations stall between approved designs and production for your analytics capability, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for business intelligence & analytics sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics deployment engagement.'
WHERE variant_id = 112;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Integrated and tested BI environment', 'Data sources connected, pipelines running to schedule, and the semantic layer in place with all agreed KPIs calculating correctly.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Certified dashboard suite', 'All specified dashboards built, tested against acceptance criteria, and certified as the authoritative source for each metric they present.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Self-service analytics configuration', 'Self-service workspace configured with governed data sets, access controls in place, and documentation enabling your analysts to build their own reports.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (112, 'Training materials and handover documentation', 'Role-based training guides, administrator documentation, and a handover pack confirming your team can maintain and extend the BI environment independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'What does dashboard certification mean?', 'Certification means a named data owner has reviewed the dashboard, confirmed its calculations against the agreed metric definitions, and approved it as the authoritative source. Certified dashboards are marked in the BI environment.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'How do you handle conflicting numbers found during testing?', 'When user acceptance testing reveals a metric discrepancy, the DigitalQatalyst team traces it to its source, applies the agreed metric definition, and resolves it before certification. No dashboard goes live with unresolved conflicts.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'Will our data team be able to add new dashboards after the engagement?', 'Yes. Self-service configuration and administrator training are included. Your team will be able to publish new reports against the governed data sets without our involvement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (112, 'How do we get started?', 'Provide your completed BI design specifications to the DigitalQatalyst team. We will confirm scope, agree the data sources to connect first, and schedule a kick-off.', 3);

-- Business Intelligence & Analytics (High-Impact) - AI Deploy (variant 113)
UPDATE product_content SET
  description = 'Put validated forecasting, anomaly detection, and AI-driven insight capabilities into production within your BI and analytics environment, with governance controls and monitoring configured from the first day of operation.',
  positioning = 'Launch AI-powered analytics in production: models governed, outputs integrated into your existing dashboards, and your analytics team trained to act on what the AI surfaces.',
  hero_summary = 'Put validated forecasting, anomaly detection, and AI-driven insight capabilities into production within your BI and analytics environment, with governance controls and monitoring configured from the first day of operation.',
  overview_paragraphs = '["The Business Intelligence & Analytics AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled business intelligence and analytics workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for business intelligence & analytics with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["AI outputs surface inside your existing BI tools, no separate interface required","Human-in-the-loop controls implemented as specified, not deferred to a later phase","Analytics team trained on model interpretation before go-live"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many AI initiatives for your analytics capability fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for business intelligence & analytics fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics AI deployment engagement.'
WHERE variant_id = 113;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Production AI analytics deployment', 'AI models serving live predictions integrated into your BI dashboards, with version control and rollback capability confirmed working before launch.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Monitoring and alert configuration', 'Drift detection, accuracy tracking, and alerting thresholds configured so degradation is caught and investigated before it affects decisions.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Governance and audit controls', 'Audit logs covering model predictions, access controls on model endpoints, and documentation of the human review points applied in each workflow.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Analytics team enablement pack', 'Training materials, interpretation guides, and escalation procedures giving your analytics team the confidence to act on AI outputs and challenge them when something looks wrong.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do AI insights appear inside our existing dashboards?', 'The integration architecture defined in your AI design connects model outputs to your BI tool''s data layer. Analysts see forecasts, anomaly flags, or narrative insights directly in the dashboards they already use.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'What happens when a model flags an anomaly?', 'The alert routes to the relevant analyst. The incident playbook tells them what to investigate, what to rule out, and when to escalate. The DigitalQatalyst team will support the first few live alerts to build team confidence.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do you validate that the AI is producing useful outputs before go-live?', 'We run a shadow period where models produce outputs alongside your existing analysis. Your analytics team reviews the outputs against known historical events before the model is promoted to production.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do we get started?', 'Share your completed AI design specifications with the DigitalQatalyst team. We will confirm infrastructure requirements, identify the first use case for deployment, and schedule a kick-off.', 3);

-- Business Intelligence & Analytics (High-Impact) - Managed (variant 114)
UPDATE product_content SET
  description = 'Keep your business intelligence and analytics environment accurate, performant, and current every month, with SLA-backed monitoring, monthly quality reporting, and a continuous improvement cycle managed by the DigitalQatalyst team.',
  positioning = 'Maintain a BI and analytics environment your decision-makers can rely on every month, with proactive quality checks, rapid incident resolution, and regular optimisation reviews.',
  hero_summary = 'Keep your business intelligence and analytics environment accurate, performant, and current every month, with SLA-backed monitoring, monthly quality reporting, and a continuous improvement cycle managed by the DigitalQatalyst team.',
  overview_paragraphs = '["The Business Intelligence & Analytics Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve business intelligence and analytics with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for business intelligence & analytics - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed incident response so report failures are resolved before they affect the morning meeting","Monthly quality reporting gives leadership a consistent view of analytics environment health","Governed change management prevents the metric drift that erodes report credibility over time"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many organisations struggle to sustain performance across your analytics capability after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"business intelligence & analytics issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics managed service.'
WHERE variant_id = 114;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Monthly analytics quality report', 'A scored view of metric accuracy, data freshness, report usage, and incident history with trend analysis and recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Incident log and resolution record', 'A complete log of every report failure or data issue, the time to detect and resolve, root cause, and preventive action taken.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Quarterly optimisation review', 'An analysis of report performance, dashboard usage, and the optimisations applied or planned for the next quarter.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (114, 'Change register', 'A documented record of every approved change to reports, metrics, or data sources, with the business justification and sign-off for each.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'What counts as an incident under the managed service?', 'A report failure, a data refresh that misses its SLA window, a metric that calculates incorrectly, or a dashboard that becomes inaccessible. All are classified by severity and handled within the agreed response times.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'How do we request new reports or metric changes?', 'Through the change request process included in the service. The DigitalQatalyst team scopes the request, estimates effort, and delivers it within the agreed capacity. Requests that exceed included capacity are quoted separately.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'What happens if our source data changes and breaks our reports?', 'Monitoring detects the failure. The DigitalQatalyst team investigates, identifies the source change, and either remediates or raises a change request to update the affected pipelines and dashboards.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (114, 'How do we get started?', 'The managed service typically follows a completed deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs and service scope, and schedule the onboarding period.', 3);

-- Enterprise AI & Automation (High-Impact) - Assess (variant 115)
UPDATE product_content SET
  description = 'Identify the highest-value AI and automation opportunities in your organisation, uncover the data and infrastructure gaps blocking adoption, and leave with a prioritised roadmap and the governance requirements your first production capability will need.',
  positioning = 'Find out where AI and automation will create the most value for your organisation, what is blocking you today, and what needs to happen before you build.',
  hero_summary = 'Identify the highest-value AI and automation opportunities in your organisation, uncover the data and infrastructure gaps blocking adoption, and leave with a prioritised roadmap and the governance requirements your first production capability will need.',
  overview_paragraphs = '["The Enterprise AI & Automation Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps maturity and returns prioritised improvements your technology and business leaders can act on.","See how enterprise AI and automation perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for ceos, cios, ai & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews enterprise ai & automation across data, analytics, and intelligent automation.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use cases grounded in your actual workflows and data, not generic AI scenarios","Responsible AI and ethics assessment included, not a separate engagement","No commitment to build required to receive the full findings and roadmap"]'::jsonb,
  why_it_matters = '{"hook":"AI and automation are reshaping how organisations operate, but only where use cases are validated and governed.","problemParagraph":"Many organisations experiment with AI and automation without portfolio governance, risk controls, or a clear view of production readiness. This assessment maps maturity and returns prioritised improvements your technology and business leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Scattered experiments","description":"Pilots run in isolation without shared prioritisation or learning."},{"title":"Weak governance","description":"Risk, ethics, and compliance controls are not applied consistently."},{"title":"Production gap","description":"Promising use cases lack a path from proof of concept to scaled operations."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Portfolio priority view","description":"Leadership sees which AI and automation opportunities matter most."},{"title":"Prioritised delivery roadmap","description":"Use cases are ordered by value, feasibility, and risk."},{"title":"Investment clarity","description":"Your leaders can fund governed production capabilities first."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise AI and Automation assessment.'
WHERE variant_id = 115;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'AI opportunity map', 'A scored view of the AI and automation opportunities across your priority workflows, ranked by business value, feasibility, and time to first value.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'Readiness assessment', 'A gap analysis covering data quality, infrastructure, skills, and governance against the requirements of each priority use case.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'Risk and ethics register', 'The responsible AI risks specific to your use cases and sector, with the controls and governance requirements needed to address each one.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (115, 'Prioritised AI adoption roadmap', 'A sequenced action plan for closing readiness gaps and building your first AI capabilities, with the investment case for each priority use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'Do we need to have AI projects already underway to benefit from this assessment?', 'No. This assessment is designed for organisations at the start of their AI journey. It is equally valuable if you have existing AI experiments that need structure and prioritisation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'How do you identify which use cases are genuinely feasible?', 'The DigitalQatalyst team scores each candidate against four factors: the data available to train and run it, the technical complexity, the business value, and the responsible AI risk. Only use cases that score above a defined threshold make the roadmap.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'What does the responsible AI review cover?', 'It covers bias risk, explainability requirements, regulatory obligations relevant to your sector, and the human oversight needed for each use case. The output is a practical list of the controls you will need to put in place.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (115, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We will confirm scope, identify the right stakeholders, and agree which workflows to focus on during the assessment.', 3);

-- Enterprise AI & Automation (High-Impact) - Design (variant 116)
UPDATE product_content SET
  description = 'Turn your validated AI and automation use cases into user-centred workflow designs, integration specifications, and a governed deployment blueprint your engineering teams can build against, with governance and override controls designed in from the outset.',
  positioning = 'Translate AI and automation ambitions into build-ready specifications: workflows designed, integrations mapped, governance controls specified, and adoption planned before a line of code is written.',
  hero_summary = 'Turn your validated AI and automation use cases into user-centred workflow designs, integration specifications, and a governed deployment blueprint your engineering teams can build against, with governance and override controls designed in from the outset.',
  overview_paragraphs = '["The Enterprise AI & Automation Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines AI use cases and build-ready specifications.","Turn enterprise AI and automation goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for ceos, cios, ai & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate enterprise ai & automation requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Workflow designs validated with end users before specifications are finalised","Governance and override controls designed in, not retrofitted after the build","Adoption plan included so your people are ready when the technology goes live"]'::jsonb,
  why_it_matters = '{"hook":"AI and automation are reshaping how organisations operate, but only where use cases are validated and governed.","problemParagraph":"Many organisations design AI solutions without validated workflows, responsible controls, or specifications engineering teams can deploy. This design engagement defines AI use cases and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated use cases","description":"AI ideas lack structured business cases and success criteria."},{"title":"Missing guardrails","description":"Human oversight, monitoring, and safety controls are not designed in."},{"title":"Integration ambiguity","description":"Teams lack specs for data, APIs, and operational handover."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated AI designs","description":"Use cases include workflow, data, and governance detail."},{"title":"Responsible control standards","description":"Safety and compliance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Engineering receives artefacts that de-risk production deployment."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise AI and Automation design engagement.'
WHERE variant_id = 116;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'AI workflow designs', 'Detailed workflow diagrams for each prioritised use case, showing the AI or automation interactions, decision points, human touchpoints, and exception paths.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'Integration architecture specification', 'A technical specification mapping how each AI capability connects to your applications, APIs, and data sources, with the agreed integration patterns and data flow.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'Governance and control framework', 'Policies and process designs for decision audit trails, human override mechanisms, model governance, and escalation when an automated decision must be reviewed.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (116, 'Adoption and change management plan', 'A structured plan covering communication, training, role changes, and the success metrics that confirm adoption is working after go-live.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'How much involvement does our team need during the design phase?', 'We run workshops in weeks one and two requiring your process owners, technology leads, and end-user representatives. Half-day availability across those sessions is typically sufficient. The DigitalQatalyst team handles design synthesis between workshops.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'How do you design for human oversight in automated workflows?', 'We identify the decision points in each workflow where the automated output must be reviewed by a human before acting. The design specifies the trigger conditions, the review interface, the time window, and the escalation path if a reviewer is unavailable.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'What if we do not have a preferred technology platform yet?', 'The design engagement includes technology alignment. The DigitalQatalyst team will map your requirements against appropriate platforms and provide a recommendation with rationale before the integration specification is written.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (116, 'How do we get started?', 'Share your prioritised use cases or your AI opportunity assessment with the DigitalQatalyst team. We will scope the design engagement and propose a workshop schedule.', 3);

-- Enterprise AI & Automation (High-Impact) - AI Design (variant 117)
