  hero_summary = 'Validate your enterprise AI and automation use cases against data readiness, responsible AI requirements, and sector-specific compliance obligations, and leave with deployment-ready specifications your engineering team can build against without ambiguity.',
  overview_paragraphs = '["The Enterprise AI & Automation AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for enterprise AI and automation, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for ceos, cios, ai & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for enterprise ai & automation.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Feasibility validation prevents investment in use cases the data or infrastructure cannot yet support","Responsible AI requirements specified at design time, not discovered during a post-launch audit","Compliance mapping covers your sector-specific obligations so your legal and risk teams can review before build begins"]'::jsonb,
  why_it_matters = '{"hook":"AI and automation are reshaping how organisations operate, but only where use cases are validated and governed.","problemParagraph":"Many organisations apply AI to your AI and automation portfolio without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for enterprise ai & automation lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for enterprise ai & automation are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise AI and Automation AI design engagement.'
WHERE variant_id = 117;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Use-case feasibility assessment', 'Each AI use case scored and assessed against data readiness, technical complexity, responsible AI risk, and business value, with a build or defer recommendation and supporting rationale.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Responsible AI workflow designs', 'Detailed workflow designs for each approved use case, specifying the bias controls, explainability hooks, human oversight points, and the actions to take when the model output falls below the agreed confidence threshold.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Model and infrastructure specifications', 'Training data requirements, model type recommendations, compute and serving infrastructure specifications, and monitoring requirements for each approved use case.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (117, 'Governance and compliance mapping', 'A record of the governance controls and regulatory obligations that apply to each AI workflow, and the specific design decisions that address each one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'How is this different from the standard design engagement?', 'The AI design engagement focuses specifically on AI and machine learning use cases. It adds a responsible AI layer covering bias, explainability, and oversight requirements, and produces model-level specifications rather than just workflow designs.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'What if our data is not ready for all the use cases we want to build?', 'That is the point of the feasibility assessment. Use cases that fail the data readiness check are deferred. The gap remediation plan tells you exactly what data improvements are needed and in what sequence to prioritise them.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'How do you handle sector-specific AI regulations?', 'The DigitalQatalyst team maps each workflow against the applicable regulations for your sector, identifies the specific obligations that apply, and designs the controls to meet them. The compliance mapping deliverable records every decision for your legal and risk teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (117, 'How do we get started?', 'Share your candidate AI use cases or your AI opportunity assessment with the DigitalQatalyst team. We will confirm scope, assess your starting position, and propose an engagement plan.', 3);

-- Enterprise AI & Automation (High-Impact) - Deploy (variant 118)
UPDATE product_content SET
  description = 'Configure, integrate, and launch your enterprise AI and automation capabilities into production with sprint-gated testing, quality assurance, change management, and a clean operational handover to your teams, within a twelve-week programme.',
