  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for devsecops automation.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Confirms feasibility before any AI build spend is committed","Responsible by design: human gates and audit trails at every stage","Covers code quality, security, and reliability AI use cases"]'::jsonb,
  why_it_matters = '{"hook":"DevSecOps practices determine how fast you can ship, and how confidently you can scale.","problemParagraph":"Many organisations apply AI to your software delivery pipelines without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for devsecops automation lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for devsecops automation are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about the DevSecOps AI design engagement.'
WHERE variant_id = 129;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'AI use-case feasibility register', 'Each candidate scored on data availability, toolchain compatibility, and expected quality or velocity improvement, with a clear go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'Pipeline signal readiness report', 'Assessment of existing telemetry, scan outputs, and historical data quality against the inputs each AI model requires.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'Responsible DevSecOps AI workflows', 'Designed flows for approved use cases with human review gates, confidence thresholds, and audit logging at every decision point.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (129, 'Deployment and monitoring specification', 'Model selection guidance, performance baselines, drift detection thresholds, and feedback loop design for production use.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'Which AI use cases are most commonly explored?', 'AI-assisted code review, ML-based vulnerability prioritisation, predictive test selection to reduce pipeline duration, and anomaly detection on deployment telemetry.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'What if our pipeline telemetry is incomplete?', 'The signal readiness report identifies specific gaps. Organisations often start with lower-data-demand use cases while building telemetry coverage in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'How do you ensure AI recommendations do not block releases incorrectly?', 'Confidence thresholds, human override gates, and fallback logic are designed into every workflow so false positives never silently block deployments.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (129, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and share current pipeline telemetry and toolchain details.', 3);

-- DevSecOps Automation (High-Impact) - Deploy (variant 130)
