INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Monthly delivery and security report', 'DORA metrics, security finding volumes and age, policy exception counts, and pipeline health summary with recommended actions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Incident and change log', 'Transparent record of pipeline incidents, policy changes, and SLA performance across each reporting period.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Quarterly pipeline optimisation review', 'Analysis of stage durations, flaky test trends, and security tool false-positive rates, with prioritised improvement actions.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (132, 'Annual pipeline roadmap', 'Forward-looking plan covering toolchain updates, new security integrations, and scalability improvements to support engineering growth.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'What is covered under the managed service?', 'Pipeline monitoring, incident response, policy and configuration updates, monthly reporting, and quarterly optimisation. Full scope is confirmed in the service agreement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'Can you manage pipelines across multiple cloud environments?', 'Yes. Multi-cloud and hybrid pipeline environments are in scope. The DigitalQatalyst team confirms the environment inventory during onboarding.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'How are security policy changes handled when compliance requirements change?', 'Policy update requests are assessed, implemented in a staging pipeline, validated, and promoted to production within the agreed change management process.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (132, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the pipelines, toolchains, and SLA requirements in scope before the service agreement is drafted.', 3);

-- IT Operations & Support (High-Impact) - Assess (variant 133)
UPDATE product_content SET
  description = 'Audit your IT operations and service desk to identify where incidents are taking too long to resolve, where change control is creating risk, and where manual effort is reducing your team''s capacity for strategic work.',
  positioning = 'Find the operational gaps creating IT reliability risk and service desk inefficiency before they become incidents your business notices.',
  hero_summary = 'Audit your IT operations and service desk to identify where incidents are taking too long to resolve, where change control is creating risk, and where manual effort is reducing your team''s capacity for strategic work.',
  overview_paragraphs = '["The IT Operations & Support Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operations maturity and returns prioritised improvements your IT leaders can act on.","See how IT operations and employee support services perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cios, it operations & service desk leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews it operations & support across customer experience and digital engagement.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope, no-obligation assessment grounded in your actual ITSM and operations data","Repeat failure and change risk analysis included as core outputs","Completed within one week with findings ready for IT leadership review"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations run IT operations reactively, with unclear service catalogues, inconsistent incident practices, and limited capacity planning. This assessment maps operations maturity and returns prioritised improvements your IT leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive incident handling","description":"Outages are managed ad hoc without consistent runbooks and communication."},{"title":"Opaque service catalogue","description":"Business teams do not know what IT provides or how to request it."},{"title":"Capacity blind spots","description":"Infrastructure and support load are not forecast against business demand."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operations priority map","description":"You know which services, processes, and tools to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, automation, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support IT service transformation funding."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations and service desk assessment.'
WHERE variant_id = 133;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'IT operations maturity scorecard', 'Ratings across incident management, change control, monitoring coverage, and automation maturity, each supported by evidence from your actual service desk and operations data.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'Incident and repeat failure analysis', 'Root-cause patterns behind your highest-volume and longest-duration incidents, with specific recommendations for eliminating repeat failures and reducing mean time to resolution.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'Change control risk assessment', 'Evaluation of your change management process against the frequency, impact, and rollback capability of recent changes, with recommendations for improving control without slowing delivery.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (133, 'Prioritised IT improvement roadmap', 'Sequenced actions covering process, tooling, and automation improvements, with effort scores so your IT leadership can plan the next phase around existing operational commitments.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'Which ITSM platforms do you assess?', 'The DigitalQatalyst team works across ServiceNow, Jira Service Management, BMC Helix, Freshservice, and other platforms. Scope is confirmed during the initial consultation.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'What data do you need from us?', 'Incident, change, and problem ticket data for the previous 6-12 months, monitoring alert logs, and any existing runbooks or process documentation. No access to production systems is required for the assessment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'Can this assessment cover both on-premises and cloud operations?', 'Yes. The operational scope, including on-premises, cloud, or hybrid environments, is confirmed during the consultation and the assessment is tailored accordingly.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (133, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm data requirements, operational scope, and stakeholder participants before the engagement begins.', 3);

-- IT Operations & Support (High-Impact) - Design (variant 134)
UPDATE product_content SET
  description = 'Design the ITSM processes, tooling architecture, and automation workflows your IT operations team needs to resolve incidents faster, control change more effectively, and reduce manual workload.',
  positioning = 'An IT operations design that gives your service desk team the structure and tools to manage incidents and change without firefighting.',
  hero_summary = 'Design the ITSM processes, tooling architecture, and automation workflows your IT operations team needs to resolve incidents faster, control change more effectively, and reduce manual workload.',
  overview_paragraphs = '["The IT Operations & Support Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines IT service operations and build-ready specifications.","Turn IT operations and employee support services goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cios, it operations & service desk leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate it operations & support requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Automation workflow design to reduce manual ticket handling from the start","Monitoring architecture designed around the services your business actually depends on","ITSM process design validated with both operations leadership and frontline service desk staff"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations improve IT tools without designed service models, incident workflows, or specifications operations teams can run. This design engagement defines IT service operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined service models","description":"Request, fulfilment, and escalation paths are not designed consistently."},{"title":"Runbook fragmentation","description":"Operational knowledge lives with individuals instead of governed libraries."},{"title":"Tooling ambiguity","description":"Teams lack specs for ITSM, monitoring, and automation integration."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned IT service designs","description":"Workflows reflect how the business consumes technology services."},{"title":"Consistent operational standards","description":"SLAs, runbooks, and escalation rules are defined upfront."},{"title":"Implementation-ready specs","description":"Operations teams receive artefacts they can configure and adopt."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations and service desk design engagement.'
WHERE variant_id = 134;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'ITSM process design', 'Defined workflows for incident, problem, change, and request management, covering roles, decision points, SLA tier assignments, and escalation paths tailored to your operational environment.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'Automation workflow specifications', 'Detailed designs for automated alert triage, ticket enrichment, routing logic, and routine resolution playbooks, with the trigger conditions, data requirements, and fallback paths for each.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'Monitoring and observability architecture', 'Coverage design for your infrastructure and application stack, defining what to monitor, alert thresholds, noise reduction rules, and the dashboards your operations team needs for effective incident response.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (134, 'Tooling integration and adoption plan', 'Integration specifications for ITSM, monitoring, asset, and CI/CD connections, plus an adoption plan covering training outlines, change communication, and go-live readiness criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'Does the design cover both reactive incident management and proactive problem management?', 'Yes. Problem management process design, including root-cause analysis workflows and known error management, is included alongside the reactive incident procedures.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'Can the design accommodate a DevOps or SRE working model?', 'Yes. The DigitalQatalyst team can design ITSM processes that integrate with DevOps delivery pipelines and align with SRE practices, including error budget and reliability target definitions.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'How do you handle regulatory or compliance requirements for IT change control?', 'Compliance requirements, such as change freezes, approval audit trails, and segregation of duties, are addressed in the change management process design and the tooling integration specifications.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (134, 'How do we get started?', 'Book a scoping call. The DigitalQatalyst team reviews your current ITSM platform and operational environment, then confirms the stakeholders needed for design workshops.', 3);

