  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Human approval gates and blast-radius limits designed into every automated remediation workflow","Data readiness report tells you exactly which operational data needs improvement before build","Specifications designed for your existing ITSM and monitoring platform architecture"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations apply AI to your IT service operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for it operations & support lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for it operations & support are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations AI design engagement.'
WHERE variant_id = 135;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'AI use-case scorecard for IT operations', 'Each candidate use case rated by operational impact, data feasibility, risk, and implementation complexity, with a clear build recommendation and the sequencing rationale.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Responsible AI workflow designs', 'Workflow diagrams for each validated use case showing AI decision points, human approval gates, rollback triggers, blast-radius limits, and the conditions under which automated remediation is prohibited.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Operational data readiness report', 'Assessment of your monitoring, log, and ITSM data against the requirements of each validated AI use case, with specific data improvement actions needed before build can begin.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Technical deployment specification', 'Model inputs, outputs, ITSM and monitoring integration requirements, infrastructure needs, and the acceptance criteria for validating AI performance in a staging environment before production.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'Which AI use cases are most commonly validated for IT operations?', 'Intelligent alert correlation and noise reduction, anomaly detection for infrastructure metrics, predictive disk and capacity failure, and automated safe remediation playbooks are the most frequently scoped. The DigitalQatalyst team validates each against your specific operational data.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'How do you ensure AI remediation cannot cause a wider outage?', 'Blast-radius limits and scope boundaries are core design requirements, not optional additions. Every automated remediation workflow specifies what the AI is permitted to do, the conditions that must be true before action is taken, and the rollback trigger if the action does not produce the expected result.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'What monitoring data do we need before AI design is viable?', 'The data readiness assessment evaluates your monitoring coverage, log retention, and alert history. Gaps are identified with specific remediation steps. Many organisations find targeted monitoring improvements take weeks rather than months.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your ITSM platform, monitoring stack, and operational data landscape to shape the engagement scope.', 3);

-- IT Operations & Support (High-Impact) - Deploy (variant 136)
UPDATE product_content SET
  description = 'Configure, integrate, test, and launch your ITSM and IT operations platform improvements with structured quality assurance and a handover that leaves your operations team fully equipped to manage them independently.',
  positioning = 'IT operations capabilities delivered and tested, with your team ready to manage incidents and change before the project closes.',
  hero_summary = 'Configure, integrate, test, and launch your ITSM and IT operations platform improvements with structured quality assurance and a handover that leaves your operations team fully equipped to manage them independently.',
  overview_paragraphs = '["The IT Operations & Support Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed IT operations and employee support services changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cios, it operations & service desk leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated it operations & support assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Monitoring and alert configuration validated before any production traffic is managed through the new system","Runbook library built and reviewed with your operations team during user acceptance testing","Post-launch hypercare period to resolve early operational issues before full handover"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations stall between approved designs and production for your IT service operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for it operations & support sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations and ITSM deployment engagement.'
WHERE variant_id = 136;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'Configured ITSM environment', 'Fully built incident, change, problem, and request management workflows, routing rules, SLA configurations, and permission sets, validated in a staging environment before production promotion.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'Monitoring and alerting validation report', 'Evidence that monitoring covers the agreed infrastructure and application scope, alert thresholds produce the expected signals, and noise reduction rules are functioning correctly.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'Integration test evidence pack', 'Test scenarios and results for every ITSM integration, covering data synchronisation, trigger accuracy, and error handling across monitoring, asset management, and CI/CD connections.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (136, 'IT operations handover pack', 'Administrator guides, runbook library, escalation contacts, and a 30-day post-launch review schedule so your team owns the platform and processes from day one.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'How is monitoring coverage validated?', 'The DigitalQatalyst team runs a coverage validation against the agreed scope, confirming that each in-scope system and application is instrumented, alert thresholds produce the expected response, and noise reduction rules reduce false positives before go-live.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'What happens to open incidents and change requests at cutover?', 'Open ticket migration is planned and tested before cutover. The DigitalQatalyst team produces a cutover playbook covering data migration steps, rollback triggers, and the communication plan for operations staff.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'Can we continue using the existing ITSM during the build period?', 'Yes. The cutover is planned to minimise disruption to live operations. Parallel running options and low-risk migration windows are agreed during planning.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (136, 'How do we get started?', 'Share your approved design specifications and the DigitalQatalyst team will confirm scope, platform configuration approach, and a delivery timeline.', 3);

-- IT Operations & Support (High-Impact) - AI Deploy (variant 137)
UPDATE product_content SET
  description = 'Deploy validated AI capabilities into your IT operations and ITSM environment with production monitoring, safety controls, and a structured handover that gives your operations team full ownership of the capability.',
  positioning = 'AI-assisted incident detection and operations automation in production, with the safety controls your infrastructure team demands.',
  hero_summary = 'Deploy validated AI capabilities into your IT operations and ITSM environment with production monitoring, safety controls, and a structured handover that gives your operations team full ownership of the capability.',
  overview_paragraphs = '["The IT Operations & Support AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled IT operations and employee support services workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cios, it operations & service desk leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for it operations & support with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Safety controls and blast-radius limits validated in staging before any production automated remediation is enabled","Operations dashboards give your team visibility into AI behaviour, not just business outcomes","Runbook and training included so engineers can work confidently alongside and manage the AI capability"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many AI initiatives for your IT service operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for it operations & support fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations AI deployment engagement.'
WHERE variant_id = 137;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'Production AI deployment for IT operations', 'AI capabilities fully integrated into your ITSM and monitoring environment, validated against detection accuracy, automated resolution success rates, and the agreed safety acceptance criteria.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'Safety control validation report', 'Evidence that blast-radius limits, human approval gates, and rollback triggers operate correctly across representative production scenarios before the capability goes live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'AI operations dashboard and alerting', 'Real-time visibility into model detection accuracy, false positive and negative rates, automated resolution outcomes, and the alert rules that notify your team when AI performance moves outside agreed thresholds.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (137, 'Operations runbook and training record', 'Step-by-step procedures for AI monitoring, incident response, model performance review, and escalation, with confirmed training completion for operations engineers and team leads.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'How do you test that automated remediation cannot cause a wider outage?', 'The DigitalQatalyst team runs blast-radius tests in the staging environment, simulating remediation actions across representative failure scenarios to confirm that scope limits, rollback triggers, and human approval gates operate correctly before any production deployment.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'Can AI capabilities be deployed to non-critical systems first?', 'Yes. Staged rollout by system criticality or environment type is the standard approach, allowing the operations team to build confidence and refine thresholds before the AI manages business-critical infrastructure.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'How will our engineers know what the AI has done and why?', 'Every AI action is logged to the ITSM platform with the trigger condition, the action taken, the outcome, and the confidence level. Engineers have full audit trail access and the AI operations dashboard provides a real-time summary view.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (137, 'How do we get started?', 'Provide your approved AI design specifications and the DigitalQatalyst team will confirm infrastructure requirements, safety control specifications, and the production deployment schedule.', 3);

-- IT Operations & Support (High-Impact) - Managed (variant 138)
UPDATE product_content SET
  description = 'Keep your IT operations and ITSM platform running reliably, with ongoing monitoring, proactive incident trend analysis, and a team accountable to your service levels so your IT function can focus on delivery.',
  positioning = 'Your IT operations platform continuously maintained and optimised, so your team resolves incidents faster and changes land without surprises.',
  hero_summary = 'Keep your IT operations and ITSM platform running reliably, with ongoing monitoring, proactive incident trend analysis, and a team accountable to your service levels so your IT function can focus on delivery.',
  overview_paragraphs = '["The IT Operations & Support Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve IT operations and employee support services with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cios, it operations & service desk leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for it operations & support - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Problem management support included to eliminate repeat incidents, not just resolve them","Monthly reports aligned to your SLA tiers and business service dependencies","Quarterly service reviews to keep the ITSM roadmap aligned with your IT strategy"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations struggle to sustain performance across your IT service operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"it operations & support issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations managed service.'
WHERE variant_id = 138;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'Monthly IT operations performance report', 'Incident volumes, resolution times, SLA compliance by tier, change success rates, and automation health, with commentary on trends and the next period optimisation priorities.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'Problem management and trend analysis report', 'Root-cause patterns behind repeat incidents, the problem records raised, and the improvement actions taken or recommended to eliminate recurring failures.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'ITSM platform change and update record', 'Documentation of all ITSM updates applied, regression tests completed, and any issues resolved before changes were promoted to the production environment.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (138, 'Quarterly IT service review', 'A structured assessment of IT operations performance against your agreed service objectives, incorporating business volume changes, new service onboardings, and emerging operational risks.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'Does the managed service cover problem management as well as incidents?', 'Yes. Problem management is an active part of the service. The DigitalQatalyst team identifies repeat failure patterns from monthly incident data, raises problem records, and tracks improvement actions to resolution.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'Can we request ITSM configuration changes within the managed service?', 'Yes. A defined change request allowance is included each month. Larger structural changes are assessed and agreed separately so you remain in control of scope and investment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'How do you manage the service if we have an in-house IT operations team?', 'The DigitalQatalyst team operates as an extension of your team. Responsibility boundaries, escalation paths, and communication channels are agreed during onboarding and documented in the service agreement.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (138, 'How do we get started?', 'Request an onboarding call. The DigitalQatalyst team reviews your current ITSM environment, agrees the service baseline and SLA framework, and confirms the first reporting cycle.', 3);

-- Farming Operations (High-Impact) - Assess (variant 149)
UPDATE product_content SET
  description = 'Understand where your farming operations fall short on yield visibility, resource efficiency, and planning accuracy. The DigitalQatalyst team assesses your current operational maturity and returns a prioritised roadmap your agribusiness leaders can act on.',
  positioning = 'A structured assessment that reveals where operational gaps are costing yield, water, and labour, and what to fix first.',
  hero_summary = 'Understand where your farming operations fall short on yield visibility, resource efficiency, and planning accuracy. The DigitalQatalyst team assesses your current operational maturity and returns a prioritised roadmap your agribusiness leaders can act on.',
  overview_paragraphs = '["The Farming Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","See how farming operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for agribusiness & farm operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews farming operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment delivered within one week","Covers crop, livestock, and mixed farming operation models","No obligation to proceed with subsequent design or deployment"]'::jsonb,
  why_it_matters = '{"hook":"Farming operations depend on timely data, coordinated field activity, and resilient supply chain execution.","problemParagraph":"Many agribusinesses run farming operations with manual field coordination, inconsistent yield data, and limited visibility into supply chain risk. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Agricultural operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which agricultural operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the farming operations assessment.'
WHERE variant_id = 149;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Farming operations maturity scorecard', 'Ratings across yield tracking, resource management, planning accuracy, and equipment utilisation, with evidence and specific gaps.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Operational gap register', 'Documented gaps in crop monitoring, irrigation scheduling, input management, and harvest coordination, ranked by cost and yield impact.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Prioritised improvement roadmap', 'Sequenced actions with owners, effort estimates, and dependencies your operations team can act on from the first season.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (149, 'Leadership briefing pack', 'A concise summary of findings and recommended investment for agribusiness and farm operations leadership.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'What farming models does the assessment cover?', 'Broadacre cropping, horticulture, livestock, and mixed operations. The DigitalQatalyst team confirms the applicable model during scoping.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'Do you need access to our farm management systems?', 'We review system outputs and operational records rather than live data. Any access required is read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'What do we get at the end?', 'A maturity scorecard, an operational gap register, a prioritised improvement roadmap, and a leadership briefing pack.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (149, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm the farming operation type, geographic scope, and key stakeholders before work begins.', 3);

