INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Infrastructure AI use-case feasibility register', 'Each candidate scored on sensor data availability, asset history quality, and expected reliability or cost improvement, with a clear go or no-go recommendation.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Asset data readiness report', 'Gaps in sensor coverage, inspection record completeness, maintenance history depth, and GIS data quality that must be addressed before model development.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Responsible infrastructure AI workflows', 'Designed flows for approved use cases with engineer review points, confidence displays for field technicians, and documented override procedures.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (163, 'Deployment and monitoring specification', 'Model selection guidance, performance thresholds, asset-aligned retraining triggers, and fleet or portfolio-level monitoring requirements for production use.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'Which AI use cases are most commonly explored?', 'Predictive asset failure from sensor and maintenance history data, condition-based maintenance scheduling, field workforce route optimisation, and fault pattern detection across asset networks.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'What if our sensor coverage is limited to a subset of assets?', 'The data readiness report identifies the minimum coverage needed for each use case. Many organisations start with highest-criticality assets while expanding sensor coverage in parallel.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'How do field engineers interact with AI maintenance recommendations?', 'Recommendations appear in the field management mobile tool with confidence scores and recommended actions. Engineers can confirm, reschedule, or override, with all decisions logged.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (163, 'How do we get started?', 'Book a consultation with the DigitalQatalyst team to identify your highest-value AI use cases and share your current asset data, sensor, and maintenance record landscape.', 3);

