INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (165, 'Production infrastructure AI capabilities', 'Approved models live in your EAM environment with sensor pipelines, prediction logging, and technician-facing recommendation interfaces active.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (165, 'Asset portfolio monitoring dashboard', 'Real-time view of prediction accuracy, maintenance intervention hit rates, technician override rates, and field productivity impact by asset class.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (165, 'Engineer and technician override playbook', 'Procedures for accepting, deferring, or overriding AI maintenance recommendations, with escalation steps for model quality concerns.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (165, 'AI governance handover pack', 'Model cards, sensor data lineage, asset-aligned retraining schedule, and accountability assignments for ongoing responsible operation.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (165, 'How do field technicians receive AI maintenance recommendations?', 'Recommendations appear in the field management mobile tool with priority, confidence score, and recommended action. Technicians can accept, defer, or override with a reason captured for model improvement.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (165, 'What happens if a predictive failure model produces frequent false alerts?', 'False-alert rates are tracked in the monitoring dashboard. Threshold adjustments are made during the pilot phase before full portfolio rollout.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (165, 'How is model performance maintained as assets age or the network expands?', 'Retraining triggers are defined in the governance handover pack. Asset age events and new asset additions automatically flag affected models for review.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (165, 'How do we get started?', 'Contact the DigitalQatalyst team with your approved AI design specification to plan the production environment, sensor pipeline access, and pilot asset class selection.', 3);

