INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'How are regulatory compliance updates to maintenance standards handled?', 'Compliance-driven configuration changes are assessed, implemented in a test environment, validated, and promoted to production within the agreed change management process.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'Can the service scale to cover additional asset classes or new sites?', 'Yes. New asset classes and sites are onboarded under the service. Large portfolio expansions are scoped and priced separately.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (166, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the EAM platform, asset portfolio scope, and SLA requirements before the service agreement is drafted.', 3);

