  why_it_matters = '{"hook":"Public service delivery depends on reliable processes, transparent accountability, and citizen-centred design.","problemParagraph":"Many government programmes digitise services without designed citizen journeys, policy controls, or specifications delivery teams can implement. This design engagement defines government operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Government service journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how government service teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the government operations design engagement.'
WHERE variant_id = 168;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Citizen journey maps', 'End-to-end service flows from initial application through processing, decision, notification, and appeals across all in-scope government services.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Back-office workflow specification', 'Approval queues, case assignment rules, compliance check procedures, and audit trail requirements documented for configuration and development teams.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Cross-agency integration design', 'Data sharing patterns, referral workflow logic, and privacy compliance controls for all inter-agency touchpoints in scope.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (168, 'Public sector adoption plan', 'Phased rollout sequence with staff training requirements by role, accessibility compliance checklist, and service continuity plan during transition.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How do you ensure the design meets accessibility obligations?', 'Accessibility requirements are incorporated from the first workshop. The DigitalQatalyst team aligns designs to the applicable standard, such as WCAG 2.1 AA, and documents compliance evidence.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How are citizens involved in the design process?', 'Where the programme governance permits, representative citizen research or usability review is incorporated to validate that service journeys work for the intended audience.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (168, 'How do we get started?', 'Contact the DigitalQatalyst team to confirm the services and functions in scope, the platforms in use, and any procurement or governance constraints before the engagement begins.', 2);

-- Government Operations (High-Impact) - AI Design (variant 169)
UPDATE product_content SET
  description = 'Validate where AI can improve government service processing speed, decision support, and cross-agency coordination before committing build budget. The DigitalQatalyst team designs responsible, audit-ready AI workflows and deployment-ready specifications that meet public sector accountability requirements.',
