  why_it_matters = '{"hook":"Service businesses win on scheduling discipline, field execution, and customer communication.","problemParagraph":"Many AI initiatives for your field service operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for service operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying AI into live service operations.'
