INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (189, 'Live service AI capability suite', 'Approved AI features in production, integrated with your FSM and job-data systems, accepted by dispatch managers and field service leads.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (189, 'Service AI monitoring dashboard', 'Real-time view of scheduling accuracy, first-visit resolution rates, and model recommendation uptake, with alert thresholds agreed with your service management team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (189, 'Dispatcher governance documentation', 'Written policies and in-system controls covering when dispatchers must review or override AI scheduling recommendations, with escalation paths.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (189, 'AI operations handover pack', 'Model cards, FSM integration diagrams, monitoring runbooks, and retraining schedules handed to your technology and service operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (189, 'Which AI capabilities are activated in this deployment?', 'Those validated in your AI Design phase: commonly predictive scheduling optimisation, first-visit-resolution modelling, and asset failure prediction. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (189, 'How do you avoid AI scheduling errors affecting field staff and customers?', 'Shadow-mode testing runs the scheduling AI against live data without acting on outputs until accuracy thresholds are met. Dispatcher override controls remain active after full launch.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (189, 'Who maintains the AI models after handover?', 'Your technology team, using the model cards, monitoring runbooks, and retraining schedules provided in the handover pack. The DigitalQatalyst team can provide ongoing managed support if needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (189, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm production environment requirements and the job-type activation sequence.', 3);

