  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for service operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Scheduling and field performance reported together in a single monthly view","Proactive scheduling optimisation included alongside reactive incident management","Named team with service-sector context, not a generic IT support function"]'::jsonb,
  why_it_matters = '{"hook":"Service businesses win on scheduling discipline, field execution, and customer communication.","problemParagraph":"Many organisations struggle to sustain performance across your field service operations after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"service operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Service Operations managed service.'
WHERE variant_id = 190;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (190, 'Monthly service operations performance report', 'Job completion rates, first-visit resolution, scheduling utilisation, and system-uptime metrics across all in-scope platforms, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (190, 'Optimisation log', 'Record of every scheduling adjustment, workflow change, and integration fix made during the service period, with before-and-after performance metrics.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (190, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (190, 'Annual service operations roadmap', 'Forward-looking plan identifying scheduling optimisation priorities, platform upgrade opportunities, and recommended investments for the next 12 months.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (190, 'What platforms does the managed service cover?', 'FSM, scheduling, and mobile field applications, plus the integrations connecting them. Additional platforms can be onboarded as your estate grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (190, 'What SLA response times apply to field-critical incidents?', 'Response and resolution targets are agreed during onboarding. Field-facing system failures that prevent job dispatch receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (190, 'Does the managed service include peak-capacity support periods?', 'Yes. The DigitalQatalyst team reviews your operational calendar during onboarding and confirms enhanced monitoring for high-demand periods.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (190, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call covering platforms in scope, SLA targets, reporting format, and named contacts.', 3);

-- Logistics Operations (High-Impact) - Assess (variant 191)
UPDATE product_content SET
  description = 'A structured assessment of your logistics and supply chain operations that identifies the fulfilment inaccuracies, visibility gaps, and asset utilisation losses reducing delivery performance, and returns a prioritised improvement roadmap your supply chain leaders can act on.',
  positioning = 'Pinpoint the logistics and supply chain gaps costing you fulfilment accuracy, delivery visibility, and asset utilisation, with every recommendation ranked for impact.',
  hero_summary = 'A structured assessment of your logistics and supply chain operations that identifies the fulfilment inaccuracies, visibility gaps, and asset utilisation losses reducing delivery performance, and returns a prioritised improvement roadmap your supply chain leaders can act on.',
  overview_paragraphs = '["The Logistics Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your supply chain leaders can act on.","See how logistics and supply chain operations perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for logistics & supply chain leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews logistics operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Covers fulfilment accuracy, network visibility, and asset utilisation in one assessment","Cost and delivery-performance impact scored on every recommendation","Fixed-scope with a prioritised roadmap ready within the week"]'::jsonb,
  why_it_matters = '{"hook":"Logistics performance is won or lost on visibility, routing discipline, and handoff accuracy.","problemParagraph":"Many logistics organisations run networks with fragmented tracking, inconsistent warehouse processes, and limited end-to-end visibility. This assessment maps operational maturity and returns prioritised improvements your supply chain leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Logistics operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which logistics operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Logistics Operations assessment.'
WHERE variant_id = 191;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (191, 'Fulfilment accuracy diagnostic', 'Data-backed analysis of pick, pack, despatch, and last-mile failure rates, with root causes and cost estimates for the highest-impact error patterns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (191, 'Supply chain visibility report', 'Assessment of order, stock, and carrier data flows across your network, with the specific visibility gaps causing delayed decisions and customer-facing delivery failures.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (191, 'Asset and fleet utilisation scorecard', 'Benchmark of vehicle and warehouse asset utilisation against capacity, with idle time, route inefficiencies, and the revenue cost of underutilisation identified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (191, 'Prioritised logistics improvement roadmap', 'Sequenced action plan ranked by fulfilment and cost impact, with ownership suggestions and a phasing recommendation your supply chain leadership can execute.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (191, 'Which parts of the logistics network does the assessment cover?', 'Warehousing, fulfilment, carrier integration, last-mile delivery, and returns. Exact scope is confirmed with the DigitalQatalyst team before start.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (191, 'What data do you need?', 'Fulfilment accuracy records, carrier performance data, warehouse throughput metrics, and fleet utilisation reports. Data is reviewed read-only and agreed in advance.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (191, 'Can you assess third-party logistics operations alongside our own?', 'Yes, where you have data access. The assessment maps your full network including 3PL partners where performance data is available.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (191, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the network scope, data requirements, and assessment schedule.', 3);

-- Logistics Operations (High-Impact) - Design (variant 192)
UPDATE product_content SET
  description = 'A logistics design engagement that converts your supply chain improvement objectives into fulfilment workflow blueprints, carrier integration specifications, and warehouse technology architectures your delivery teams can implement and launch.',
  positioning = 'Design the logistics operations blueprint you need: fulfilment workflows, carrier integrations, and warehouse technology ready for build.',
  hero_summary = 'A logistics design engagement that converts your supply chain improvement objectives into fulfilment workflow blueprints, carrier integration specifications, and warehouse technology architectures your delivery teams can implement and launch.',
  overview_paragraphs = '["The Logistics Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines logistics operations and build-ready specifications.","Turn logistics and supply chain operations goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for logistics & supply chain leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate logistics operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fulfilment, carrier integration, and warehouse technology designed in a single engagement","Integration architecture built to your existing WMS, TMS, and carrier connections","Throughput and accuracy targets embedded in workflow specifications from the design stage"]'::jsonb,
  why_it_matters = '{"hook":"Logistics performance is won or lost on visibility, routing discipline, and handoff accuracy.","problemParagraph":"Many logistics operators digitise networks without designed routing workflows, warehouse standards, or specifications operations teams can implement. This design engagement defines logistics operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Logistics operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how logistics operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the Logistics Operations design engagement.'
WHERE variant_id = 192;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (192, 'Fulfilment workflow designs', 'End-to-end process specifications from inbound receipt to last-mile despatch and returns, with throughput targets, accuracy checkpoints, and escalation paths at each stage.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (192, 'Carrier and TMS integration architecture', 'Data-flow diagrams and API integration specifications connecting your WMS, TMS, and carrier systems into a real-time network visibility picture.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (192, 'Warehouse technology specification', 'Scanning, slotting, and automation technology recommendations with layout integration plans aligned to your fulfilment volume and accuracy targets.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (192, 'Adoption and training plan', 'Role-specific onboarding materials for warehouse operatives, transport coordinators, and planning teams, with a rollout sequence and sign-off criteria.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (192, 'Does the design cover returns as well as outbound fulfilment?', 'Yes. Returns workflow specifications are included as a standard component of the fulfilment blueprint.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (192, 'What if we are changing our WMS as part of this programme?', 'The integration architecture can be designed for your target WMS system if a platform migration is already planned. The DigitalQatalyst team confirms the approach during scoping.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (192, 'How are specifications handed to the delivery team?', 'Annotated workflow diagrams, integration specs, and warehouse technology recommendations in a shared workspace formatted for handover to internal or third-party implementation teams.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (192, 'How do we get started?', 'Book a scoping call and the DigitalQatalyst team will confirm the network scope, the workshops required, and the design sprint schedule.', 3);

-- Logistics Operations (High-Impact) - AI Design (variant 193)
UPDATE product_content SET
  description = 'A logistics-focused AI design engagement that validates which AI capabilities will genuinely improve demand forecasting, route optimisation, and fulfilment planning, producing responsible workflow designs and build-ready specifications before any development investment is committed.',
  positioning = 'Design logistics AI with validated forecasting and routing use cases, clean data requirements, and responsible guardrails defined before build begins.',
  hero_summary = 'A logistics-focused AI design engagement that validates which AI capabilities will genuinely improve demand forecasting, route optimisation, and fulfilment planning, producing responsible workflow designs and build-ready specifications before any development investment is committed.',
  overview_paragraphs = '["The Logistics Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for logistics and supply chain operations, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for logistics & supply chain leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for logistics operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation against your actual order and carrier data, not generic industry benchmarks","Planner override controls specified in every AI routing and replenishment workflow","Deployment specifications ready to hand to your engineering or WMS vendor team"]'::jsonb,
  why_it_matters = '{"hook":"Logistics performance is won or lost on visibility, routing discipline, and handoff accuracy.","problemParagraph":"Many organisations apply AI to your logistics network without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for logistics operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for logistics operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about designing AI capabilities for logistics operations.'
WHERE variant_id = 193;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (193, 'Validated logistics AI use-case register', 'Candidate AI use cases scored against network value, data availability, and responsible-AI criteria specific to logistics and supply chain operations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (193, 'Responsible logistics AI workflow designs', 'Step-by-step specifications for AI-assisted route planning, demand forecasting, and replenishment, with planner override controls and escalation paths.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (193, 'Logistics data readiness report', 'Assessment of order, carrier, fleet, and inventory data required for each approved AI use case, with gaps and remediation steps identified.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (193, 'AI deployment specification', 'Build-ready documentation covering model selection, WMS and TMS integration points, monitoring metrics, and rollback procedures for each approved logistics AI use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (193, 'Which AI use cases make sense for logistics?', 'Demand forecasting, dynamic route optimisation, predictive inventory replenishment, and carrier performance scoring are the most common starting points. The DigitalQatalyst team validates which are feasible for your data.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (193, 'How much historical data is needed for demand forecasting AI?', 'Typically two or more years of order and inventory records. The data readiness report specifies exactly what each use case requires and identifies gaps to close.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (193, 'How do you keep human planners in control of AI routing decisions?', 'Override controls and confidence thresholds are built into every AI routing workflow design. The specification defines when and how planners retain authority over final route assignments.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (193, 'How do we get started?', 'Request a scoping call and the DigitalQatalyst team will confirm which AI use cases to evaluate and what data access is required for the feasibility assessment.', 3);

-- Logistics Operations (High-Impact) - Deploy (variant 194)
UPDATE product_content SET
  description = 'A managed logistics deployment that configures, integrates, tests, and launches your warehouse management and carrier integration capabilities, with structured quality assurance across fulfilment workflows and a formal handover to your logistics operations team.',
  positioning = 'Go live with improved logistics operations through a tested build that covers WMS configuration, carrier integration, and fulfilment workflow launch.',
  hero_summary = 'A managed logistics deployment that configures, integrates, tests, and launches your warehouse management and carrier integration capabilities, with structured quality assurance across fulfilment workflows and a formal handover to your logistics operations team.',
  overview_paragraphs = '["The Logistics Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed logistics and supply chain operations changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for logistics & supply chain leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated logistics operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Zone-by-zone acceptance testing with formal sign-off before any live inventory transactions","Carrier API integrations tested alongside WMS workflows before go-live","Hypercare monitoring covers the first weeks of live fulfilment operation"]'::jsonb,
  why_it_matters = '{"hook":"Logistics performance is won or lost on visibility, routing discipline, and handoff accuracy.","problemParagraph":"Many organisations stall between approved designs and production for your logistics network, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for logistics operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Logistics Operations deployment engagement.'
WHERE variant_id = 194;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (194, 'Configured logistics operations platform', 'WMS, TMS, and carrier integrations configured and tested end-to-end across all in-scope fulfilment workflows and operational zones.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (194, 'Test results and sign-off report', 'Test evidence covering integration, fulfilment workflow, and acceptance scenarios for each operational zone, with all critical issues resolved before go-live.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (194, 'Staff training completion record', 'Documented training completion for warehouse operatives, transport coordinators, and planning teams, with competency assessed against the fulfilment standards in the workflow designs.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (194, 'Logistics operations handover pack', 'WMS configuration documentation, carrier integration runbooks, escalation contacts, and first-90-days operational guidance for your logistics management team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (194, 'Can we go live with one warehouse zone before expanding?', 'Yes. The deployment plan typically phases activation by fulfilment zone or product category, allowing validation at smaller scale before full warehouse rollout.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (194, 'How is live inventory data migrated?', 'Inventory migration is planned, validated, and tested in a non-production environment before go-live. The migration plan is confirmed with your operations team during the first three weeks.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (194, 'What happens if carrier integrations fail during acceptance testing?', 'Carrier integration failures are logged, triaged, and resolved before that carrier goes live. Individual carrier failures do not delay zones that are ready for launch.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (194, 'How do we get started?', 'Share your approved workflow specifications with the DigitalQatalyst team and we will scope the deployment plan, environment requirements, and carrier onboarding sequence.', 3);

-- Logistics Operations (High-Impact) - AI Deploy (variant 195)
UPDATE product_content SET
  description = 'A governed AI deployment that activates validated logistics AI capabilities in production, with integrated monitoring, planner override controls, and a formal handover to your supply chain operations and technology teams.',
  positioning = 'Activate demand forecasting and route optimisation AI in a controlled, monitored environment with planner authority and governance built in from day one.',
  hero_summary = 'A governed AI deployment that activates validated logistics AI capabilities in production, with integrated monitoring, planner override controls, and a formal handover to your supply chain operations and technology teams.',
  overview_paragraphs = '["The Logistics Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled logistics and supply chain operations workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for logistics & supply chain leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for logistics operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Shadow-mode testing validates forecast and route AI accuracy before any operational decisions are affected","Planner override controls active from day one of live AI operation across all use cases","Use-case-by-use-case activation reduces risk at each launch gate"]'::jsonb,
  why_it_matters = '{"hook":"Logistics performance is won or lost on visibility, routing discipline, and handoff accuracy.","problemParagraph":"Many AI initiatives for your logistics network fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for logistics operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying AI into live logistics operations.'
WHERE variant_id = 195;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (195, 'Live logistics AI capability suite', 'Approved AI features in production, integrated with WMS and TMS, accepted by supply chain planning and logistics operations leads.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (195, 'Logistics AI monitoring dashboard', 'Real-time view of forecast accuracy, route efficiency, and fulfilment-cost signals, with alert thresholds agreed with your planning and operations team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (195, 'Planner governance documentation', 'Written policies and in-system controls covering when planners must review or override AI forecasting and routing recommendations, with escalation paths.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (195, 'AI operations handover pack', 'Model cards, WMS and TMS integration diagrams, monitoring runbooks, and retraining schedules for your supply chain technology and operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (195, 'Which AI capabilities are activated in this deployment?', 'Those validated in your AI Design phase: commonly demand forecasting, dynamic route optimisation, and predictive replenishment. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (195, 'How do you prevent AI forecasting errors from affecting inventory commitments?', 'Shadow-mode testing runs forecasting models against live data without acting on outputs until accuracy thresholds are met. Planner override controls remain active after full launch.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (195, 'Who maintains the AI models after handover?', 'Your supply chain technology team, using model cards, monitoring runbooks, and retraining schedules provided in the handover pack. The DigitalQatalyst team can provide ongoing managed support if needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (195, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm production environment requirements and the use-case activation sequence.', 3);

-- Logistics Operations (High-Impact) - Managed (variant 196)
UPDATE product_content SET
  description = 'An ongoing managed service that runs and continuously improves your logistics operations platform, with SLA-backed monitoring, monthly performance reporting across fulfilment and carrier delivery, and proactive network optimisation by the DigitalQatalyst team.',
  positioning = 'Keep logistics and supply chain operations performing at target with continuous monitoring, proactive route and fulfilment optimisation, and monthly network performance reporting.',
  hero_summary = 'An ongoing managed service that runs and continuously improves your logistics operations platform, with SLA-backed monitoring, monthly performance reporting across fulfilment and carrier delivery, and proactive network optimisation by the DigitalQatalyst team.',
  overview_paragraphs = '["The Logistics Operations Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve logistics and supply chain operations with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for logistics & supply chain leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for logistics operations - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fulfilment and carrier performance reported together in a single monthly view","Proactive route and network optimisation included alongside reactive incident management","Named logistics-sector team with supply chain context, not a generic IT support function"]'::jsonb,
  why_it_matters = '{"hook":"Logistics performance is won or lost on visibility, routing discipline, and handoff accuracy.","problemParagraph":"Many organisations struggle to sustain performance across your logistics network after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"logistics operations issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Logistics Operations managed service.'
WHERE variant_id = 196;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (196, 'Monthly logistics performance report', 'Fulfilment accuracy, on-time delivery rates, carrier performance, and system-availability metrics across all in-scope network nodes, delivered every month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (196, 'Network optimisation log', 'Record of every routing adjustment, slotting change, and carrier integration fix made during the service period, with before-and-after performance metrics.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (196, 'SLA compliance report', 'Monthly record of incidents, response times, and resolution times against agreed SLA targets, with root-cause notes for any network availability breaches.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (196, 'Annual logistics roadmap', 'Forward-looking plan identifying network optimisation priorities, platform upgrade opportunities, and recommended technology investments for the next 12 months.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (196, 'What platforms does the managed service cover?', 'WMS, TMS, and carrier integration APIs, plus the workflows connecting them across your fulfilment network. Additional nodes and platforms can be onboarded as your estate grows.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (196, 'What SLA response times apply to fulfilment-critical incidents?', 'Response and resolution targets are agreed during onboarding. Incidents affecting live despatch and carrier integration receive priority-one treatment.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (196, 'Does the service scale for peak fulfilment periods?', 'Yes. The DigitalQatalyst team reviews your trading calendar during onboarding and confirms enhanced monitoring windows for peak despatch periods.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (196, 'How do we get started?', 'Contact the DigitalQatalyst team to schedule a service onboarding call covering network scope, SLA targets, reporting format, and named contacts on both sides.', 3);

-- Wellness Operations (High-Impact) - Assess (variant 197)
UPDATE product_content SET
  description = 'A structured assessment of your wellness, clinic, or care operations that identifies the scheduling inefficiencies, care coordination gaps, and service quality issues reducing client experience and operational throughput, and returns a prioritised improvement roadmap.',
  positioning = 'Understand exactly where your wellness operations fall short on client experience and scheduling efficiency, with every finding ranked for clinical and operational impact.',
  hero_summary = 'A structured assessment of your wellness, clinic, or care operations that identifies the scheduling inefficiencies, care coordination gaps, and service quality issues reducing client experience and operational throughput, and returns a prioritised improvement roadmap.',
  overview_paragraphs = '["The Wellness Operations Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","See how wellness operations and client experience perform today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for wellness, clinic & care operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews wellness operations across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Covers client experience, scheduling efficiency, and care coordination in one assessment","Client retention and satisfaction impact scored on every recommendation","Fixed-scope with prioritised findings ready within the week"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many wellness operators run clinics and programmes with fragmented booking, client records, and service delivery workflows. This assessment maps operational maturity and returns prioritised improvements your operations leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Fragmented operations data","description":"Wellness operations teams work from disconnected systems without a single operational view."},{"title":"Inconsistent field processes","description":"Standard operating procedures vary by site, team, or shift."},{"title":"Limited digitisation baseline","description":"Automation and analytics opportunities are unclear and unprioritised."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Operational priority map","description":"You know which wellness operations processes and systems to improve first."},{"title":"Ranked improvement backlog","description":"Gaps are ordered for design, technology, and investment."},{"title":"Leadership-ready roadmap","description":"Recommendations support governance review and transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the Wellness Operations assessment.'
WHERE variant_id = 197;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (197, 'Client journey friction map', 'A stage-by-stage view of where the client experience breaks down, from first booking to post-session follow-up, with root causes and retention-impact estimates.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (197, 'Scheduling and capacity report', 'Assessment of appointment fill rates, cancellation patterns, and practitioner utilisation, with the specific inefficiencies reducing revenue and client access.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (197, 'Care coordination gap analysis', 'Review of practitioner communication pathways, referral processes, and client record completeness, with the gaps affecting continuity and service quality.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (197, 'Prioritised improvement roadmap', 'Sequenced action plan ranked by client-satisfaction and efficiency impact, with ownership suggestions and a phasing recommendation your leadership team can act on.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (197, 'Which types of wellness organisation does the assessment cover?', 'Wellness centres, clinics, fitness operators, preventive health services, and allied health practices. Scope is confirmed with the DigitalQatalyst team before start.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (197, 'What data do you need?', 'Appointment and scheduling records, cancellation logs, client satisfaction feedback, and referral data. No sensitive health records are required.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (197, 'Can the assessment cover multiple sites or practitioners?', 'Yes. The assessment scope covers the sites and practitioner groups confirmed with the DigitalQatalyst team during scoping.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (197, 'How do we get started?', 'Request a consultation and the DigitalQatalyst team will confirm the operational scope, data requirements, and assessment schedule.', 3);

-- Wellness Operations (High-Impact) - Design (variant 198)
UPDATE product_content SET
  description = 'A design engagement that converts your wellness operations goals into client-centred journey designs, appointment and care coordination workflow specifications, and technology integration blueprints your implementation teams can build and launch.',
  positioning = 'Design the wellness operations blueprint your practitioners and clients need: booking journeys, care coordination workflows, and platform integrations ready for build.',
  hero_summary = 'A design engagement that converts your wellness operations goals into client-centred journey designs, appointment and care coordination workflow specifications, and technology integration blueprints your implementation teams can build and launch.',
  overview_paragraphs = '["The Wellness Operations Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines wellness operations and build-ready specifications.","Turn wellness operations and client experience goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for wellness, clinic & care operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate wellness operations requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Client experience and practitioner workflow design completed together in a single sprint","Integration architecture built to your existing practice management and EHR systems","Specifications include both clinical and administrative workflow requirements"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many wellness groups adopt platforms without designed client journeys, practitioner workflows, or specifications teams can implement. This design engagement defines wellness operations and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined operational workflows","description":"Wellness operations journeys from intake to completion are not designed end to end."},{"title":"Integration gaps","description":"Field, ERP, and customer systems lack clear data and event contracts."},{"title":"Rollout ambiguity","description":"Teams lack specs to pilot and scale changes across sites."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned operational designs","description":"Workflows reflect how wellness operations teams actually deliver service."},{"title":"Consistent standards","description":"Data, integration, and governance requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Delivery teams receive artefacts they can execute across locations."}]}}'::jsonb,
  faq_intro = 'Key questions about the Wellness Operations design engagement.'
WHERE variant_id = 198;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (198, 'Client journey designs', 'End-to-end journey maps from first contact to post-session follow-up, with service standards, touchpoints, and consistency requirements across booking and in-clinic experiences.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (198, 'Practitioner workflow specifications', 'Step-by-step workflow definitions for scheduling, care planning, record-keeping, and referral processes, designed to reduce administrative time and coordination failures.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (198, 'Technology integration architecture', 'Data-flow diagrams and integration specifications connecting your practice management system, EHR, billing, and client-communication tools into a coherent operational view.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (198, 'Adoption and training plan', 'Role-specific onboarding materials for reception, practitioners, and clinic managers, with a rollout sequence and go/no-go criteria for each phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (198, 'Does the design cover digital booking as well as in-clinic workflows?', 'Yes. Client journey designs span online booking through to in-clinic delivery and post-session follow-up, covering all touchpoints in your client experience.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (198, 'Can the design accommodate multiple disciplines or service types?', 'Yes. Workflow specifications are designed per discipline or service type where your operation offers a range of modalities.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (198, 'What if we are migrating to a new practice management system?', 'The integration architecture can be designed for your target platform if a migration is already planned. The DigitalQatalyst team confirms the approach during scoping.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (198, 'How do we get started?', 'Book a scoping call and the DigitalQatalyst team will confirm the service types in scope, the workshops required, and the design sprint schedule.', 3);

-- Wellness Operations (High-Impact) - AI Design (variant 199)
UPDATE product_content SET
  description = 'A wellness-focused AI design engagement that validates which AI capabilities will genuinely improve appointment scheduling, client retention prediction, and care coordination quality, producing responsible workflow designs and build-ready specifications before any development begins.',
  positioning = 'Design AI for wellness with validated scheduling and retention use cases, clear data requirements, and clinical governance guardrails defined before build begins.',
  hero_summary = 'A wellness-focused AI design engagement that validates which AI capabilities will genuinely improve appointment scheduling, client retention prediction, and care coordination quality, producing responsible workflow designs and build-ready specifications before any development begins.',
  overview_paragraphs = '["The Wellness Operations AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for wellness operations and client experience, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for wellness, clinic & care operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for wellness operations.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use-case validation against your actual appointment and client data, not generic health-sector benchmarks","Clinical authority boundaries and practitioner override controls specified in every AI workflow design","Regulatory and privacy considerations for health and wellness data addressed at design stage"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many organisations apply AI to your wellness operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for wellness operations lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for wellness operations are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about designing AI capabilities for wellness operations.'
WHERE variant_id = 199;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (199, 'Validated wellness AI use-case register', 'Candidate AI use cases scored against clinical value, data availability, regulatory constraints, and responsible-AI criteria specific to wellness and care operations.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (199, 'Responsible wellness AI workflow designs', 'Step-by-step specifications for AI-assisted scheduling and retention modelling, with practitioner authority boundaries, override controls, and client-communication guidelines.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (199, 'Wellness data readiness report', 'Assessment of appointment, engagement, care plan, and practitioner data required for each approved AI use case, with gaps and remediation steps.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (199, 'AI deployment specification', 'Build-ready documentation covering model selection, PMS and EHR integration points, monitoring metrics, and rollback procedures for each approved wellness AI use case.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (199, 'What AI use cases make sense for wellness operations?', 'Appointment scheduling optimisation, client dropout prediction, demand forecasting, and care plan recommendation support are common starting points. The DigitalQatalyst team validates which are feasible for your data.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (199, 'How do you handle health and wellness data privacy in AI designs?', 'Privacy requirements and data-minimisation principles are built into every workflow specification. Regulatory constraints relevant to your jurisdiction are identified and addressed during the engagement.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (199, 'Do practitioners retain clinical authority when AI makes care recommendations?', 'Yes, unconditionally. Every AI care-support workflow design specifies that practitioners have full authority to accept, modify, or reject AI recommendations. AI is framed as a decision-support tool only.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (199, 'How do we get started?', 'Request a scoping call and the DigitalQatalyst team will confirm which AI use cases to evaluate and what data access is required for the feasibility assessment.', 3);

-- Wellness Operations (High-Impact) - Deploy (variant 200)
UPDATE product_content SET
  description = 'A managed wellness operations deployment that configures, integrates, tests, and launches your practice management and client engagement platform capabilities, with structured quality assurance and a formal handover to your clinic and wellness operations team.',
  positioning = 'Launch improved wellness operations through a tested build covering practice management configuration, care coordination workflows, and a confirmed team handover.',
  hero_summary = 'A managed wellness operations deployment that configures, integrates, tests, and launches your practice management and client engagement platform capabilities, with structured quality assurance and a formal handover to your clinic and wellness operations team.',
  overview_paragraphs = '["The Wellness Operations Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed wellness operations and client experience changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for wellness, clinic & care operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated wellness operations assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Discipline-by-discipline acceptance testing with formal sign-off before any live client interactions","EHR and PMS workflows tested together before go-live to prevent care-record gaps at launch","Hypercare monitoring covers the first weeks of live wellness operation"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many organisations stall between approved designs and production for your wellness operations, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for wellness operations sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about the Wellness Operations deployment engagement.'
WHERE variant_id = 200;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Configured wellness operations platform', 'Practice management system and EHR configured and integrated across your in-scope service types and sites, with booking, care record, and billing flows tested end-to-end.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Test results and discipline sign-off report', 'Test evidence covering integration, care workflow, and acceptance scenarios for each discipline, with all critical issues resolved before any live client access.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Staff training completion record', 'Documented training completion for reception, practitioners, and clinic managers, with competency assessed against the client experience and workflow standards in your design.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (200, 'Wellness operations handover pack', 'Platform configuration documentation, care-workflow runbooks, escalation contacts, and first-90-days operational guidance for your clinic management team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'Can we go live with one clinic site or discipline before expanding?', 'Yes. The deployment plan typically phases activation by site or discipline, allowing validation at smaller scale before full rollout.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'How is existing client data migrated?', 'Client data migration is planned, validated, and tested in a non-production environment before go-live. The migration approach is confirmed with your operations and clinical leads during the first three weeks.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'What if acceptance testing reveals issues with a specific discipline workflow?', 'Issues are logged, triaged, and resolved before that discipline proceeds to launch. Discipline-specific sign-off gates mean a delay in one area does not hold back others that are ready.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (200, 'How do we get started?', 'Share your approved workflow specifications with the DigitalQatalyst team and we will scope the deployment plan and environment requirements.', 3);

-- Wellness Operations (High-Impact) - AI Deploy (variant 201)
UPDATE product_content SET
  description = 'A governed AI deployment that activates validated wellness AI capabilities in production, with integrated monitoring, practitioner authority controls, and a formal handover to your clinic operations and technology teams.',
  positioning = 'Launch scheduling optimisation and client retention AI in a controlled, monitored environment where practitioners retain full clinical authority from activation day.',
  hero_summary = 'A governed AI deployment that activates validated wellness AI capabilities in production, with integrated monitoring, practitioner authority controls, and a formal handover to your clinic operations and technology teams.',
  overview_paragraphs = '["The Wellness Operations AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled wellness operations and client experience workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for wellness, clinic & care operations leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for wellness operations with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Shadow-mode testing validates scheduling and retention AI against live client data before any clinical workflows are affected","Practitioner authority controls active from day one: no AI recommendation is acted on without clinical review where specified","Use-case-by-use-case activation keeps risk contained at each launch gate"]'::jsonb,
  why_it_matters = '{"hook":"Wellness providers depend on seamless booking, care coordination, and compliant client management.","problemParagraph":"Many AI initiatives for your wellness operations fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for wellness operations fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying AI into live wellness operations.'
WHERE variant_id = 201;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (201, 'Live wellness AI capability suite', 'Approved AI features in production, integrated with your PMS and EHR, accepted by clinical leads and clinic management.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (201, 'Wellness AI monitoring dashboard', 'Real-time view of scheduling fill rates, client retention metrics, and model recommendation uptake, with alert thresholds agreed with your clinical and operations team.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (201, 'Clinical governance documentation', 'Written policies and in-system controls confirming practitioner authority over AI care-support outputs, with override procedures and client communication guidelines.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (201, 'AI operations handover pack', 'Model cards, PMS and EHR integration diagrams, monitoring runbooks, and retraining schedules handed to your wellness technology and clinical operations teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (201, 'Which AI capabilities are activated in this deployment?', 'Those validated in your AI Design phase: commonly appointment scheduling optimisation, client dropout prediction, and demand forecasting. Scope is confirmed from your approved specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (201, 'How do you protect client privacy during AI activation?', 'Data-minimisation and privacy controls are built into every model integration. Shadow-mode testing operates on consented operational data only, and no client PII is used beyond what was specified in the AI Design phase.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (201, 'Who is responsible for AI model accuracy over time?', 'Your technology team, using model cards, monitoring runbooks, and retraining schedules provided in the handover pack. The DigitalQatalyst team can provide ongoing managed support if needed.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (201, 'How do we get started?', 'Provide your approved AI deployment specifications and the DigitalQatalyst team will confirm production environment requirements and the use-case activation sequence.', 3);

